hey i wanted to create an app to keep track of my warhammer games. im now using an app tabletop battles but it does not have the full potential i want. i made an html to transfer the data to a google sheet and then makes graphs there with this code
function doPost(e) {
  try {
    const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("Match Data") 
                  || SpreadsheetApp.getActiveSpreadsheet().insertSheet("Match Data");

    const data = JSON.parse(e.postData.contents);

    // Determine next ID
    let lastRow = sheet.getLastRow();
    let nextId = 1;
    if (lastRow > 0) {
      const lastId = sheet.getRange(lastRow, 1).getValue();
      if (typeof lastId === "number") nextId = lastId + 1;
    }

    const timestamp = new Date();
    const player1 = data.player1;
    const player2 = data.player2;
    const points = data.points;
    const army1 = data.army1 || "";
    const army2 = data.army2 || "";
    const detachmentP1 = data.detachmentP1 || "";
    const detachmentP2 = data.detachmentP2 || "";

    // Start building the row
    const row = [nextId, timestamp, points, player1, army1, detachmentP1, player2, army2, detachmentP2];

    for (let i = 1; i <= 5; i++) {
      // 1️⃣ Numeric points first
      row.push(
        data[`p1_primary_${i}`] || 0,
        data[`p1_secondary_${i}`] || 0,
        data[`p1_challenger_${i}`] || 0,
        data[`p1_cp_earned_${i}`] || 0,
        data[`p1_cp_used_${i}`] || 0,

        data[`p2_primary_${i}`] || 0,
        data[`p2_secondary_${i}`] || 0,
        data[`p2_challenger_${i}`] || 0,
        data[`p2_cp_earned_${i}`] || 0,
        data[`p2_cp_used_${i}`] || 0
      );


    }
    const primary = data.primaryMission || "";
    row.push(primary)
    for (let i = 1; i <= 5; i++) {
      const primary = data.primaryMission || "";
      row.push(
        // Player 1 data
        data[`p1_secondary1_name_${i}`] || "",
        data[`p1_secondary2_name_${i}`] || "",
        (Array.isArray(data[`p1_stratagems_${i}`]) 
          ? data[`p1_stratagems_${i}`].join("; ") 
          : data[`p1_stratagems_${i}`] || ""),   // <- stratagems used
        (Array.isArray(data[`p1_cp_army_${i}`])
          ? data[`p1_cp_army_${i}`].join("; ")
          : data[`p1_cp_army_${i}`] || ""),

        // Player 2 data
        data[`p2_secondary1_name_${i}`] || "",
        data[`p2_secondary2_name_${i}`] || "",
        (Array.isArray(data[`p2_stratagems_${i}`]) 
          ? data[`p2_stratagems_${i}`].join("; ") 
          : data[`p2_stratagems_${i}`] || ""),   // <- stratagems used
        (Array.isArray(data[`p2_cp_army_${i}`]) 
          ? data[`p2_cp_army_${i}`].join("; ") 
          : data[`p2_cp_army_${i}`] || ""),
      );
    }

    sheet.appendRow(row);

    return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);

  } catch (err) {
    return ContentService.createTextOutput("Error: " + err.message).setMimeType(ContentService.MimeType.TEXT);
  }
}

const P1_position = 3;
const P2_position = 6;
const base_start = 9;




function onOpen() {
  const ui = SpreadsheetApp.getUi();
  ui.createMenu('Game Analysis')
    .addItem('Average for Player', 'averageForPlayer')
    .addItem('Graph for One Game', 'graphForOneGame')
    .addItem('winrate', 'calculateWinrates')
    .addItem('GamesPlayed', 'calculateMatchups')
    .addToUi();
}

function averageForPlayer() {
  const ss = SpreadsheetApp.getActiveSpreadsheet(); 
  const sheet = ss.getSheetByName("Match Data");
  const data = sheet.getDataRange().getValues();
  const ui = SpreadsheetApp.getUi();
  const rounds = 5;

  // Delete the existing "ChartOutput" sheet if it exists
  const existingSheet = ss.getSheetByName("Average");
  if (existingSheet) {
    ss.deleteSheet(existingSheet);
  }
  // Step 1: Collect unique player names
  const playerSet = new Set();
  for (let i = 2; i < data.length; i++) {
    playerSet.add(data[i][P1_position]); // player1
    playerSet.add(data[i][P2_position]); // player2
  }
  const players = [...playerSet].sort();

  // Step 2: Hardcoded editions with date ranges
  const editions = [
    { name: "Edition 10", start: "2023-07-01", end: "2026-07-31" },
  ];

  // Step 3: Build HTML UI
  const html = HtmlService.createHtmlOutput(`
    <label for="player">Select a player:</label><br>
    <select id="player">
      ${players.map(p => `<option value="${p}">${p}</option>`).join('')}
    </select>
    <br><br>

    <label for="edition">Select Edition:</label><br>
    <select id="edition">
      <option value="">(None)</option>
      ${editions.map(e => `<option value="${e.name}">${e.name} (${e.start} to ${e.end})</option>`).join('')}
    </select>
    <br><br>

    <label>Or pick a custom date range:</label><br>
    Start Date: <input type="date" id="startDate"><br>
    End Date: <input type="date" id="endDate"><br><br>

    <button onclick="submit()">Submit</button>
    <button onclick="allDates()">All Dates</button>

    <script>
      function submit() {
        const player = document.getElementById('player').value;
        const edition = document.getElementById('edition').value;
        const startDate = document.getElementById('startDate').value;
        const endDate = document.getElementById('endDate').value;
        google.script.run.withSuccessHandler(() => google.script.host.close())
          .averageForPlayerProcess(player, edition, startDate, endDate, false);
      }

      function allDates() {
        const player = document.getElementById('player').value;
        google.script.run.withSuccessHandler(() => google.script.host.close())
          .averageForPlayerProcess(player, "", "", "", true);
      }
    </script>
  `).setWidth(400).setHeight(320);
  ui.showModalDialog(html, 'Select Player & Date Range');
}

// This function does the actual work after the dropdown
function averageForPlayerProcess(player, edition, startDateStr, endDateStr, allDates) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName("Match Data");
  const data = sheet.getDataRange().getValues();
  const rounds = 5;

  // Hardcoded editions again for processing
  const editions = [
    { name: "Edition 10", start: "2023-07-01", end: "2026-07-31" },
  ];

  let startDate = startDateStr ? new Date(startDateStr) : null;
  let endDate = endDateStr ? new Date(endDateStr) : null;

  // If edition is chosen, override start/end date
  if (edition && editions[edition]) {
    startDate = editions[edition].start;
    endDate = editions[edition].end;
  }

  let pVPs = Array(rounds).fill(0),
      sVPs = Array(rounds).fill(0),
      cVPs = Array(rounds).fill(0); // NEW: challenger VP array
  let count = 0;

  for (let i = 1; i < data.length; i++) {
    const row = data[i];
    const uploadDate = new Date(row[1]); // Column B date
    const player1 = row[P1_position], player2 = row[P2_position];

    // Skip date filtering if "allDates" is true
    if (!allDates) {
      if (startDate && uploadDate < startDate) continue;
      if (endDate && uploadDate > endDate) continue;
    }

    // Player filter
    if (player1 !== player && player2 !== player) continue;

    // Score accumulation
    for (let r = 0; r < rounds; r++) {
      const base = base_start + r * 10;
      const p1_pVP = row[base];
      const p1_sVP = row[base + 1];
      const p1_cVP = row[base + 2]; // NEW
      const p2_pVP = row[base + 5];
      const p2_sVP = row[base + 6];
      const p2_cVP = row[base + 7]; // NEW

      if (player1 === player) {
        pVPs[r] += p1_pVP;
        sVPs[r] += p1_sVP;
        cVPs[r] += p1_cVP;
      }
      if (player2 === player) {
        pVPs[r] += p2_pVP;
        sVPs[r] += p2_sVP;
        cVPs[r] += p2_cVP;
      }
    }
    count++;
  }

  if (count === 0) {
    SpreadsheetApp.getUi().alert('No games found for ' + player);
    return;
  }

  // Averages
  const avg_pVP = pVPs.map(v => v / count);
  const avg_sVP = sVPs.map(v => v / count);
  const avg_cVP = cVPs.map(v => v / count); // NEW

  // Cumulative sums
  const cum_pVP = cumulativeSum(avg_pVP);
  const cum_sVP = cumulativeSum(avg_sVP);
  const cum_cVP = cumulativeSum(avg_cVP); // NEW

  // Total now includes challenger VP
  const total = cum_pVP.map((v, i) => v + cum_sVP[i] + cum_cVP[i]);

  // Pass all 3 VP types to chart
  drawChartAverage(
    player + ' (Average)',
    cum_pVP,
    cum_sVP,
    cum_cVP,
    total,
    ['pVP', 'sVP', 'cVP', 'Total'] // Updated legend
  );
}



function graphForOneGame() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();

  // Delete the existing "ChartOutput" sheet if it exists
  const existingSheet = ss.getSheetByName("OneGame");
  if (existingSheet) {
    ss.deleteSheet(existingSheet);
  }

  // Get data from "Match Data" sheet
  const sheet = ss.getSheetByName("Match Data");
  const data = sheet.getDataRange().getValues();
  const ui = SpreadsheetApp.getUi();
  const rounds = 5;

  // Ask user for the Game number (column A)
  const input = ui.prompt('Enter the Game number (from column A):', ui.ButtonSet.OK);
  if (input.getSelectedButton() !== ui.Button.OK) return;

  const gameNumber = input.getResponseText().trim();
  if (!gameNumber) {
    ui.alert('Invalid input.');
    return;
  }

  // Find the row with that game number
  let row = null;
  for (let i = 1; i < data.length; i++) {
    if (String(data[i][0]).trim() === gameNumber) {
      row = data[i];
      break;
    }
  }

  if (!row) {
    ui.alert('No game found with number ' + gameNumber);
    return;
  }

  const p1 = row[P1_position]; // Player 1
  const p2 = row[P2_position]; // Player 2

  const p1_primary = [];
  const p1_secondary = [];
  const p1_challenger = [];

  const p2_primary = [];
  const p2_secondary = [];
  const p2_challenger = [];

  for (let r = 0; r < rounds; r++) {
    const base = base_start + r * 10; // data starts from column G (index 6), each round is 10 columns

    p1_primary.push(row[base]);
    p1_secondary.push(row[base + 1]);
    p1_challenger.push(row[base + 2]);

    p2_primary.push(row[base + 5]);
    p2_secondary.push(row[base + 6]);
    p2_challenger.push(row[base + 7]);
  }

  // Cumulative scoring
  const p1_cum_primary = cumulativeSum(p1_primary);
  const p1_cum_secondary = cumulativeSum(p1_secondary);
  const p1_cum_challenger = cumulativeSum(p1_challenger);
  const p1_total_per_round = p1_primary.map((v, i) => v + p1_secondary[i] + p1_challenger[i]);
  const p1_cum_total = cumulativeSum(p1_total_per_round);

  const p2_cum_primary = cumulativeSum(p2_primary);
  const p2_cum_secondary = cumulativeSum(p2_secondary);
  const p2_cum_challenger = cumulativeSum(p2_challenger);
  const p2_total_per_round = p2_primary.map((v, i) => v + p2_secondary[i] + p2_challenger[i]);
  const p2_cum_total = cumulativeSum(p2_total_per_round);

  // Chart headers
  const seriesNames = [
    `${p1} Primary`, `${p1} Secondary`, `${p1} Challenger`, `${p1} Total`,
    `${p2} Primary`, `${p2} Secondary`, `${p2} Challenger`, `${p2} Total`
  ];

  // Draw the chart
  drawChartOneGame(
    `Game ${gameNumber}: ${p1} vs ${p2}`,
    p1_cum_primary,
    p1_cum_secondary,
    p1_cum_challenger,
    p1_cum_total,
    p2_cum_primary,
    p2_cum_secondary,
    p2_cum_challenger,
    p2_cum_total,
    seriesNames
  );
}

// Helper function
function cumulativeSum(array) {
  const result = [];
  array.reduce((sum, val, i) => {
    const value = Number(val) || 0;
    result[i] = sum + value;
    return result[i];
  }, 0);
  return result;
}

function calculateWinrates() {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("Match Data"); // Change name if needed
  const data = sheet.getDataRange().getValues();

  const header = data[0];
  const games = data.slice(2);

  const results = {}; // Key: "Player | Army" → {wins, losses, draws}

  for (const row of games) {
    const player1 = row[P1_position];
    const player2 = row[P2_position];
    const army1 = row[P1_position+1];
    const army2 = row[P2_position+1];

    let totalP1 = 0;
    let totalP2 = 0;

    for (let r = 0; r < 5; r++) {
      const base = base_start + r * 10;

      const p1_primary = Number(row[base]) || 0;
      const p1_secondary = Number(row[base + 1]) || 0;
      const p1_challenger = Number(row[base + 2]) || 0;

      const p2_primary = Number(row[base + 5]) || 0;
      const p2_secondary = Number(row[base + 6]) || 0;
      const p2_challenger = Number(row[base + 7]) || 0;

      totalP1 += p1_primary + p1_secondary + p1_challenger;
      totalP2 += p2_primary + p2_secondary + p2_challenger;
    }

    const key1 = `${player1} | ${army1}`;
    const key2 = `${player2} | ${army2}`;

    if (!results[key1]) results[key1] = { wins: 0, losses: 0, draws: 0 };
    if (!results[key2]) results[key2] = { wins: 0, losses: 0, draws: 0 };

    if (totalP1 > totalP2) {
      results[key1].wins++;
      results[key2].losses++;
    } else if (totalP1 < totalP2) {
      results[key1].losses++;
      results[key2].wins++;
    } else {
      results[key1].draws++;
      results[key2].draws++;
    }
  }

  // Output sheet
  const outputSheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("Winrates") || SpreadsheetApp.getActiveSpreadsheet().insertSheet("Winrates");
  outputSheet.clear();

  outputSheet.appendRow(["Player", "Army", "Total Games", "Wins", "Losses", "Draws", "Winrate"]);

  for (const key in results) {
    const [player, army] = key.split(" | ");
    const { wins, losses, draws } = results[key];
    const total = wins + losses + draws;
    const winrate = total ? ((wins / total) * 100).toFixed(1) + "%" : "0.0%";
    outputSheet.appendRow([player, army, total, wins, losses, draws, winrate]);
  }

  SpreadsheetApp.getUi().alert("Winrates calculated and written to 'Winrates' sheet.");
}

function calculateMatchups() {
  const sheetName = "Match Data"; // Change if needed
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(sheetName);
  if (!sheet) {
    SpreadsheetApp.getUi().alert(`Sheet "${sheetName}" not found!`);
    return;
  }

  const data = sheet.getDataRange().getValues();
  const games = data.slice(2); // skip first 2 header rows

  const matchups = {}; // Key: "PlayerA | PlayerB" → count

  for (const row of games) {
    const p1 = row[P1_position]?.trim();
    const p2 = row[P2_position]?.trim();
    if (!p1 || !p2) continue; // skip empty rows

    // Always store matchup in alphabetical order so A vs B = B vs A
    const players = [p1, p2].sort();
    const key = `${players[0]} | ${players[1]}`;

    if (!matchups[key]) matchups[key] = 0;
    matchups[key]++;
  }

  // Output to a new sheet
  const outputSheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName("Matchups") ||
                      SpreadsheetApp.getActiveSpreadsheet().insertSheet("Matchups");
  outputSheet.clear();
  outputSheet.appendRow(["Player 1", "Player 2", "Times Played"]);

  for (const key in matchups) {
    const [playerA, playerB] = key.split(" | ");
    outputSheet.appendRow([playerA, playerB, matchups[key]]);
  }

  SpreadsheetApp.getUi().alert("Matchup counts written to 'Matchups' sheet.");
}


function drawChartAverage(title, ...args) {
  const sheetName = 'Average';
  const spreadsheet = SpreadsheetApp.getActiveSpreadsheet();
  let chartSheet = spreadsheet.getSheetByName(sheetName);
  if (!chartSheet) chartSheet = spreadsheet.insertSheet(sheetName);
  chartSheet.clear();

  const lines = args.slice(0, -1);
  const customLegend = Array.isArray(args[args.length - 1]) ? args[args.length - 1] : null;
  const headers = ['Round'];
  for (let i = 0; i < lines.length; i++) {
    headers.push(customLegend ? customLegend[i] : `Line ${i + 1}`);
  }

  const numRounds = lines[0].length;
  const values = [headers];

  for (let r = 0; r < numRounds; r++) {
    const row = [r + 1]; // Round number
    for (let line of lines) row.push(line[r]);
    values.push(row);
  }

  // Paste data into the sheet
  chartSheet.getRange(1, 1, values.length, values[0].length).setValues(values);

  // Build series configuration
  const seriesOptions = {};
  for (let i = 0; i < lines.length; i++) {
    seriesOptions[i] = {
      labelInLegend: customLegend ? customLegend[i] : `Line ${i + 1}`,
    };
  }

  // Build chart with series labels
  const chartBuilder = chartSheet.newChart()
    .setChartType(Charts.ChartType.LINE)
    .addRange(chartSheet.getRange(1, 1, values.length, values[0].length)) // include header
    .setPosition(1, values[0].length + 3, 0, 0)
    .setOption('title', title)
    .setOption('legend', { position: 'right' })
    .setOption('hAxis', { title: 'Rounds' })
    .setOption('vAxis', { title: 'VP' })
    .setOption('series', seriesOptions);

  chartSheet.insertChart(chartBuilder.build());
}

