    const tabs = document.querySelectorAll('.tabs button');
    function showPage(key){
      document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
      const pg = document.getElementById(`page-${key}`);
      if (pg) pg.classList.add('active');
      tabs.forEach(t => t.classList.remove('active'));
      const activeBtn = document.querySelector(`.tabs button[data-page="${key}"]`);
      if(activeBtn) activeBtn.classList.add('active');
      updatePlayerHeaders();
      updateAllTotals();
    }
    tabs.forEach(t => t.addEventListener('click', ()=> showPage(t.dataset.page)));

    const form = document.getElementById('matchForm');

	function updateAllTotals(){
	  for(let r=1;r<=5;r++){
		let p1 = {primary:0, secondary:0, challenger:0, earned:0, used:0};
		let p2 = {primary:0, secondary:0, challenger:0, earned:0, used:0};

		for(let i=1;i<=r;i++){
		  // Player 1 secondaries
		  const s1p1 = Number(form[`p1_secondary1_pts_${i}`]?.value) || 0;
		  const s2p1 = Number(form[`p1_secondary2_pts_${i}`]?.value) || 0;
		  if(form[`p1_secondary_${i}`]) form[`p1_secondary_${i}`].value = s1p1 + s2p1;

		  // Player 2 secondaries
		  const s1p2 = Number(form[`p2_secondary1_pts_${i}`]?.value) || 0;
		  const s2p2 = Number(form[`p2_secondary2_pts_${i}`]?.value) || 0;
		  if(form[`p2_secondary_${i}`]) form[`p2_secondary_${i}`].value = s1p2 + s2p2;

		  // Accumulate Player 1
		  p1.primary += Number(form[`p1_primary_${i}`]?.value) || 0;
		  p1.secondary += Number(form[`p1_secondary_${i}`]?.value) || 0;
		  p1.challenger += Number(form[`p1_challenger_${i}`]?.value) || 0;
		  p1.earned += Number(form[`p1_cp_earned_${i}`]?.value) || 0;
		  p1.used += Number(form[`p1_cp_used_${i}`]?.value) || 0;

		  // Accumulate Player 2
		  p2.primary += Number(form[`p2_primary_${i}`]?.value) || 0;
		  p2.secondary += Number(form[`p2_secondary_${i}`]?.value) || 0;
		  p2.challenger += Number(form[`p2_challenger_${i}`]?.value) || 0;
		  p2.earned += Number(form[`p2_cp_earned_${i}`]?.value) || 0;
		  p2.used += Number(form[`p2_cp_used_${i}`]?.value) || 0;
		}

		const net1 = p1.earned - p1.used;
		const net2 = p2.earned - p2.used;

		const totalsP1 = document.getElementById(`totals-p1-round${r}`);
		if(totalsP1){
		  totalsP1.textContent = `P ${p1.primary} | S ${p1.secondary} | C ${p1.challenger} | CP ${net1}`;
		}

		const totalsP2 = document.getElementById(`totals-p2-round${r}`);
		if(totalsP2){
		  totalsP2.textContent = `P ${p2.primary} | S ${p2.secondary} | C ${p2.challenger} | CP ${net2}`;
		}
	  }
	}

    // Populate stratagem selects for a player & round
    function populateStratagemSelectFor(player, round) {
      const sel = document.getElementById(`p${player}_stratagems_${round}`);
      if(!sel) return;
      // capture previous selections to try and restore
      const prev = Array.from(sel.selectedOptions).map(o => o.value);

      // determine detachment for that player
      const detSelect = document.getElementById(`detachmentP${player}`);
      const det = detSelect ? detSelect.value : '';

