const SHEET_NAME = "Match Data";

function doPost(e) {
  try {
    const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_NAME) 
                  || SpreadsheetApp.getActiveSpreadsheet().insertSheet(SHEET_NAME);

    const data = JSON.parse(e.postData.contents);

    // Determine next ID
    let lastRow = sheet.getLastRow();
    let nextId = 1;
    if (lastRow > 0) {
      // Assuming ID is in column 1. check if header exists or data exists
      // If only header (row 1), nextId is 1. If data exists, grab last.
      if (lastRow > 1) {
         const lastId = sheet.getRange(lastRow, 1).getValue();
         if (typeof lastId === "number") nextId = lastId + 1;
      }
    } else {
      // Create Header if sheet is new
      const headers = [
        "ID", "Date", "Total Points", 
        "Player 1", "Army 1", "Detachment 1", 
        "Player 2", "Army 2", "Detachment 2", 
        "Mission",
        // We aren't creating 100 headers here for brevity, but the data will append correctly
      ];
      sheet.appendRow(headers);
      lastRow = 1;
    }

    const timestamp = new Date();

    // Calculate Totals for the summary columns (to make reading easier later)
    let p1Total = 0;
    let p2Total = 0;

    // We can sum up the round data from the incoming JSON to save a "Score" column
    // The incoming JSON has keys like p1_primary_1, p1_secondary_1, etc.
    for(let i=1; i<=5; i++) {
       p1Total += (data[`p1_primary_${i}`]||0) + (data[`p1_secondary_${i}`]||0) + (data[`p1_challenger_${i}`]||0);
       p2Total += (data[`p2_primary_${i}`]||0) + (data[`p2_secondary_${i}`]||0) + (data[`p2_challenger_${i}`]||0);
    }

    const row = [
      nextId, 
      timestamp, 
      data.points, 
      data.player1, 
      data.army1, 
      data.detachmentP1, 
      data.player2, 
      data.army2, 
      data.detachmentP2,
      data.primaryMission,
      p1Total, // Store calculated totals for easier fetching
      p2Total,
      // ... followed by detailed raw data ...
    ];

    // Add the detailed raw round data
    for (let i = 1; i <= 5; i++) {
      row.push(
        data[`p1_primary_${i}`] || 0,
        data[`p1_secondary_${i}`] || 0, // This is the sum of sec1 + sec2
        data[`p1_challenger_${i}`] || 0,
        data[`p1_cp_earned_${i}`] || 0,
        data[`p1_cp_used_${i}`] || 0,
        data[`p2_primary_${i}`] || 0,
        data[`p2_secondary_${i}`] || 0,
        data[`p2_challenger_${i}`] || 0,
        data[`p2_cp_earned_${i}`] || 0,
        data[`p2_cp_used_${i}`] || 0
      );
    }

    // Append Stratagem/Text info at the end (optional, based on your previous structure)
    // For the app history view, we mostly care about the first 12 columns

    sheet.appendRow(row);

    return ContentService.createTextOutput(JSON.stringify({ result: "Success", id: nextId }))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (err) {
    return ContentService.createTextOutput(JSON.stringify({ result: "Error", message: err.message }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

// --- NEW FUNCTION TO READ DATA ---
function doGet(e) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_NAME);
  if (!sheet) {
    return ContentService.createTextOutput(JSON.stringify([])).setMimeType(ContentService.MimeType.JSON);
  }

  const data = sheet.getDataRange().getValues();
  // Remove header row
  const rows = data.slice(1);

  const history = rows.map(row => {
    // Helper to safely parse date
    let dateStr = row[1];
    try { 
      if (dateStr instanceof Date) dateStr = dateStr.toISOString(); 
    } catch(e) {}

    return {
      id: row[0],
      date: dateStr,
      points: row[2],
      player1: row[3],
      army1: row[4],
      detachment1: row[5],
      player2: row[6],
      army2: row[7],
      detachment2: row[8],
      mission: row[9],
      p1Score: row[10] || 0, // We added these totals in doPost line 60
      p2Score: row[11] || 0
    };
  });

  // Return as JSON
  return ContentService.createTextOutput(JSON.stringify(history))
    .setMimeType(ContentService.MimeType.JSON);
}
