const SHEET_NAME = "Match Data";

function doPost(e) {
  try {
    const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_NAME) 
                  || SpreadsheetApp.getActiveSpreadsheet().insertSheet(SHEET_NAME);
    const data = JSON.parse(e.postData.contents);
    let lastRow = sheet.getLastRow();
    let nextId = 1;
    if (lastRow > 0 && sheet.getRange(lastRow, 1).getValue() !== "ID") {
       const val = sheet.getRange(lastRow, 1).getValue();
       if (typeof val === "number") nextId = val + 1;
    } else if (lastRow === 0) {
      sheet.appendRow(["ID", "Date", "Total Points", "Player 1", "Army 1", "Detachment 1", "Player 2", "Army 2", "Detachment 2", "Mission", "P1 Total", "P2 Total"]);
    }

    // Calculate totals
    let p1Total = 0, p2Total = 0;
    for(let i=1; i<=5; i++) {
       p1Total += (data[`p1_primary_${i}`]||0) + (data[`p1_secondary_${i}`]||0) + (data[`p1_challenger_${i}`]||0);
       p2Total += (data[`p2_primary_${i}`]||0) + (data[`p2_secondary_${i}`]||0) + (data[`p2_challenger_${i}`]||0);
    }

    const row = [nextId, new Date(), data.points, data.player1, data.army1, data.detachmentP1, data.player2, data.army2, data.detachmentP2, data.primaryMission, p1Total, p2Total];

    // Add 50 columns of round data (5 rounds * 10 columns per round per player set)
    // We stick to your original structure order for appending
    for (let i = 1; i <= 5; i++) {
      row.push(
        data[`p1_primary_${i}`] || 0, data[`p1_secondary_${i}`] || 0, data[`p1_challenger_${i}`] || 0,
        data[`p1_cp_earned_${i}`] || 0, data[`p1_cp_used_${i}`] || 0,
        data[`p2_primary_${i}`] || 0, data[`p2_secondary_${i}`] || 0, data[`p2_challenger_${i}`] || 0,
        data[`p2_cp_earned_${i}`] || 0, data[`p2_cp_used_${i}`] || 0
      );
    }
    sheet.appendRow(row);
    return ContentService.createTextOutput(JSON.stringify({ result: "Success", id: nextId })).setMimeType(ContentService.MimeType.JSON);
  } catch (err) {
    return ContentService.createTextOutput(JSON.stringify({ result: "Error", message: err.message })).setMimeType(ContentService.MimeType.JSON);
  }
}

function doGet(e) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(SHEET_NAME);
  if (!sheet) return ContentService.createTextOutput("[]").setMimeType(ContentService.MimeType.JSON);

  const data = sheet.getDataRange().getValues();
  const rows = data.slice(1); // skip header

  const history = rows.map(row => {
    // Basic Info
    const match = {
      id: row[0],
      date: row[1],
      points: row[2],
      player1: row[3],
      army1: row[4],
      detachment1: row[5],
      player2: row[6],
      army2: row[7],
      detachment2: row[8],
      mission: row[9],
      p1Score: row[10],
      p2Score: row[11],
      rawRounds: []
    };

    // Extract Round Data (starts at column index 12, which is the 13th column)
    // Structure: 5 rounds. Each round has 10 columns.
    // Order: P1_Prim, P1_Sec, P1_Chal, P1_CP_E, P1_CP_U, P2_Prim, P2_Sec, P2_Chal, P2_CP_E, P2_CP_U
    let col = 12; 
    for(let r=1; r<=5; r++) {
      match.rawRounds.push({
        round: r,
        p1: { primary: row[col], secondary: row[col+1], challenger: row[col+2] },
        p2: { primary: row[col+5], secondary: row[col+6], challenger: row[col+7] }
      });
      col += 10;
    }
    return match;
  });

  return ContentService.createTextOutput(JSON.stringify(history)).setMimeType(ContentService.MimeType.JSON);
}
