            secondary1Name: v(1), secondary1Pts: v(2),
            secondary2Name: v(3), secondary2Pts: v(4),
            secondary: (Number(v(2))||0) + (Number(v(4))||0), // Aggregated for graphs
            challenger: v(5), cpEarned: v(6), cpUsed: v(7)
          },
