            secondary: (Number(v(10))||0) + (Number(v(12))||0),
            challenger: v(13), cpEarned: v(14), cpUsed: v(15)
          }
        });
        col += 16; // Jump 16 columns per round
      }
    }
    return match;
  });

  return ContentService.createTextOutput(JSON.stringify(history))
    .setMimeType(ContentService.MimeType.JSON);
}
