  date: string;
  points: number;
  player1: string;
  army1: string;
  detachment1?: string;
  player2: string;
  army2: string;
  detachment2?: string;
  mission: string;
  p1Score: number;
  p2Score: number;
  rawRounds?: HistoricalRoundData[];
  // Hydrated metadata
  tournamentId?: string;
}

export interface ScoringGroup {
  label?: string;
  buttons: number[]; // e.g. [5, 10]
  max?: number; // e.g. 10
}

export interface ScoringRule {
  type: 'fixed' | 'tiered' | 'cumulative' | 'manual' | 'additive';
  options?: number[]; // For tiered/fixed, e.g. [0, 2, 5]
  increment?: number; // For cumulative, e.g. 4 for Assassination
  buttons?: number[]; // For simple additive, e.g. [2, 4]
  groups?: ScoringGroup[]; // For complex grouped additive
  max?: number;
}

// Tournament Types
export interface TournamentMatch {
  id: string;
  roundIndex: number; // 0 = Ro16, 1 = QF, etc.
  player1: string | null; // Null if waiting for previous match
  player2: string | null;
  winner: string | null;
  nextMatchId?: string; // ID of the match the winner advances to
  loserNextMatchId?: string; // For double elimination
  status: 'pending' | 'ready' | 'completed';
}

export interface Tournament {
  id: string;
  name: string;
  type: 'single' | 'double';
  participants: string[];
  matches: TournamentMatch[];
  rounds: number; // Total number of rounds
  status: 'active' | 'completed';
  dateCreated: string;
}

export const INITIAL_PLAYER_ROUND: PlayerRoundData = {
  primary: 0,
  secondary1_name: '',
  secondary1_pts: 0,
  secondary2_name: '',
  secondary2_pts: 0,
  challenger: 0,
  cpEarnedTurn1: false,
  cpGainedTurn1: false,
  cpEarnedTurn2: false,
  cpGainedTurn2: false,
  cpEarnedArmy: [],
  cpUsed: 0,
  stratagems: []
};

import { GOOGLE_SCRIPT_URL } from '../constants';
import { MatchState, HistoricalMatch } from '../types';

export const submitMatchData = async (matchState: MatchState) => {
  // Transform the React State Tree into the flat JSON structure expected by the GAS doPost

  // METADATA PACKING:
  // Since we can't change the GAS backend easily, we pack tournament data into the 'primaryMission' string.
  // Format: "MissionName [TID:123|MID:456]"
  let missionField = matchState.primaryMission;
  if (matchState.tournamentId) {
    missionField = `${matchState.primaryMission} [TID:${matchState.tournamentId}|MID:${matchState.bracketMatchId || '0'}]`;
  }

  const flatData: any = {
    points: matchState.points,
    player1: matchState.player1,
    player2: matchState.player2,
    army1: matchState.army1,
    army2: matchState.army2,
    detachmentP1: matchState.detachmentP1,
    detachmentP2: matchState.detachmentP2,
    primaryMission: missionField,
  };

  matchState.rounds.forEach((round, index) => {
    const i = index + 1; // 1-based index for GAS

    // Player 1
    flatData[`p1_primary_${i}`] = round.p1.primary;
    flatData[`p1_secondary1_name_${i}`] = round.p1.secondary1_name;
    flatData[`p1_secondary1_pts_${i}`] = round.p1.secondary1_pts;
    flatData[`p1_secondary2_name_${i}`] = round.p1.secondary2_name;
    flatData[`p1_secondary2_pts_${i}`] = round.p1.secondary2_pts;
    flatData[`p1_secondary_${i}`] = round.p1.secondary1_pts + round.p1.secondary2_pts; // Sum needed by backend
    flatData[`p1_challenger_${i}`] = round.p1.challenger;

    // Calculate Total CP Earned for the round
    const p1CpFromTurn = (round.p1.cpEarnedTurn1 ? 1 : 0) + (round.p1.cpEarnedTurn2 ? 1 : 0);
    const p1CpFromGained = (round.p1.cpGainedTurn1 ? 1 : 0) + (round.p1.cpGainedTurn2 ? 1 : 0);
    const p1CpFromArmy = round.p1.cpEarnedArmy.reduce((sum, val) => sum + parseFloat(val), 0);
    flatData[`p1_cp_earned_${i}`] = p1CpFromTurn + p1CpFromGained + p1CpFromArmy;

    flatData[`p1_cp_used_${i}`] = round.p1.cpUsed;

    // Send arrays for Stratagems/CP - GAS will join them
    flatData[`p1_stratagems_${i}`] = round.p1.stratagems; 
    flatData[`p1_cp_army_${i}`] = round.p1.cpEarnedArmy; 

    // Player 2
    flatData[`p2_primary_${i}`] = round.p2.primary;
    flatData[`p2_secondary1_name_${i}`] = round.p2.secondary1_name;
    flatData[`p2_secondary1_pts_${i}`] = round.p2.secondary1_pts;
    flatData[`p2_secondary2_name_${i}`] = round.p2.secondary2_name;
    flatData[`p2_secondary2_pts_${i}`] = round.p2.secondary2_pts;
    flatData[`p2_secondary_${i}`] = round.p2.secondary1_pts + round.p2.secondary2_pts;
    flatData[`p2_challenger_${i}`] = round.p2.challenger;

    const p2CpFromTurn = (round.p2.cpEarnedTurn1 ? 1 : 0) + (round.p2.cpEarnedTurn2 ? 1 : 0);
    const p2CpFromGained = (round.p2.cpGainedTurn1 ? 1 : 0) + (round.p2.cpGainedTurn2 ? 1 : 0);
    const p2CpFromArmy = round.p2.cpEarnedArmy.reduce((sum, val) => sum + parseFloat(val), 0);
    flatData[`p2_cp_earned_${i}`] = p2CpFromTurn + p2CpFromGained + p2CpFromArmy;

    flatData[`p2_cp_used_${i}`] = round.p2.cpUsed;

    // Send arrays for Stratagems/CP
    flatData[`p2_stratagems_${i}`] = round.p2.stratagems;
    flatData[`p2_cp_army_${i}`] = round.p2.cpEarnedArmy;
  });

  try {
    const response = await fetch(GOOGLE_SCRIPT_URL, {
      method: 'POST',
      mode: 'no-cors', 
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(flatData)
    });
    return true;
  } catch (error) {
    console.error("Transmission error:", error);
    throw error;
  }
};

export const getMatchHistory = async (): Promise<HistoricalMatch[] | null> => {
  try {
    // Add cache busting and action param to ensure GET request is fresh
    const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getHistory&t=${Date.now()}`, {
      method: 'GET',
    });

    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }

    const data = await response.json();
    if (!Array.isArray(data)) return [];

    // Unpack Metadata
    return data.map((m: any) => {
      let tournamentId = undefined;
      let cleanMission = m.mission;

      // Check for [TID:...] tag
      const metaMatch = m.mission && m.mission.match && m.mission.match(/\[TID:(.*?)(\|.*?)?\]/);
      if (metaMatch) {
        tournamentId = metaMatch[1];
        cleanMission = m.mission.replace(/\[.*?\]/, '').trim();
      }

      return {
        ...m,
        mission: cleanMission, // Show clean name in UI
        tournamentId
      };
    });

  } catch (error) {
    console.error("Fetch history error:", error);
    return null; 
  }
};

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { ARMY_DATA, MISSIONS, PLAYERS } from '../constants';
import { MatchState, INITIAL_PLAYER_ROUND } from '../types';
import { submitMatchData } from '../services/sheetsService';
import { Input } from '../components/ui/Input';
import { Select } from '../components/ui/Select';
import { Button } from '../components/ui/Button';
import { RoundInput } from '../components/RoundInput';
import { MatchGraphs } from '../components/MatchGraphs';

const INITIAL_STATE: MatchState = {
  points: 2000,
  primaryMission: '',
  player1: '',
  player2: '',
  army1: '',
  army2: '',
  detachmentP1: '',
  detachmentP2: '',
  rounds: Array(5).fill(null).map((_, i) => ({
    roundNumber: i + 1,
    p1: { ...INITIAL_PLAYER_ROUND },
    p2: { ...INITIAL_PLAYER_ROUND }
  }))
};

export const MatchLogger: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();

  // Check for Tournament Init State
  const tournamentState = location.state as Partial<MatchState> | undefined;

  const [activeTab, setActiveTab] = useState<'setup' | 1 | 2 | 3 | 4 | 5>('setup');
  const [matchData, setMatchData] = useState<MatchState>(() => {
    // If we have tournament state passed in, use it immediately
    if (tournamentState) {
        return { ...INITIAL_STATE, ...tournamentState };
    }

    const saved = localStorage.getItem('battleforge_match_v1');
    return saved ? JSON.parse(saved) : INITIAL_STATE;
  });
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Auto-save (Skip if in tournament mode to avoid overwriting standard local save, or use separate key)
  useEffect(() => {
    if (!tournamentState) {
       localStorage.setItem('battleforge_match_v1', JSON.stringify(matchData));
    }
  }, [matchData, tournamentState]);

  const updateSetup = (field: keyof MatchState, value: any) => {
    setMatchData(prev => ({ ...prev, [field]: value }));
  };

  const updateRound = (roundIdx: number, player: 'p1' | 'p2', data: any) => {
    setMatchData(prev => {
      const newRounds = [...prev.rounds];
      newRounds[roundIdx] = { ...newRounds[roundIdx], [player]: data };
      return { ...prev, rounds: newRounds };
    });
  };

  // Helper to calculate CP at the START of a round based on previous rounds
  const getStartCpForRound = (roundNum: number, player: 'p1' | 'p2'): number => {
    let cp = 0; 
    for(let i=0; i < roundNum - 1; i++) {
       const r = matchData.rounds[i][player];
       const earned = (r.cpEarnedTurn1 ? 1 : 0) + 
                      (r.cpEarnedTurn2 ? 1 : 0) + 
                      (r.cpGainedTurn1 ? 1 : 0) + 
                      (r.cpGainedTurn2 ? 1 : 0) + 
                      r.cpEarnedArmy.reduce((acc, val) => acc + Number(val), 0);
       cp += (earned - r.cpUsed);
    }
    return Math.max(0, cp);
  };

  // Helper to calculate cumulative SCORES (Primary/Secondary) from PREVIOUS rounds
  const getPriorScores = (roundNum: number, player: 'p1' | 'p2') => {
    let primary = 0;
    let secondary = 0;
    for(let i=0; i < roundNum - 1; i++) {
       const r = matchData.rounds[i][player];
       primary += r.primary;
       secondary += (r.secondary1_pts + r.secondary2_pts);
    }
    return { primary, secondary };
  };

  const handleClear = () => {
    if(confirm("Are you sure you want to clear all data?")) {
      setMatchData(INITIAL_STATE);
      setActiveTab('setup');
    }
  };

  const handleSubmit = async () => {
    if (!matchData.player1 || !matchData.player2) {
      alert("Please define players in setup.");
      setActiveTab('setup');
      return;
    }

    setIsSubmitting(true);
    try {
      await submitMatchData(matchData);

      // Calculate winner for tournament return
      let p1Score = 0, p2Score = 0;
      matchData.rounds.forEach(r => {
        p1Score += r.p1.primary + r.p1.secondary1_pts + r.p1.secondary2_pts + r.p1.challenger;
        p2Score += r.p2.primary + r.p2.secondary1_pts + r.p2.secondary2_pts + r.p2.challenger;
      });

      const winner = p1Score > p2Score ? matchData.player1 : (p2Score > p1Score ? matchData.player2 : null);

      alert("Match submitted successfully!");

      if (tournamentState) {
        // Return to Tournament Hub with result
        navigate('/tournament', { 
            state: { 
                completedMatchId: matchData.bracketMatchId, 
                winner: winner 
            } 
        });
      } else {
        setMatchData(INITIAL_STATE);
        localStorage.removeItem('battleforge_match_v1');
        setActiveTab('setup');
      }

    } catch (e) {
      alert("Failed to submit. Check internet connection.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const armyOptions = Object.keys(ARMY_DATA).map(k => ({ label: k, value: k }));
  const playerOptions = PLAYERS.map(p => ({ label: p, value: p }));
  const missionOptions = MISSIONS.map(m => ({ label: m, value: m }));

  const getDetachments = (armyName: string) => {
    return (ARMY_DATA[armyName]?.detachments || []).map(d => ({ label: d, value: d }));
  };

  // Pre-calculate prior scores for current round
  const activeRoundNum = typeof activeTab === 'number' ? activeTab : 1;
  const p1Prior = getPriorScores(activeRoundNum, 'p1');
  const p2Prior = getPriorScores(activeRoundNum, 'p2');

  const isTournamentMode = !!matchData.tournamentId;

  return (
    <div className="min-h-screen pb-20">
      <header className="bg-war-panel border-b border-zinc-700 p-4 sticky top-0 z-50 shadow-lg">
        <div className="container mx-auto flex justify-between items-center">
          <div className="flex flex-col">
            <h1 className="text-2xl font-orbitron font-bold text-war-red tracking-widest leading-none">
              BATTLE<span className="text-white">FORGE</span>
            </h1>
            {isTournamentMode && <span className="text-xs text-green-400 font-mono">TOURNAMENT MATCH</span>}
          </div>
          <div className="flex gap-2">
            {!isTournamentMode && <Button variant="secondary" className="text-xs py-2 px-3" onClick={() => navigate('/history')}>
               STATS
            </Button>}
             <Button variant="secondary" className="text-xs py-2 px-3" onClick={() => navigate('/tournament')}>
               BRACKETS
            </Button>
            <Button variant="danger" className="text-xs py-2 px-3" onClick={handleClear}>
               RESET
            </Button>
          </div>
        </div>
      </header>

      <main className="container mx-auto p-4 max-w-4xl">

        {(matchData.player1 && matchData.player2) && (
          <MatchGraphs matchData={matchData} />
        )}

        {activeTab === 'setup' && (
          <div className="animate-fade-in space-y-6">
             <div className="bg-war-panel p-6 rounded-lg border border-zinc-700 shadow-xl">
                <h2 className="text-xl font-orbitron mb-6 border-b border-zinc-700 pb-2">Match Setup</h2>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                   <Input label="Points Limit" type="number" value={matchData.points} onChange={e => updateSetup('points', parseInt(e.target.value))} />
                   <Select label="Primary Mission" options={missionOptions} value={matchData.primaryMission} onChange={e => updateSetup('primaryMission', e.target.value)} placeholder="Select Mission" />
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                   <div className="space-y-4 p-4 border border-zinc-800 rounded bg-zinc-900/50">
                      <h3 className="text-war-red font-bold font-orbitron">Player 1 (Attacker)</h3>
                      {isTournamentMode ? (
                        <div className="text-white font-bold text-lg border-b border-zinc-700 pb-2">{matchData.player1}</div>
                      ) : (
                        <Select label="Name" options={playerOptions} value={matchData.player1} onChange={e => updateSetup('player1', e.target.value)} placeholder="Select Player" />
                      )}
                      <Select label="Army" options={armyOptions} value={matchData.army1} onChange={e => updateSetup('army1', e.target.value)} placeholder="Select Faction" />
                      <Select label="Detachment" options={getDetachments(matchData.army1)} value={matchData.detachmentP1} onChange={e => updateSetup('detachmentP1', e.target.value)} placeholder="Select Detachment" disabled={!matchData.army1} />
                   </div>

                   <div className="space-y-4 p-4 border border-zinc-800 rounded bg-zinc-900/50">
                      <h3 className="text-blue-500 font-bold font-orbitron">Player 2 (Defender)</h3>
                      {isTournamentMode ? (
                        <div className="text-white font-bold text-lg border-b border-zinc-700 pb-2">{matchData.player2}</div>
                      ) : (
                        <Select label="Name" options={playerOptions} value={matchData.player2} onChange={e => updateSetup('player2', e.target.value)} placeholder="Select Player" />
                      )}
                      <Select label="Army" options={armyOptions} value={matchData.army2} onChange={e => updateSetup('army2', e.target.value)} placeholder="Select Faction" />
                      <Select label="Detachment" options={getDetachments(matchData.army2)} value={matchData.detachmentP2} onChange={e => updateSetup('detachmentP2', e.target.value)} placeholder="Select Detachment" disabled={!matchData.army2} />
                   </div>
                </div>
             </div>

             <div className="flex justify-end">
               <Button onClick={() => setActiveTab(1)}>Start Round 1 &rarr;</Button>
             </div>
          </div>
        )}

        {typeof activeTab === 'number' && (
          <div className="animate-fade-in space-y-6">
            <h2 className="text-2xl font-orbitron text-center mb-6">Round {activeTab}</h2>

            <div className="grid grid-cols-1 gap-6">
              <RoundInput 
                playerName={matchData.player1}
                playerData={matchData.rounds[activeTab - 1].p1}
                armyData={ARMY_DATA[matchData.army1]}
                detachmentName={matchData.detachmentP1}
                roundNumber={activeTab}
                primaryMission={matchData.primaryMission}
                onChange={(d) => updateRound(activeTab - 1 as number, 'p1', d)}
                startingCp={getStartCpForRound(activeTab, 'p1')}
                priorPrimary={p1Prior.primary}
                priorSecondary={p1Prior.secondary}
              />

              <RoundInput 
                isPlayer2
                playerName={matchData.player2}
                playerData={matchData.rounds[activeTab - 1].p2}
                armyData={ARMY_DATA[matchData.army2]}
                detachmentName={matchData.detachmentP2}
                roundNumber={activeTab}
                primaryMission={matchData.primaryMission}
                onChange={(d) => updateRound(activeTab - 1 as number, 'p2', d)}
                startingCp={getStartCpForRound(activeTab, 'p2')}
                priorPrimary={p2Prior.primary}
                priorSecondary={p2Prior.secondary}
              />
            </div>

            <div className="flex justify-between mt-8">
               {activeTab === 5 ? (
                 <Button onClick={handleSubmit} className="w-full bg-green-600 hover:bg-green-700" disabled={isSubmitting}>
                    {isSubmitting ? 'Submitting...' : 'FINISH GAME'}
                 </Button>
               ) : (
                 <Button onClick={() => setActiveTab((activeTab + 1) as any)} className="w-full">
                    Next Round &rarr;
                 </Button>
               )}
            </div>
          </div>
        )}

      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-black border-t border-zinc-800 flex justify-between items-center text-xs font-orbitron z-50">
         <button onClick={() => setActiveTab('setup')} className={`flex-1 py-4 text-center hover:bg-zinc-900 ${activeTab === 'setup' ? 'text-war-red bg-zinc-900 border-t-2 border-war-red' : 'text-zinc-500'}`}>SETUP</button>
         {[1,2,3,4,5].map(r => (
           <button 
             key={r} 
             onClick={() => setActiveTab(r as any)} 
             className={`flex-1 py-4 text-center hover:bg-zinc-900 ${activeTab === r ? 'text-war-red bg-zinc-900 border-t-2 border-war-red' : 'text-zinc-500'}`}
           >
             R{r}
           </button>
         ))}
      </nav>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { PLAYERS } from '../constants';
import { Tournament, TournamentMatch } from '../types';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';
import { Select } from '../components/ui/Select';

export const TournamentHub: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [activeTournament, setActiveTournament] = useState<Tournament | null>(null);
  const [newTourneyName, setNewTourneyName] = useState('');
  const [selectedPlayers, setSelectedPlayers] = useState<string[]>([]);
  const [tourneyType, setTourneyType] = useState<'single' | 'double'>('single');

  // Load active tournament
  useEffect(() => {
    const saved = localStorage.getItem('battleforge_active_tournament');
    if (saved) {
      setActiveTournament(JSON.parse(saved));
    }
  }, []);

  // Handle return from MatchLogger with results
  useEffect(() => {
    if (location.state && location.state.completedMatchId && activeTournament) {
      const { completedMatchId, winner } = location.state;
      handleMatchCompletion(completedMatchId, winner);
      // Clear state so we don't re-process on refresh
      window.history.replaceState({}, document.title);
    }
  }, [location.state, activeTournament]);

  const handleMatchCompletion = (matchId: string, winner: string | null) => {
    if (!activeTournament || !winner) return;

    const newMatches = [...activeTournament.matches];
    const matchIndex = newMatches.findIndex(m => m.id === matchId);
    if (matchIndex === -1) return;

    const match = newMatches[matchIndex];
    match.winner = winner;
    match.status = 'completed';

    // Advance winner to next match
    if (match.nextMatchId) {
      const nextMatchIndex = newMatches.findIndex(m => m.id === match.nextMatchId);
      if (nextMatchIndex > -1) {
        const nextMatch = newMatches[nextMatchIndex];
        // Are we P1 or P2 in the next match? 
        // Logic: If current match ID is even/odd relative to bracket? 
        // Simplification: We need to know which slot in the next match to fill.
        // Simple tree algorithm: Parent 1 -> Next Match Slot 1. Parent 2 -> Next Match Slot 2.
        // We can check which one is empty, or pre-calculate this link.

        if (!nextMatch.player1) nextMatch.player1 = winner;
        else if (!nextMatch.player2) nextMatch.player2 = winner;

        if (nextMatch.player1 && nextMatch.player2) nextMatch.status = 'ready';
      }
    }

    const updatedTourney = { ...activeTournament, matches: newMatches };
    setActiveTournament(updatedTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(updatedTourney));
  };

  const createTournament = () => {
    if (!newTourneyName || selectedPlayers.length < 2) {
      alert("Enter name and select at least 2 players.");
      return;
    }

    // Shuffle Players
    const shuffled = [...selectedPlayers].sort(() => 0.5 - Math.random());

    // Generate Bracket
    const matches: TournamentMatch[] = [];
    let matchIdCounter = 1;

    // Calculate required rounds (Power of 2)
    const count = shuffled.length;
    let size = 2;
    while(size < count) size *= 2;

    // Fill with "Byes" if needed
    while(shuffled.length < size) {
      shuffled.push("BYE");
    }

    // ROUND 1
    const round1Matches = size / 2;
    const round1Ids: string[] = [];

    for(let i=0; i<round1Matches; i++) {
       const p1 = shuffled[i*2];
       const p2 = shuffled[i*2+1];

       const id = `m_${matchIdCounter++}`;
       round1Ids.push(id);

       const isBye = p2 === "BYE";
       matches.push({
         id,
         roundIndex: 0,
         player1: p1,
         player2: isBye ? null : p2,
         winner: isBye ? p1 : null,
         status: isBye ? 'completed' : 'ready'
       });
    }

    // SUBSEQUENT ROUNDS
    let currentRoundIds = round1Ids;
    let roundIdx = 1;

    while(currentRoundIds.length > 1) {
      const nextRoundIds: string[] = [];
      for(let i=0; i < currentRoundIds.length; i+=2) {
         const id = `m_${matchIdCounter++}`;
         nextRoundIds.push(id);

         const prev1 = matches.find(m => m.id === currentRoundIds[i]);
         const prev2 = matches.find(m => m.id === currentRoundIds[i+1]);

         if(prev1) prev1.nextMatchId = id;
         if(prev2) prev2.nextMatchId = id;

         matches.push({
           id,
           roundIndex: roundIdx,
           player1: prev1?.winner || null, // If Bye, auto-advance
           player2: prev2?.winner || null,
           winner: null,
           status: (prev1?.winner && prev2?.winner) ? 'ready' : 'pending'
         });
      }
      currentRoundIds = nextRoundIds;
      roundIdx++;
    }

    const newTourney: Tournament = {
      id: newTourneyName.replace(/\s+/g, '') + '_' + Date.now(),
      name: newTourneyName,
      type: tourneyType,
      participants: selectedPlayers,
      matches,
      rounds: roundIdx,
      status: 'active',
      dateCreated: new Date().toISOString()
    };

    setActiveTournament(newTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(newTourney));
  };

  const handlePlayerToggle = (p: string) => {
    if (selectedPlayers.includes(p)) setSelectedPlayers(selectedPlayers.filter(x => x !== p));
    else setSelectedPlayers([...selectedPlayers, p]);
  };

  const deleteTournament = () => {
    if(confirm("Delete active tournament? This cannot be undone.")) {
       localStorage.removeItem('battleforge_active_tournament');
       setActiveTournament(null);
       setNewTourneyName('');
       setSelectedPlayers([]);
    }
  };

  const startMatch = (m: TournamentMatch) => {
     if (!activeTournament) return;
     if (m.status !== 'ready') return;

     navigate('/', { 
       state: {
         player1: m.player1,
         player2: m.player2,
         tournamentId: activeTournament.id,
         bracketMatchId: m.id
       }
     });
  };

  return (
    <div className="min-h-screen bg-war-dark pb-20 p-4">
      <header className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-orbitron font-bold text-war-red">
          TOURNAMENT<span className="text-white">HUB</span>
        </h1>
        <Button variant="secondary" onClick={() => navigate('/')} className="text-xs py-2 px-3">&larr; App</Button>
      </header>

      {!activeTournament ? (
        <div className="bg-war-panel border border-zinc-700 rounded-lg p-6 max-w-2xl mx-auto shadow-xl animate-fade-in">
           <h2 className="text-xl font-orbitron text-white mb-4">Create New Tournament</h2>

           <div className="space-y-4">
             <Input label="Tournament Name" value={newTourneyName} onChange={e => setNewTourneyName(e.target.value)} placeholder="e.g. Summer Slam 2024" />

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Format</label>
               <div className="flex gap-2">
                 <button onClick={() => setTourneyType('single')} className={`flex-1 py-2 rounded border ${tourneyType === 'single' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Single Elimination</button>
                 <button disabled className="flex-1 py-2 rounded border bg-zinc-900 border-zinc-800 text-zinc-600 cursor-not-allowed">Double Elimination (Coming Soon)</button>
               </div>
             </div>

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Participants ({selectedPlayers.length})</label>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-2 bg-zinc-900 p-3 rounded border border-zinc-800 max-h-40 overflow-y-auto">
                 {PLAYERS.map(p => (
                   <button 
                     key={p} 
                     onClick={() => handlePlayerToggle(p)}
                     className={`text-xs p-2 rounded text-left transition-colors ${selectedPlayers.includes(p) ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
                   >
                     {p}
                   </button>
                 ))}
               </div>
             </div>

             <Button onClick={createTournament} className="w-full mt-4">Generate Bracket</Button>
           </div>
        </div>
      ) : (
        <div className="animate-fade-in overflow-x-auto">
           <div className="flex justify-between items-center mb-4 min-w-[600px]">
             <div>
               <h2 className="text-2xl font-bold font-orbitron text-white">{activeTournament.name}</h2>
               <div className="text-xs text-zinc-500">Status: {activeTournament.status}</div>
             </div>
             <Button variant="danger" onClick={deleteTournament} className="text-xs py-1 px-3">End Tournament</Button>
           </div>

           {/* BRACKET VISUALIZATION */}
           <div className="flex gap-8 min-w-max pb-10">
              {Array.from({ length: activeTournament.rounds }).map((_, rIdx) => {
                 const roundMatches = activeTournament.matches.filter(m => m.roundIndex === rIdx);
                 return (
                   <div key={rIdx} className="flex flex-col justify-around gap-8 w-64">
                      <div className="text-center text-war-red font-orbitron text-sm font-bold uppercase mb-4 bg-black/40 p-1 rounded">
                        {rIdx === activeTournament.rounds - 1 ? "Finals" : `Round ${rIdx + 1}`}
                      </div>
                      {roundMatches.map(m => {
                        const isReady = m.status === 'ready';
                        const isComplete = m.status === 'completed';
                        return (
                          <div 
                             key={m.id} 
                             onClick={() => isReady && startMatch(m)}
                             className={`
                               relative p-3 rounded border transition-all 
                               ${isComplete ? 'bg-green-900/20 border-green-800' : isReady ? 'bg-war-panel border-war-red cursor-pointer hover:bg-zinc-800 hover:scale-[1.02] shadow-[0_0_10px_rgba(255,45,45,0.2)]' : 'bg-zinc-900 border-zinc-800 opacity-60'}
                             `}
                          >
                             <div className={`text-sm font-bold ${m.winner === m.player1 && isComplete ? 'text-green-400' : 'text-zinc-300'}`}>
                               {m.player1 || 'Waiting...'}
                             </div>
                             <div className="h-px bg-zinc-700 my-2"></div>
                             <div className={`text-sm font-bold ${m.winner === m.player2 && isComplete ? 'text-green-400' : 'text-zinc-300'}`}>
                               {m.player2 || 'Waiting...'}
                             </div>

                             {/* Connector Line Logic (Simplified for Visuals) */}
                             {rIdx < activeTournament.rounds - 1 && (
                               <div className="absolute top-1/2 -right-8 w-8 h-px bg-zinc-700 z-0"></div>
                             )}
                          </div>
                        );
                      })}
                   </div>
                 );
              })}
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { getMatchHistory } from '../services/sheetsService';
import { HistoricalMatch } from '../types';
import { Button } from '../components/ui/Button';
import { Select } from '../components/ui/Select';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';

export const History: React.FC = () => {
  const navigate = useNavigate();
  const [matches, setMatches] = useState<HistoricalMatch[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [view, setView] = useState<'leaderboard' | 'tournaments' | 'matchups' | 'analysis' | 'game' | 'logs'>('leaderboard');

  // Winrate Filter State
  const [winrateFilter, setWinrateFilter] = useState<'all' | '2000' | 'sub2000'>('all');

  // Analysis State
  const [selectedPlayer, setSelectedPlayer] = useState<string>('');
  const [selectedGameId, setSelectedGameId] = useState<string>('');

  // Scorecard Modal State
  const [selectedMatch, setSelectedMatch] = useState<HistoricalMatch | null>(null);

  const loadData = () => {
    setLoading(true);
    setError(null);
    getMatchHistory().then(data => {
      if (data === null) {
        setError("Unable to connect to the database. Please check your internet connection or deployment settings.");
      } else {
        // Filter out any rows that are actually headers (e.g. "Player 1")
        const validMatches = data.filter(m => {
          const p1 = m.player1?.trim().toLowerCase();
          const p2 = m.player2?.trim().toLowerCase();
          if (!p1 || !p2) return false;
          // Check for common header values
          const invalidNames = ['player 1', 'player 2', 'name', 'player name', 'player', 'p1', 'p2'];
          if (invalidNames.includes(p1) || invalidNames.includes(p2)) return false;
          return true;
        });

        setMatches(validMatches.reverse());
      }
      setLoading(false);
    });
  };

  useEffect(() => {
    loadData();
  }, []);

  // --- Winrate Logic (Leaderboard) ---
  const winrates = useMemo(() => {
    const results: Record<string, { wins: number, losses: number, draws: number }> = {};

    // Filter matches based on points criteria
    const filteredMatches = matches.filter(m => {
      // Exclude tournament games from general winrates if desired? User asked for "separate".
      // Let's keep them in unless explicitly asked to remove, but the filter handles points.

      if (winrateFilter === '2000') return m.points === 2000;
      if (winrateFilter === 'sub2000') return m.points < 2000;
      return true; // 'all'
    });

    filteredMatches.forEach(m => {
       const key1 = `${m.player1} | ${m.army1}`;
       const key2 = `${m.player2} | ${m.army2}`;

       if (!results[key1]) results[key1] = { wins: 0, losses: 0, draws: 0 };
       if (!results[key2]) results[key2] = { wins: 0, losses: 0, draws: 0 };

       let p1 = 0;
       let p2 = 0;

       if (m.rawRounds && m.rawRounds.length > 0) {
         p1 = m.rawRounds.reduce((acc, r) => acc + (Number(r.p1.primary)||0) + (Number(r.p1.secondary)||0) + (Number(r.p1.challenger)||0), 0);
         p2 = m.rawRounds.reduce((acc, r) => acc + (Number(r.p2.primary)||0) + (Number(r.p2.secondary)||0) + (Number(r.p2.challenger)||0), 0);
       } else {
         p1 = Number(m.p1Score) || 0;
         p2 = Number(m.p2Score) || 0;
       }

       if (p1 > p2) {
         results[key1].wins++;
         results[key2].losses++;
       } else if (p1 < p2) {
         results[key1].losses++;
         results[key2].wins++;
       } else {
         results[key1].draws++;
         results[key2].draws++;
       }
    });

    return Object.entries(results).map(([key, stats]) => {
      const [player, army] = key.split(" | ");
      const total = stats.wins + stats.losses + stats.draws;
      const rate = total > 0 ? (stats.wins / total) * 100 : 0;
      return { player, army, total, ...stats, rate };
    }).sort((a, b) => b.rate - a.rate);
  }, [matches, winrateFilter]); 

  // --- Tournament Grouping Logic ---
  const tournamentGroups = useMemo(() => {
    const groups: Record<string, HistoricalMatch[]> = {};
    matches.forEach(m => {
      if (m.tournamentId) {
        if (!groups[m.tournamentId]) groups[m.tournamentId] = [];
        groups[m.tournamentId].push(m);
      }
    });
    return Object.entries(groups).map(([id, ms]) => ({ id, matches: ms }));
  }, [matches]);

  // --- Matchup Logic ---
  const matchups = useMemo(() => {
    const counts: Record<string, number> = {};
    matches.forEach(m => {
       const players = [m.player1, m.player2].sort();
       const key = `${players[0]} vs ${players[1]}`;
       counts[key] = (counts[key] || 0) + 1;
    });
    return Object.entries(counts)
      .map(([matchup, count]) => ({ matchup, count }))
      .sort((a, b) => b.count - a.count);
  }, [matches]);

  // --- Player Average Graph Logic ---
  const playerAverageData = useMemo(() => {
    if (!selectedPlayer) return [];

    const totals = Array(5).fill(0).map(() => ({ primary: 0, secondary: 0, challenger: 0 }));
    let gameCount = 0;

    matches.forEach(m => {
      if ((m.player1 === selectedPlayer || m.player2 === selectedPlayer) && m.rawRounds) {
        gameCount++;
        m.rawRounds.forEach((r, idx) => {
          if (idx >= 5) return; 
          const isP1 = m.player1 === selectedPlayer;
          const pData = isP1 ? r.p1 : r.p2;
          totals[idx].primary += Number(pData.primary) || 0;
          totals[idx].secondary += Number(pData.secondary) || 0;
          totals[idx].challenger += Number(pData.challenger) || 0;
        });
      }
    });

    if (gameCount === 0) return [];

    let cumPrimary = 0, cumSecondary = 0, cumChallenger = 0;

    return totals.map((t, idx) => {
      const avgPrim = t.primary / gameCount;
      const avgSec = t.secondary / gameCount;
      const avgChal = t.challenger / gameCount;

      cumPrimary += avgPrim;
      cumSecondary += avgSec;
      cumChallenger += avgChal;

      return {
        round: `R${idx + 1}`,
        Primary: parseFloat(cumPrimary.toFixed(1)),
        Secondary: parseFloat(cumSecondary.toFixed(1)),
        Challenger: parseFloat(cumChallenger.toFixed(1)),
        Total: parseFloat((cumPrimary + cumSecondary + cumChallenger).toFixed(1))
      };
    });
  }, [matches, selectedPlayer]);

  // --- Single Game Graph Logic ---
  const singleGameData = useMemo(() => {
    if (!selectedGameId) return null;
    const m = matches.find(match => String(match.id) === selectedGameId);
    if (!m || !m.rawRounds) return null;

    let p1Sum = 0, p2Sum = 0;
    const data = m.rawRounds.map(r => {
       const p1RoundTotal = (Number(r.p1.primary)||0) + (Number(r.p1.secondary)||0) + (Number(r.p1.challenger)||0);
       const p2RoundTotal = (Number(r.p2.primary)||0) + (Number(r.p2.secondary)||0) + (Number(r.p2.challenger)||0);
       p1Sum += p1RoundTotal;
       p2Sum += p2RoundTotal;

       return {
         round: `R${r.round}`,
         [m.player1]: p1Sum,
         [m.player2]: p2Sum
       };
    });
    return { data, p1: m.player1, p2: m.player2 };
  }, [matches, selectedGameId]);

  const allPlayers = Array.from(new Set(matches.flatMap(m => [m.player1, m.player2]))).sort();
  const allGameOptions = matches.map(m => ({ label: `${m.date.split('T')[0]}: ${m.player1} vs ${m.player2}`, value: String(m.id) }));

  const getScore = (m: HistoricalMatch, p: 'p1' | 'p2') => {
      if (m.rawRounds && m.rawRounds.length > 0) {
          return m.rawRounds.reduce((acc, r) => acc + (Number(r[p].primary)||0) + (Number(r[p].secondary)||0) + (Number(r[p].challenger)||0), 0);
      }
      return p === 'p1' ? m.p1Score : m.p2Score;
  }

  // --- SCORECARD COMPONENT ---
  const ScorecardModal: React.FC<{ match: HistoricalMatch; onClose: () => void }> = ({ match, onClose }) => {
    if (!match.rawRounds) return null;

    const getUniqueSecondaries = (player: 'p1' | 'p2') => {
      const set = new Set<string>();
      match.rawRounds?.forEach(r => {
         const d = r[player];
         if (d.secondary1Name) set.add(d.secondary1Name);
         if (d.secondary2Name) set.add(d.secondary2Name);
      });
      const list = Array.from(set);
      if (list.length === 0) {
         const totalSecPoints = match.rawRounds?.reduce((acc, r) => acc + (Number(r[player].secondary1Pts)||0) + (Number(r[player].secondary2Pts)||0), 0) || 0;
         if (totalSecPoints > 0) return ["Legacy / Unknown Secondary"];
      }
      return list;
    };

    const p1Secondaries = getUniqueSecondaries('p1');
    const p2Secondaries = getUniqueSecondaries('p2');

    const calculateCpFlow = (player: 'p1' | 'p2') => {
       let current = 0; 
       const flow = [];
       for(let i=0; i<5; i++) {
          const r = match.rawRounds![i];
          if(!r) { flow.push(0); continue; }
          const pData = r[player];
          const start = current;
          const end = start + Number(pData.cpEarned) - Number(pData.cpUsed);
          current = Math.max(0, end);
          flow.push(current);
       }
       return flow;
    };

    const p1Cp = calculateCpFlow('p1');
    const p2Cp = calculateCpFlow('p2');
    const s1Total = getScore(match, 'p1');
    const s2Total = getScore(match, 'p2');
    const winner = s1Total > s2Total ? match.player1 : (s2Total > s1Total ? match.player2 : "Draw");

    const ScoreRow = ({ label, data, type }: { label: string, data: any[], type: 'p1'|'p2' }) => {
      const total = data.reduce((a,b) => a+b, 0);
      return (
        <div className="grid grid-cols-[3fr_repeat(5,1fr)_1.5fr] text-sm border-b border-zinc-800 hover:bg-white/5">
           <div className="p-2 text-zinc-400 truncate border-r border-zinc-800">{label}</div>
           {[0,1,2,3,4].map(idx => (
             <div key={idx} className="p-2 text-center text-zinc-300 border-r border-zinc-800">
               {data[idx] > 0 ? data[idx] : <span className="text-zinc-700">-</span>}
             </div>
           ))}
           <div className="p-2 text-center font-bold text-white bg-white/5">{total}</div>
        </div>
      );
    };

    const SecondaryRow = ({ mission, type }: { mission: string, type: 'p1'|'p2' }) => {
       const scores = [0,1,2,3,4].map(idx => {
          const r = match.rawRounds![idx];
          if (!r) return 0;
          const d = r[type];
          let pts = 0;
          if (mission === "Legacy / Unknown Secondary") {
             if (!d.secondary1Name) pts += Number(d.secondary1Pts);
             if (!d.secondary2Name) pts += Number(d.secondary2Pts);
          } else {
             if (d.secondary1Name === mission) pts += Number(d.secondary1Pts);
             if (d.secondary2Name === mission) pts += Number(d.secondary2Pts);
          }
          return pts;
       });
       return <ScoreRow label={mission} data={scores} type={type} />;
    };

    const renderPlayerSection = (player: string, army: string, detach: string | undefined, type: 'p1'|'p2', cpData: number[]) => {
       const rounds = match.rawRounds || [];
       const primaryScores = rounds.map(r => Number(r[type].primary)||0);
       const challScores = rounds.map(r => Number(r[type].challenger)||0);
       const score = type === 'p1' ? s1Total : s2Total;
       const isWinner = winner === player;

       return (
         <div className="mb-8">
            <div className="flex justify-between items-end mb-2 border-b-2 border-zinc-700 pb-2">
               <div>
                 <div className="text-xl font-bold font-orbitron text-white">{player}</div>
                 <div className="text-xs text-zinc-400">{army}</div>
                 {detach && <div className="text-[10px] text-zinc-500">{detach}</div>}
               </div>
               <div className={`text-3xl font-orbitron font-bold ${isWinner ? 'text-green-500' : 'text-zinc-500'}`}>
                 {score}
               </div>
            </div>
            <div className="bg-zinc-900/50 rounded border border-zinc-800 overflow-hidden">
               <div className="grid grid-cols-[3fr_repeat(5,1fr)_1.5fr] bg-black/40 text-xs text-zinc-500 font-bold uppercase">
                  <div className="p-2">Mission</div>
                  {[1,2,3,4,5].map(r => <div key={r} className="p-2 text-center">R{r}</div>)}
                  <div className="p-2 text-center">Total</div>
               </div>
               <ScoreRow label={match.mission} data={primaryScores} type={type} />
               {(type === 'p1' ? p1Secondaries : p2Secondaries).map(m => (
                  <SecondaryRow key={m} mission={m} type={type} />
               ))}
               {challScores.some(s => s > 0) && (
                 <ScoreRow label="Challenger" data={challScores} type={type} />
               )}
               <div className="grid grid-cols-[3fr_repeat(5,1fr)_1.5fr] text-sm border-t border-zinc-700 bg-white/5 mt-1">
                  <div className="p-2 text-zinc-400 font-bold border-r border-zinc-800">CP Remaining</div>
                  {cpData.map((cp, idx) => (
                    <div key={idx} className="p-2 text-center text-zinc-300 border-r border-zinc-800">{cp}</div>
                  ))}
                  <div className="p-2 bg-black/20"></div>
               </div>
            </div>
         </div>
       );
    };

    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/90 backdrop-blur-sm animate-fade-in">
         <div className="bg-war-panel w-full max-w-3xl max-h-[90vh] overflow-y-auto rounded-xl border border-zinc-700 shadow-2xl flex flex-col">
            <div className="p-4 border-b border-zinc-700 flex justify-between items-center bg-black/40 sticky top-0 z-10 backdrop-blur">
               <div>
                  <div className="text-xs text-zinc-500 font-mono">{new Date(match.date).toLocaleDateString()}</div>
                  <div className="text-lg font-orbitron text-war-red font-bold">MATCH SCORECARD</div>
               </div>
               <button onClick={onClose} className="text-zinc-400 hover:text-white hover:bg-zinc-800 p-2 rounded transition-colors">
                 ✕ Close
               </button>
            </div>
            <div className="p-6">
               <div className="flex justify-center items-center gap-6 mb-8 font-orbitron font-bold">
                  <div className={`text-2xl ${s1Total > s2Total ? 'text-green-500' : s1Total < s2Total ? 'text-red-500' : 'text-zinc-400'}`}>{s1Total}</div>
                  <div className="text-zinc-600 text-sm">VS</div>
                  <div className={`text-2xl ${s2Total > s1Total ? 'text-green-500' : s2Total < s1Total ? 'text-red-500' : 'text-zinc-400'}`}>{s2Total}</div>
               </div>
               {renderPlayerSection(match.player1, match.army1, match.detachment1, 'p1', p1Cp)}
               {renderPlayerSection(match.player2, match.army2, match.detachment2, 'p2', p2Cp)}
            </div>
         </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-war-dark pb-20 p-4">
      {selectedMatch && <ScorecardModal match={selectedMatch} onClose={() => setSelectedMatch(null)} />}

      <header className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
        <h1 className="text-2xl font-orbitron font-bold text-war-red">
          BATTLE<span className="text-white">LOGS</span>
        </h1>
        <div className="flex flex-wrap gap-2 justify-center">
           <Button variant={view === 'leaderboard' ? 'primary' : 'secondary'} onClick={() => setView('leaderboard')} className="text-xs py-2 px-3">Winrates</Button>
           <Button variant={view === 'tournaments' ? 'primary' : 'secondary'} onClick={() => setView('tournaments')} className="text-xs py-2 px-3">Tournaments</Button>
           <Button variant={view === 'matchups' ? 'primary' : 'secondary'} onClick={() => setView('matchups')} className="text-xs py-2 px-3">Matchups</Button>
           <Button variant={view === 'analysis' ? 'primary' : 'secondary'} onClick={() => setView('analysis')} className="text-xs py-2 px-3">Player Avg</Button>
           <Button variant={view === 'game' ? 'primary' : 'secondary'} onClick={() => setView('game')} className="text-xs py-2 px-3">Game Review</Button>
           <Button variant={view === 'logs' ? 'primary' : 'secondary'} onClick={() => setView('logs')} className="text-xs py-2 px-3">History</Button>
           <Button variant="secondary" onClick={() => navigate('/')} className="text-xs py-2 px-3">&larr; App</Button>
        </div>
      </header>

      {loading ? (
        <div className="text-center text-zinc-500 font-orbitron animate-pulse mt-20">Accessing Archives...</div>
      ) : error ? (
        <div className="text-center mt-20 p-6 bg-war-panel border border-red-900 rounded-lg max-w-lg mx-auto">
          <p className="text-red-400 font-bold mb-4 font-orbitron">Connection Failed</p>
          <p className="text-zinc-400 mb-4">{error}</p>
          <Button onClick={loadData} variant="primary">Retry Connection</Button>
        </div>
      ) : (
        <div className="max-w-5xl mx-auto space-y-8 animate-fade-in">

          {/* WINRATES VIEW */}
          {view === 'leaderboard' && (
              <div className="bg-war-panel border border-zinc-700 rounded-lg p-6 shadow-xl">
                 <div className="flex flex-col md:flex-row justify-between items-center mb-4 border-b border-zinc-700 pb-2 gap-3">
                   <h2 className="text-xl font-orbitron text-white">
                     {winrateFilter === 'all' ? 'Overall Winrates' : winrateFilter === '2000' ? '2000 Pts Winrates' : 'Sub-2000 Pts Winrates'}
                   </h2>
                   <div className="flex gap-2">
                     <button 
                        onClick={() => setWinrateFilter('all')} 
                        className={`text-xs px-3 py-1 rounded transition-colors ${winrateFilter === 'all' ? 'bg-war-red text-white font-bold' : 'bg-zinc-800 text-zinc-400 hover:text-white'}`}
                     >
