import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { PLAYERS } from '../constants';
import { Tournament, TournamentMatch } from '../types';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';

export const TournamentHub: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [activeTournament, setActiveTournament] = useState<Tournament | null>(null);
  const [newTourneyName, setNewTourneyName] = useState('');
  const [selectedPlayers, setSelectedPlayers] = useState<string[]>([]);
  const [tourneyType, setTourneyType] = useState<'single' | 'double'>('single');

  // Load active tournament
  useEffect(() => {
    const saved = localStorage.getItem('battleforge_active_tournament');
    if (saved) {
      setActiveTournament(JSON.parse(saved));
    }
  }, []);

  // Handle return from MatchLogger with results
  useEffect(() => {
    if (location.state && location.state.completedMatchId && activeTournament) {
      const { completedMatchId, winner } = location.state;
      handleMatchCompletion(completedMatchId, winner);
      // Clear state so we don't re-process on refresh
      window.history.replaceState({}, document.title);
    }
  }, [location.state, activeTournament]);

  const updateMatchPlayer = (matches: TournamentMatch[], targetId: string, player: string) => {
    const target = matches.find(m => m.id === targetId);
    if (!target) return;

    if (!target.player1) target.player1 = player;
    else if (!target.player2) target.player2 = player;

    if (target.player1 && target.player2) target.status = 'ready';
  };

  const handleMatchCompletion = (matchId: string, winner: string | null) => {
    if (!activeTournament || !winner) return;

    const newMatches = [...activeTournament.matches];
    const match = newMatches.find(m => m.id === matchId);
    if (!match) return;

    match.winner = winner;
    match.status = 'completed';

    // 1. Advance Winner
    if (match.nextMatchId) {
      updateMatchPlayer(newMatches, match.nextMatchId, winner);
    }

    // 2. Advance Loser (Double Elim)
    if (match.loserNextMatchId && match.player1 && match.player2) {
      const loser = match.winner === match.player1 ? match.player2 : match.player1;
      updateMatchPlayer(newMatches, match.loserNextMatchId, loser);
    }

    const updatedTourney = { ...activeTournament, matches: newMatches };
    setActiveTournament(updatedTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(updatedTourney));
  };

  const generateSingleElim = (participants: string[]): { matches: TournamentMatch[], rounds: number } => {
     const shuffled = [...participants].sort(() => 0.5 - Math.random());
     let size = 2;
     while(size < shuffled.length) size *= 2;
     while(shuffled.length < size) shuffled.push("BYE");

     const matches: TournamentMatch[] = [];
     let matchIdCounter = 1;
     const getId = () => `m_${matchIdCounter++}`;

     // Round 1
     const round1Ids: string[] = [];
     const half = size / 2;

     for(let i=0; i<half; i++) {
        const id = getId();
        round1Ids.push(id);
        const p1 = shuffled[i*2];
        const p2 = shuffled[i*2+1];
        const isBye = p2 === "BYE";

        matches.push({
          id,
          roundIndex: 0,
          bracketType: 'winner',
          player1: p1,
          player2: isBye ? null : p2,
          winner: isBye ? p1 : null,
          status: isBye ? 'completed' : 'ready'
        });
     }

     // Subsequent Rounds
     let currentIds = round1Ids;
     let rIdx = 1;
     while(currentIds.length > 1) {
       const nextIds: string[] = [];
       for(let i=0; i<currentIds.length; i+=2) {
         const id = getId();
         nextIds.push(id);

         const m1 = matches.find(m => m.id === currentIds[i]);
         const m2 = matches.find(m => m.id === currentIds[i+1]);
         if(m1) m1.nextMatchId = id;
         if(m2) m2.nextMatchId = id;

         matches.push({
           id,
           roundIndex: rIdx,
           bracketType: 'winner',
           player1: m1?.winner || null,
           player2: m2?.winner || null,
           winner: null,
           status: (m1?.winner && m2?.winner) ? 'ready' : 'pending'
         });
       }
       currentIds = nextIds;
       rIdx++;
     }

     return { matches, rounds: rIdx };
  };

  const generateDoubleElim = (participants: string[]): { matches: TournamentMatch[], rounds: number } => {
    // Basic logic for small brackets (4, 8, 16)
    // We reuse single elim generation for Winners Bracket (WB)
    // Then we generate Losers Bracket (LB) and link them.

    const { matches: wbMatches, rounds: wbRounds } = generateSingleElim(participants);

    // Adjust WB Rounds to spread out visually if needed, but for logic, keep indices.
    // We need to inject loser links.

    const matches = [...wbMatches];
    let matchIdCounter = 1000; // Start high for LB
    const getId = () => `m_${matchIdCounter++}`;

    // Group WB matches by round
    const wbByRound: Record<number, TournamentMatch[]> = {};
    matches.forEach(m => {
      if(!wbByRound[m.roundIndex]) wbByRound[m.roundIndex] = [];
      wbByRound[m.roundIndex].push(m);
    });

    const numPlayers = Math.pow(2, wbRounds); // 4, 8, 16...

    // --- Losers Bracket Logic ---
    // Note: This is a simplified "standard" topology generator.

    const lbMatches: TournamentMatch[] = [];

    // LB Round 1: Takes losers from WB Round 1
    // Count = WB_R1_Count / 2 = N/4 matches.
    // Wait. In DE, WB R1 losers drop to LB R1. 
    // If 8 players -> 4 WB matches. 4 Losers -> 2 LB matches.
    const lbR1Matches: TournamentMatch[] = [];
    const wbR1 = wbByRound[0]; // 4 matches (if 8 players)

    for(let i=0; i < wbR1.length; i+=2) {
       const id = getId();
       lbR1Matches.push({
         id,
         roundIndex: 0,
         bracketType: 'loser',
         player1: null, // Will come from WB losers
         player2: null,
         winner: null,
         status: 'pending'
       });
       // Link WB Losers
       wbR1[i].loserNextMatchId = id;
       wbR1[i+1].loserNextMatchId = id;
    }
    lbMatches.push(...lbR1Matches);

    // If only 4 players:
    // WB R1 (2 matches) -> Losers to LB R1 (1 match).
    // WB R2 (Final) -> Loser to LB R2 (Final).

    let currentLbRound = lbR1Matches;

    // For N=8
    // WB1(4) -> LB1(2).
    // LB1 winners -> LB2(2). WB2(2) losers -> LB2(2).
    // LB2 winners -> LB3(1).
    // WB3(1) loser -> LB3(1). (Actually WB3 is WB Final).

    // Generic approach is hard, let's explicit map for N=4, 8, 16.

    if (numPlayers === 4) {
       // WB R1 has 2 matches.
       // LB R1 has 1 match (id_L1).
       // WB R2 (WB Final) has 1 match.
       // LB R2 (LB Final) has 1 match (Winner L1 vs Loser WB Final).

       const l1 = lbR1Matches[0];

       const l2: TournamentMatch = {
         id: getId(),
         roundIndex: 1,
         bracketType: 'loser',
         player1: null, // Winner of L1
         player2: null, // Loser of WB Final
         winner: null,
         status: 'pending'
       };
       lbMatches.push(l2);

       l1.nextMatchId = l2.id;
       wbByRound[1][0].loserNextMatchId = l2.id;

       // Grand Final
       const gf: TournamentMatch = {
         id: getId(),
         roundIndex: 2,
         bracketType: 'final',
         player1: null, // Winner WB Final
         player2: null, // Winner LB Final
         winner: null,
         status: 'pending'
       };
       matches.push(gf);
       wbByRound[1][0].nextMatchId = gf.id; // Winner of WB Final -> GF
       l2.nextMatchId = gf.id; // Winner of LB Final -> GF

    } else if (numPlayers >= 8) {
       // Implements logic for 8. (16 would need more rounds, keeping it simple for now as 8 is common).
       // If 16, this logic is incomplete but functional for start.
       // Let's implement robust N=8 logic.

       // L1 (2 matches) created above.

       // L2 (2 matches): Winners of L1 vs Losers of WB R2
       const l2Matches: TournamentMatch[] = [];
       const wbR2 = wbByRound[1]; // 2 matches

       for(let i=0; i<currentLbRound.length; i++) {
          const id = getId();
          l2Matches.push({
            id, roundIndex: 1, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending'
          });
          currentLbRound[i].nextMatchId = id; // L1 winner -> L2
          wbR2[i].loserNextMatchId = id;      // WB R2 loser -> L2
       }
       lbMatches.push(...l2Matches);

       // L3 (1 match): Winners of L2 play each other
       const l3Id = getId();
       const l3: TournamentMatch = { id: l3Id, roundIndex: 2, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l3);
       l2Matches[0].nextMatchId = l3Id;
       l2Matches[1].nextMatchId = l3Id;

       // L4 (1 match): Winner L3 vs Loser WB Final (WB R3)
       const l4Id = getId();
       const l4: TournamentMatch = { id: l4Id, roundIndex: 3, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l4);
       l3.nextMatchId = l4Id;
       wbByRound[2][0].loserNextMatchId = l4Id;

       // Grand Final
       const gf: TournamentMatch = {
          id: getId(),
          roundIndex: 4,
          bracketType: 'final',
          player1: null, // Winner WB Final
          player2: null, // Winner LB Final
          winner: null,
          status: 'pending'
       };
       matches.push(gf);
       wbByRound[2][0].nextMatchId = gf.id;
       l4.nextMatchId = gf.id;
    }

    matches.push(...lbMatches);

    // Sort matches by type/round for cleaner array
    return { matches, rounds: 5 }; // Approx rounds for display
  };

  const createTournament = () => {
    if (!newTourneyName || selectedPlayers.length < 2) {
      alert("Enter name and select at least 2 players.");
      return;
    }

    let result;
    if (tourneyType === 'double') {
      result = generateDoubleElim(selectedPlayers);
    } else {
      result = generateSingleElim(selectedPlayers);
    }

    const newTourney: Tournament = {
      id: newTourneyName.replace(/\s+/g, '') + '_' + Date.now(),
      name: newTourneyName,
      type: tourneyType,
      participants: selectedPlayers,
      matches: result.matches,
      rounds: result.rounds,
      status: 'active',
      dateCreated: new Date().toISOString()
    };

    setActiveTournament(newTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(newTourney));
  };

  const handlePlayerToggle = (p: string) => {
    if (selectedPlayers.includes(p)) setSelectedPlayers(selectedPlayers.filter(x => x !== p));
    else setSelectedPlayers([...selectedPlayers, p]);
  };

  const deleteTournament = () => {
    if(confirm("Are you sure you want to delete this tournament? All current bracket progress will be lost.")) {
       localStorage.removeItem('battleforge_active_tournament');
       setActiveTournament(null);
       setNewTourneyName('');
       setSelectedPlayers([]);
    }
  };

  const startMatch = (m: TournamentMatch) => {
     if (!activeTournament) return;
     if (m.status !== 'ready') return;

     navigate('/', { 
       state: {
         player1: m.player1,
         player2: m.player2,
         tournamentId: activeTournament.id,
         bracketMatchId: m.id
       }
     });
  };

  // Helper to render a bracket section
  const renderBracketSection = (title: string, matches: TournamentMatch[], rounds: number) => {
      // Find max round index in this set to allow scrolling
      const maxRound = Math.max(...matches.map(m => m.roundIndex), 0);

      return (
        <div className="mb-8">
           <h3 className="text-war-red font-orbitron font-bold uppercase mb-4 sticky left-0">{title}</h3>
           <div className="flex gap-8 min-w-max">
              {Array.from({ length: maxRound + 1 }).map((_, rIdx) => {
                 const roundMatches = matches.filter(m => m.roundIndex === rIdx);
                 if (roundMatches.length === 0) return null;

                 return (
                   <div key={rIdx} className="flex flex-col justify-around gap-8 w-64">
                      <div className="text-center text-zinc-500 font-orbitron text-xs font-bold uppercase mb-4 bg-black/40 p-1 rounded">
                        Round {rIdx + 1}
                      </div>
                      {roundMatches.map(m => {
                        const isReady = m.status === 'ready';
                        const isComplete = m.status === 'completed';
                        return (
                          <div 
                             key={m.id} 
                             onClick={() => isReady && startMatch(m)}
                             className={`
                               relative p-3 rounded border transition-all 
                               ${isComplete ? 'bg-green-900/20 border-green-800' : isReady ? 'bg-war-panel border-war-red cursor-pointer hover:bg-zinc-800 hover:scale-[1.02] shadow-[0_0_10px_rgba(255,45,45,0.2)]' : 'bg-zinc-900 border-zinc-800 opacity-60'}
                             `}
                          >
                             <div className={`text-sm font-bold ${m.winner === m.player1 && isComplete ? 'text-green-400' : 'text-zinc-300'}`}>
                               {m.player1 || 'Waiting...'}
                             </div>
                             <div className="h-px bg-zinc-700 my-2"></div>
                             <div className={`text-sm font-bold ${m.winner === m.player2 && isComplete ? 'text-green-400' : 'text-zinc-300'}`}>
                               {m.player2 || 'Waiting...'}
                             </div>
                          </div>
                        );
                      })}
                   </div>
                 );
              })}
           </div>
        </div>
      );
  };

  return (
    <div className="min-h-screen bg-war-dark pb-20 p-4">
      <header className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-orbitron font-bold text-war-red">
          TOURNAMENT<span className="text-white">HUB</span>
        </h1>
        <Button variant="secondary" onClick={() => navigate('/')} className="text-xs py-2 px-3">&larr; App</Button>
      </header>

      {!activeTournament ? (
        <div className="bg-war-panel border border-zinc-700 rounded-lg p-6 max-w-2xl mx-auto shadow-xl animate-fade-in">
           <h2 className="text-xl font-orbitron text-white mb-4">Create New Tournament</h2>

           <div className="space-y-4">
             <Input label="Tournament Name" value={newTourneyName} onChange={e => setNewTourneyName(e.target.value)} placeholder="e.g. Summer Slam 2024" />

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Format</label>
               <div className="flex gap-2">
                 <button onClick={() => setTourneyType('single')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'single' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Single Elimination</button>
                 <button onClick={() => setTourneyType('double')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'double' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Double Elimination</button>
               </div>
             </div>

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Participants ({selectedPlayers.length})</label>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-2 bg-zinc-900 p-3 rounded border border-zinc-800 max-h-40 overflow-y-auto">
                 {PLAYERS.map(p => (
                   <button 
                     key={p} 
                     onClick={() => handlePlayerToggle(p)}
                     className={`text-xs p-2 rounded text-left transition-colors ${selectedPlayers.includes(p) ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
