       // LB R1: Winner L0 vs Loser WB Final (WB R1)
       const l1: TournamentMatch = { id: getId(), roundIndex: 1, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l1);
       l0.nextMatchId = l1.id;
       wbByRound[1][0].loserNextMatchId = l1.id;

       // Grand Final
       const gf: TournamentMatch = { id: getId(), roundIndex: 0, bracketType: 'final', player1: null, player2: null, winner: null, status: 'pending' };
       matches.push(gf);
       wbByRound[1][0].nextMatchId = gf.id;
       l1.nextMatchId = gf.id;

    } else if (numPlayers >= 8) {
       // N=8 Standard Double Elimination
       // WB R0 (4 matches) -> Losers to LB R0 (2 matches)
       // LB R0 (2 matches) -> Winners to LB R1 (2 matches). Losers of WB R1 (2 matches) drop here.
       // LB R1 (2 matches) -> Winners to LB R2 (1 match).
       // LB R2 (1 match) -> Winner to LB R3 (1 match). Loser of WB R2 (Final) drops here.
       // LB R3 (1 match) -> Winner to GF.

       // LB R0
       const lbR0: TournamentMatch[] = [];
       const wbR0 = wbByRound[0];
       for(let i=0; i<2; i++) {
         const m: TournamentMatch = { id: getId(), roundIndex: 0, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
         lbR0.push(m);
         // Map WB losers (0,1 -> 0; 2,3 -> 1)
         wbR0[i*2].loserNextMatchId = m.id;
         wbR0[i*2+1].loserNextMatchId = m.id;
       }
       lbMatches.push(...lbR0);

       // LB R1 (Fed by LB R0 winners + WB R1 losers)
       const lbR1: TournamentMatch[] = [];
       const wbR1 = wbByRound[1]; // 2 matches
       for(let i=0; i<2; i++) {
          const m: TournamentMatch = { id: getId(), roundIndex: 1, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
          lbR1.push(m);
          lbR0[i].nextMatchId = m.id;
          wbR1[i].loserNextMatchId = m.id;
       }
       lbMatches.push(...lbR1);

       // LB R2 (Fed by LB R1 winners)
       // Usually these play each other
       const l2: TournamentMatch = { id: getId(), roundIndex: 2, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l2);
       lbR1[0].nextMatchId = l2.id;
       lbR1[1].nextMatchId = l2.id;

       // LB R3 (Fed by L2 winner + WB Final loser)
       const l3: TournamentMatch = { id: getId(), roundIndex: 3, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l3);
       l2.nextMatchId = l3.id;
       wbByRound[2][0].loserNextMatchId = l3.id;

       // Grand Final
       const gf: TournamentMatch = { id: getId(), roundIndex: 0, bracketType: 'final', player1: null, player2: null, winner: null, status: 'pending' };
       matches.push(gf);
       wbByRound[2][0].nextMatchId = gf.id;
       l3.nextMatchId = gf.id;
    }
    // Note: N=16 logic would follow similar patterns but expanded. For now N=8 is max supported structure.

    matches.push(...lbMatches);
    return { matches, rounds: 5 };
  };

  const createTournament = () => {
    if (!newTourneyName || selectedPlayers.length < 2) {
      alert("Enter name and select at least 2 players.");
      return;
    }

    let result;
    if (tourneyType === 'double') {
      result = generateDoubleElim(selectedPlayers);
    } else {
      result = generateSingleElim(selectedPlayers);
    }

    // Run initial settlement to resolve any initial BYEs
    settleBracket(result.matches);

    const newTourney: Tournament = {
      id: newTourneyName.replace(/\s+/g, '') + '_' + Date.now(),
      name: newTourneyName,
      type: tourneyType,
      participants: selectedPlayers,
      matches: result.matches,
      rounds: result.rounds,
      status: 'active',
      dateCreated: new Date().toISOString()
    };

    setActiveTournament(newTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(newTourney));
  };

  const handlePlayerToggle = (p: string) => {
    if (selectedPlayers.includes(p)) setSelectedPlayers(selectedPlayers.filter(x => x !== p));
    else setSelectedPlayers([...selectedPlayers, p]);
  };

  const deleteTournament = () => {
    if(window.confirm("Are you sure you want to delete this tournament? All current bracket progress will be lost.")) {
       localStorage.removeItem('battleforge_active_tournament');
       setActiveTournament(null);
       setNewTourneyName('');
       setSelectedPlayers([]);
       // Force reload to ensure clean state
       navigate(0);
    }
  };

  const startMatch = (m: TournamentMatch) => {
     if (!activeTournament) return;
     if (m.status !== 'ready') return;

     navigate('/', { 
       state: {
         player1: m.player1,
         player2: m.player2,
         tournamentId: activeTournament.id,
         bracketMatchId: m.id
       }
     });
  };

  // Helper to render a bracket section
  const renderBracketSection = (title: string, matches: TournamentMatch[]) => {
      if (matches.length === 0) return null;
      // Find max round index in this set to allow scrolling
      const maxRound = Math.max(...matches.map(m => m.roundIndex), 0);

      return (
        <div className="mb-8">
           <h3 className="text-war-red font-orbitron font-bold uppercase mb-4 sticky left-0">{title}</h3>
           <div className="flex gap-8 min-w-max">
              {Array.from({ length: maxRound + 1 }).map((_, rIdx) => {
                 const roundMatches = matches.filter(m => m.roundIndex === rIdx);
                 if (roundMatches.length === 0) return null;

                 return (
                   <div key={rIdx} className="flex flex-col justify-around gap-8 w-64">
                      <div className="text-center text-zinc-500 font-orbitron text-xs font-bold uppercase mb-4 bg-black/40 p-1 rounded">
                        Round {rIdx + 1}
                      </div>
                      {roundMatches.map(m => {
                        const isReady = m.status === 'ready';
                        const isComplete = m.status === 'completed';
                        // Determine winner highlight
                        const p1Won = isComplete && m.winner === m.player1;
                        const p2Won = isComplete && m.winner === m.player2;

                        return (
                          <div 
                             key={m.id} 
                             onClick={() => isReady && startMatch(m)}
                             className={`
                               relative p-3 rounded border transition-all 
                               ${isComplete ? 'bg-green-900/10 border-green-900/30' : isReady ? 'bg-war-panel border-war-red cursor-pointer hover:bg-zinc-800 hover:scale-[1.02] shadow-[0_0_10px_rgba(255,45,45,0.2)]' : 'bg-zinc-900 border-zinc-800 opacity-60'}
                             `}
                          >
                             <div className={`text-sm font-bold flex justify-between ${p1Won ? 'text-green-400' : p2Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player1 || 'Waiting...'}</span>
                               {p1Won && <span>✓</span>}
                             </div>
                             <div className="h-px bg-zinc-700 my-2"></div>
                             <div className={`text-sm font-bold flex justify-between ${p2Won ? 'text-green-400' : p1Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player2 || 'Waiting...'}</span>
                               {p2Won && <span>✓</span>}
                             </div>
                          </div>
                        );
                      })}
                   </div>
                 );
              })}
           </div>
        </div>
      );
  };

  return (
    <div className="min-h-screen bg-war-dark pb-20 p-4">
      <header className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-orbitron font-bold text-war-red">
          TOURNAMENT<span className="text-white">HUB</span>
        </h1>
        <Button variant="secondary" onClick={() => navigate('/')} className="text-xs py-2 px-3">&larr; App</Button>
      </header>

      {!activeTournament ? (
        <div className="bg-war-panel border border-zinc-700 rounded-lg p-6 max-w-2xl mx-auto shadow-xl animate-fade-in">
           <h2 className="text-xl font-orbitron text-white mb-4">Create New Tournament</h2>

           <div className="space-y-4">
             <Input label="Tournament Name" value={newTourneyName} onChange={e => setNewTourneyName(e.target.value)} placeholder="e.g. Summer Slam 2024" />

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Format</label>
               <div className="flex gap-2">
                 <button onClick={() => setTourneyType('single')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'single' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Single Elimination</button>
                 <button onClick={() => setTourneyType('double')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'double' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Double Elimination</button>
               </div>
             </div>

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Participants ({selectedPlayers.length})</label>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-2 bg-zinc-900 p-3 rounded border border-zinc-800 max-h-40 overflow-y-auto">
                 {PLAYERS.map(p => (
                   <button 
                     key={p} 
                     onClick={() => handlePlayerToggle(p)}
                     className={`text-xs p-2 rounded text-left transition-colors ${selectedPlayers.includes(p) ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
                   >
                     {p}
                   </button>
                 ))}
               </div>
             </div>

             <Button onClick={createTournament} className="w-full mt-4">Generate Bracket</Button>
           </div>
        </div>
      ) : (
        <div className="animate-fade-in overflow-x-auto">
           <div className="flex justify-between items-center mb-4 min-w-[600px] sticky left-0">
             <div>
               <h2 className="text-2xl font-bold font-orbitron text-white">{activeTournament.name}</h2>
               <div className="text-xs text-zinc-500">Status: {activeTournament.status} | Type: {activeTournament.type}</div>
             </div>
             <Button variant="danger" onClick={deleteTournament} className="text-xs py-1 px-3 bg-red-800 hover:bg-red-700 text-white border-red-900">Delete Tournament</Button>
           </div>

           {/* Render Brackets Split by Type */}
           {activeTournament.type === 'single' ? (
              renderBracketSection("Bracket", activeTournament.matches)
           ) : (
              <div>
                {renderBracketSection("Winners Bracket", activeTournament.matches.filter(m => m.bracketType === 'winner'))}
                {renderBracketSection("Losers Bracket", activeTournament.matches.filter(m => m.bracketType === 'loser'))}
                {renderBracketSection("Finals", activeTournament.matches.filter(m => m.bracketType === 'final'))}
              </div>
           )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { PLAYERS } from '../constants';
import { Tournament, TournamentMatch } from '../types';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';

export const TournamentHub: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [activeTournament, setActiveTournament] = useState<Tournament | null>(null);
  const [newTourneyName, setNewTourneyName] = useState('');
  const [selectedPlayers, setSelectedPlayers] = useState<string[]>([]);
  const [tourneyType, setTourneyType] = useState<'single' | 'double'>('single');

  // Load active tournament
  useEffect(() => {
    const saved = localStorage.getItem('battleforge_active_tournament');
    if (saved) {
      setActiveTournament(JSON.parse(saved));
    }
  }, []);

  // Handle return from MatchLogger with results
  useEffect(() => {
    if (location.state && location.state.completedMatchId && location.state.winner) {
      const { completedMatchId, winner } = location.state;

      // IMPORTANT: Clear the state immediately to prevent infinite loops on re-render
      // We use navigate with replace to scrub the state from history
      navigate(location.pathname, { replace: true, state: {} });

      if (activeTournament) {
        handleMatchCompletion(completedMatchId, winner);
      }
    }
  }, [location.state, activeTournament, navigate, location.pathname]);

  // --- Core Logic: Advance Players & Resolve Byes ---

  const advancePlayerToMatch = (matches: TournamentMatch[], targetId: string, player: string): boolean => {
    const target = matches.find(m => m.id === targetId);
    if (!target) return false;

    // Idempotency check: Don't add if already there
    // We treat players as unique strings.
    if (target.player1 === player || target.player2 === player) return false;

    let changed = false;

    // Fill empty slot
    if (!target.player1) {
       target.player1 = player;
       changed = true;
    } else if (!target.player2) {
       target.player2 = player;
       changed = true;
    } else {
       // Both slots full, cannot advance (this implies bracket convergence error or full match)
       return false; 
    }

    // Auto-complete check (BYEs)
    // If a match becomes [Player vs BYE] or [BYE vs Player], auto-resolve it immediately
    if (changed && target.player1 && target.player2 && target.status !== 'completed') {
       if (target.player1 === "BYE" || target.player2 === "BYE") {
          target.status = 'completed';
          target.winner = target.player1 === "BYE" ? target.player2 : target.player1;
          // Note: We return true (changed) so the outer loop will pick up this new completion
       } else {
          target.status = 'ready';
       }
    }
    return changed;
  };

  const settleBracket = (matches: TournamentMatch[]) => {
    let changed = true;
    // Limit iterations to prevent infinite loops in case of bad topology
    let iterations = 0;
    while(changed && iterations < 50) {
      changed = false;
      iterations++;

      matches.forEach(m => {
         if (m.status === 'completed' && m.winner) {
             // 1. Advance Winner
             if (m.nextMatchId) {
                if (advancePlayerToMatch(matches, m.nextMatchId, m.winner)) changed = true;
             }
             // 2. Advance Loser (for Double Elim)
             // Note: A BYE match has no loser entity, so we propagate "BYE" as the loser if needed, 
             // but typically BYE matches shouldn't drop to loser bracket in a way that blocks.
             // If winner is P1, loser is P2.
             if (m.loserNextMatchId && m.player1 && m.player2) {
                const loser = m.winner === m.player1 ? m.player2 : m.player1;
                if (loser && advancePlayerToMatch(matches, m.loserNextMatchId, loser)) changed = true;
             }
         }
      });
    }
  };

  const handleMatchCompletion = (matchId: string, winner: string | null) => {
    if (!activeTournament || !winner) return;

    // Deep copy to ensure immutability during processing
    const newMatches = JSON.parse(JSON.stringify(activeTournament.matches)); 
    const match = newMatches.find((m: TournamentMatch) => m.id === matchId);

    // If match already completed with same winner, ignore to prevent reprocessing
    if (match && match.status === 'completed' && match.winner === winner) return;

    if (match) {
        match.winner = winner;
        match.status = 'completed';

        // Recursively resolve the bracket (autofill Byes, etc)
        settleBracket(newMatches);

        const updatedTourney = { ...activeTournament, matches: newMatches };
        setActiveTournament(updatedTourney);
        localStorage.setItem('battleforge_active_tournament', JSON.stringify(updatedTourney));
    }
  };

  // --- Generators ---

  const generateSingleElim = (participants: string[]): { matches: TournamentMatch[], rounds: number } => {
     const shuffled = [...participants].sort(() => 0.5 - Math.random());
     let size = 2;
     while(size < shuffled.length) size *= 2;
     // Fill with BYEs
     while(shuffled.length < size) shuffled.push("BYE");

     const matches: TournamentMatch[] = [];
     let matchIdCounter = 1;
     const getId = () => `m_${matchIdCounter++}`;

     // Round 1
     const round1Ids: string[] = [];
     const half = size / 2;

     for(let i=0; i<half; i++) {
        const id = getId();
        round1Ids.push(id);
        const p1 = shuffled[i*2];
        const p2 = shuffled[i*2+1];

        matches.push({
          id,
          roundIndex: 0,
          bracketType: 'winner',
          player1: p1,
          player2: p2,
          winner: null,
          status: 'pending' // settleBracket will handle BYE completion
        });
     }

     // Subsequent Rounds
     let currentIds = round1Ids;
     let rIdx = 1;
     while(currentIds.length > 1) {
       const nextIds: string[] = [];
       for(let i=0; i<currentIds.length; i+=2) {
         const id = getId();
         nextIds.push(id);

         const m1 = matches.find(m => m.id === currentIds[i]);
         const m2 = matches.find(m => m.id === currentIds[i+1]);
         if(m1) m1.nextMatchId = id;
         if(m2) m2.nextMatchId = id;

         matches.push({
           id,
           roundIndex: rIdx,
           bracketType: 'winner',
           player1: null,
           player2: null,
           winner: null,
           status: 'pending'
         });
       }
       currentIds = nextIds;
       rIdx++;
     }

     return { matches, rounds: rIdx };
  };

  const generateDoubleElim = (participants: string[]): { matches: TournamentMatch[], rounds: number } => {
    // 1. Generate standard Winner Bracket
    const { matches: wbMatches, rounds: wbRounds } = generateSingleElim(participants);
    const matches = [...wbMatches];

    // Group WB matches by round for linking
    const wbByRound: Record<number, TournamentMatch[]> = {};
    matches.forEach(m => {
      if(!wbByRound[m.roundIndex]) wbByRound[m.roundIndex] = [];
      wbByRound[m.roundIndex].push(m);
    });

    // ID Generator for Losers Bracket
    let matchIdCounter = 2000;
    const getId = () => `m_${matchIdCounter++}`;

    const numPlayers = Math.pow(2, wbRounds); // 4, 8, 16...
    const lbMatches: TournamentMatch[] = [];

    // --- Losers Bracket Topology ---

    // N=4 (Smallest DE)
    if (numPlayers === 4) {
       // LB R0: Losers of WB R0
       const l0: TournamentMatch = { id: getId(), roundIndex: 0, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l0);
       wbByRound[0][0].loserNextMatchId = l0.id;
       wbByRound[0][1].loserNextMatchId = l0.id;

       // LB R1: Winner L0 vs Loser WB Final (WB R1)
       const l1: TournamentMatch = { id: getId(), roundIndex: 1, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l1);
       l0.nextMatchId = l1.id;
       wbByRound[1][0].loserNextMatchId = l1.id;

       // Grand Final
       const gf: TournamentMatch = { id: getId(), roundIndex: 0, bracketType: 'final', player1: null, player2: null, winner: null, status: 'pending' };
       matches.push(gf);
       wbByRound[1][0].nextMatchId = gf.id;
       l1.nextMatchId = gf.id;

    } else if (numPlayers >= 8) {
       // N=8 Standard Double Elimination

       // LB R0 (2 matches)
       const lbR0: TournamentMatch[] = [];
       const wbR0 = wbByRound[0];
       for(let i=0; i<2; i++) {
         const m: TournamentMatch = { id: getId(), roundIndex: 0, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
         lbR0.push(m);
         // Map WB losers (0,1 -> 0; 2,3 -> 1)
         wbR0[i*2].loserNextMatchId = m.id;
         wbR0[i*2+1].loserNextMatchId = m.id;
       }
       lbMatches.push(...lbR0);

       // LB R1 (Fed by LB R0 winners + WB R1 losers)
       const lbR1: TournamentMatch[] = [];
       const wbR1 = wbByRound[1]; // 2 matches
       for(let i=0; i<2; i++) {
          const m: TournamentMatch = { id: getId(), roundIndex: 1, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
          lbR1.push(m);
          lbR0[i].nextMatchId = m.id;
          wbR1[i].loserNextMatchId = m.id;
       }
       lbMatches.push(...lbR1);

       // LB R2 (Fed by LB R1 winners)
       // Usually these play each other
       const l2: TournamentMatch = { id: getId(), roundIndex: 2, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l2);
       lbR1[0].nextMatchId = l2.id;
       lbR1[1].nextMatchId = l2.id;

       // LB R3 (Fed by L2 winner + WB Final loser)
       const l3: TournamentMatch = { id: getId(), roundIndex: 3, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l3);
       l2.nextMatchId = l3.id;
       wbByRound[2][0].loserNextMatchId = l3.id;

       // Grand Final
       const gf: TournamentMatch = { id: getId(), roundIndex: 0, bracketType: 'final', player1: null, player2: null, winner: null, status: 'pending' };
       matches.push(gf);
       wbByRound[2][0].nextMatchId = gf.id;
       l3.nextMatchId = gf.id;
    }
    // Note: N=16 logic would follow similar patterns but expanded. For now N=8 is max supported structure.

    matches.push(...lbMatches);
    return { matches, rounds: 5 };
  };

  const createTournament = () => {
    if (!newTourneyName || selectedPlayers.length < 2) {
      alert("Enter name and select at least 2 players.");
      return;
    }

    let result;
    if (tourneyType === 'double') {
      result = generateDoubleElim(selectedPlayers);
    } else {
      result = generateSingleElim(selectedPlayers);
    }

    // Run initial settlement to resolve any initial BYEs
    settleBracket(result.matches);

    const newTourney: Tournament = {
      id: newTourneyName.replace(/\s+/g, '') + '_' + Date.now(),
      name: newTourneyName,
      type: tourneyType,
      participants: selectedPlayers,
      matches: result.matches,
      rounds: result.rounds,
      status: 'active',
      dateCreated: new Date().toISOString()
    };

    setActiveTournament(newTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(newTourney));
  };

  const handlePlayerToggle = (p: string) => {
    if (selectedPlayers.includes(p)) setSelectedPlayers(selectedPlayers.filter(x => x !== p));
    else setSelectedPlayers([...selectedPlayers, p]);
  };

  const deleteTournament = () => {
    if(window.confirm("Are you sure you want to delete this tournament? All current bracket progress will be lost.")) {
       localStorage.removeItem('battleforge_active_tournament');
       setActiveTournament(null);
       setNewTourneyName('');
       setSelectedPlayers([]);
       // Force a hard reload to ensure all state is completely reset
       window.location.reload();
    }
  };

  const startMatch = (m: TournamentMatch) => {
     if (!activeTournament) return;
     if (m.status !== 'ready') return;

     navigate('/', { 
       state: {
         player1: m.player1,
         player2: m.player2,
         tournamentId: activeTournament.id,
         bracketMatchId: m.id
       }
     });
  };

  // Helper to render a bracket section
  const renderBracketSection = (title: string, matches: TournamentMatch[]) => {
      if (matches.length === 0) return null;
      // Find max round index in this set to allow scrolling
      const maxRound = Math.max(...matches.map(m => m.roundIndex), 0);

      return (
        <div className="mb-8">
           <h3 className="text-war-red font-orbitron font-bold uppercase mb-4 sticky left-0">{title}</h3>
           <div className="flex gap-8 min-w-max">
              {Array.from({ length: maxRound + 1 }).map((_, rIdx) => {
                 const roundMatches = matches.filter(m => m.roundIndex === rIdx);
                 if (roundMatches.length === 0) return null;

                 return (
                   <div key={rIdx} className="flex flex-col justify-around gap-8 w-64">
                      <div className="text-center text-zinc-500 font-orbitron text-xs font-bold uppercase mb-4 bg-black/40 p-1 rounded">
                        Round {rIdx + 1}
                      </div>
                      {roundMatches.map(m => {
                        const isReady = m.status === 'ready';
                        const isComplete = m.status === 'completed';
                        // Determine winner highlight
                        const p1Won = isComplete && m.winner === m.player1;
                        const p2Won = isComplete && m.winner === m.player2;

                        return (
                          <div 
                             key={m.id} 
                             onClick={() => isReady && startMatch(m)}
                             className={`
                               relative p-3 rounded border transition-all 
                               ${isComplete ? 'bg-green-900/10 border-green-900/30' : isReady ? 'bg-war-panel border-war-red cursor-pointer hover:bg-zinc-800 hover:scale-[1.02] shadow-[0_0_10px_rgba(255,45,45,0.2)]' : 'bg-zinc-900 border-zinc-800 opacity-60'}
                             `}
                          >
                             <div className={`text-sm font-bold flex justify-between ${p1Won ? 'text-green-400' : p2Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player1 || 'Waiting...'}</span>
                               {p1Won && <span>✓</span>}
                             </div>
                             <div className="h-px bg-zinc-700 my-2"></div>
                             <div className={`text-sm font-bold flex justify-between ${p2Won ? 'text-green-400' : p1Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player2 || 'Waiting...'}</span>
                               {p2Won && <span>✓</span>}
                             </div>
                          </div>
                        );
                      })}
                   </div>
                 );
              })}
