    if (numPlayers === 4) {
       // LB R0: Losers of WB R0
       const l0: TournamentMatch = { id: getId(), roundIndex: 0, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l0);
       wbByRound[0][0].loserNextMatchId = l0.id;
       wbByRound[0][1].loserNextMatchId = l0.id;

       // LB R1: Winner L0 vs Loser WB Final (WB R1)
       const l1: TournamentMatch = { id: getId(), roundIndex: 1, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l1);
       l0.nextMatchId = l1.id;
       wbByRound[1][0].loserNextMatchId = l1.id;

       // Grand Final
       const gf: TournamentMatch = { id: getId(), roundIndex: 0, bracketType: 'final', player1: null, player2: null, winner: null, status: 'pending' };
       matches.push(gf);
       wbByRound[1][0].nextMatchId = gf.id;
       l1.nextMatchId = gf.id;

    } else if (numPlayers >= 8) {
       // N=8 Standard Double Elimination

       // LB R0 (2 matches)
       const lbR0: TournamentMatch[] = [];
       const wbR0 = wbByRound[0];
       for(let i=0; i<2; i++) {
         const m: TournamentMatch = { id: getId(), roundIndex: 0, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
         lbR0.push(m);
         // Map WB losers (0,1 -> 0; 2,3 -> 1)
         wbR0[i*2].loserNextMatchId = m.id;
         wbR0[i*2+1].loserNextMatchId = m.id;
       }
       lbMatches.push(...lbR0);

       // LB R1 (Fed by LB R0 winners + WB R1 losers)
       const lbR1: TournamentMatch[] = [];
       const wbR1 = wbByRound[1]; // 2 matches
       for(let i=0; i<2; i++) {
          const m: TournamentMatch = { id: getId(), roundIndex: 1, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
          lbR1.push(m);
          lbR0[i].nextMatchId = m.id;
          wbR1[i].loserNextMatchId = m.id;
       }
       lbMatches.push(...lbR1);

       // LB R2 (Fed by LB R1 winners)
       // Usually these play each other
       const l2: TournamentMatch = { id: getId(), roundIndex: 2, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l2);
       lbR1[0].nextMatchId = l2.id;
       lbR1[1].nextMatchId = l2.id;

       // LB R3 (Fed by L2 winner + WB Final loser)
       const l3: TournamentMatch = { id: getId(), roundIndex: 3, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l3);
       l2.nextMatchId = l3.id;
       wbByRound[2][0].loserNextMatchId = l3.id;

       // Grand Final
       const gf: TournamentMatch = { id: getId(), roundIndex: 0, bracketType: 'final', player1: null, player2: null, winner: null, status: 'pending' };
       matches.push(gf);
       wbByRound[2][0].nextMatchId = gf.id;
       l3.nextMatchId = gf.id;
    }
    // Note: N=16 logic would follow similar patterns but expanded. For now N=8 is max supported structure.

    matches.push(...lbMatches);
    return { matches, rounds: 5 };
  };

  const createTournament = () => {
    if (!newTourneyName || selectedPlayers.length < 2) {
      alert("Enter name and select at least 2 players.");
      return;
    }

    let result;
    if (tourneyType === 'double') {
      result = generateDoubleElim(selectedPlayers);
    } else {
      result = generateSingleElim(selectedPlayers);
    }

    // Run initial settlement to resolve any initial BYEs and set R1 to ready
    settleBracket(result.matches);

    const newTourney: Tournament = {
      id: newTourneyName.replace(/\s+/g, '') + '_' + Date.now(),
      name: newTourneyName,
      type: tourneyType,
      participants: selectedPlayers,
      matches: result.matches,
      rounds: result.rounds,
      status: 'active',
      dateCreated: new Date().toISOString()
    };

    setActiveTournament(newTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(newTourney));
  };

  const handlePlayerToggle = (p: string) => {
    if (selectedPlayers.includes(p)) setSelectedPlayers(selectedPlayers.filter(x => x !== p));
    else setSelectedPlayers([...selectedPlayers, p]);
  };

  const deleteTournament = () => {
    if(window.confirm("Are you sure you want to delete this tournament? All current bracket progress will be lost.")) {
       localStorage.removeItem('battleforge_active_tournament');
       setActiveTournament(null);
       setNewTourneyName('');
       setSelectedPlayers([]);
       // Explicitly clear history state to prevent any weird re-mounts
       navigate('/tournament', { replace: true, state: {} });
    }
  };

  const startMatch = (m: TournamentMatch) => {
     if (!activeTournament) return;
     if (m.status !== 'ready') return;

     navigate('/', { 
       state: {
         player1: m.player1,
         player2: m.player2,
         tournamentId: activeTournament.id,
         bracketMatchId: m.id
       }
     });
  };

  // Helper to render a bracket section
  const renderBracketSection = (title: string, matches: TournamentMatch[]) => {
      if (matches.length === 0) return null;
      // Find max round index in this set to allow scrolling
      const maxRound = Math.max(...matches.map(m => m.roundIndex), 0);

      return (
        <div className="mb-8">
           <h3 className="text-war-red font-orbitron font-bold uppercase mb-4 sticky left-0">{title}</h3>
           <div className="flex gap-8 min-w-max">
              {Array.from({ length: maxRound + 1 }).map((_, rIdx) => {
                 const roundMatches = matches.filter(m => m.roundIndex === rIdx);
                 if (roundMatches.length === 0) return null;

                 return (
                   <div key={rIdx} className="flex flex-col justify-around gap-8 w-64">
                      <div className="text-center text-zinc-500 font-orbitron text-xs font-bold uppercase mb-4 bg-black/40 p-1 rounded">
                        Round {rIdx + 1}
                      </div>
                      {roundMatches.map(m => {
                        const isReady = m.status === 'ready';
                        const isComplete = m.status === 'completed';
                        // Determine winner highlight
                        const p1Won = isComplete && m.winner === m.player1;
                        const p2Won = isComplete && m.winner === m.player2;

                        return (
                          <div 
                             key={m.id} 
                             onClick={() => isReady && startMatch(m)}
                             className={`
                               relative p-3 rounded border transition-all 
                               ${isComplete ? 'bg-green-900/10 border-green-900/30' : isReady ? 'bg-war-panel border-war-red cursor-pointer hover:bg-zinc-800 hover:scale-[1.02] shadow-[0_0_10px_rgba(255,45,45,0.2)]' : 'bg-zinc-900 border-zinc-800 opacity-60'}
                             `}
                          >
                             <div className={`text-sm font-bold flex justify-between ${p1Won ? 'text-green-400' : p2Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player1 || 'Waiting...'}</span>
                               {p1Won && <span>✓</span>}
                             </div>
                             <div className="h-px bg-zinc-700 my-2"></div>
                             <div className={`text-sm font-bold flex justify-between ${p2Won ? 'text-green-400' : p1Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player2 || 'Waiting...'}</span>
                               {p2Won && <span>✓</span>}
                             </div>
                          </div>
                        );
                      })}
                   </div>
                 );
              })}
           </div>
        </div>
      );
  };

  return (
    <div className="min-h-screen bg-war-dark pb-20 p-4">
      <header className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-orbitron font-bold text-war-red">
          TOURNAMENT<span className="text-white">HUB</span>
        </h1>
        <Button variant="secondary" onClick={() => navigate('/')} className="text-xs py-2 px-3">&larr; App</Button>
      </header>

      {!activeTournament ? (
        <div className="bg-war-panel border border-zinc-700 rounded-lg p-6 max-w-2xl mx-auto shadow-xl animate-fade-in">
           <h2 className="text-xl font-orbitron text-white mb-4">Create New Tournament</h2>

           <div className="space-y-4">
             <Input label="Tournament Name" value={newTourneyName} onChange={e => setNewTourneyName(e.target.value)} placeholder="e.g. Summer Slam 2024" />

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Format</label>
               <div className="flex gap-2">
                 <button onClick={() => setTourneyType('single')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'single' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Single Elimination</button>
                 <button onClick={() => setTourneyType('double')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'double' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Double Elimination</button>
               </div>
             </div>

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Participants ({selectedPlayers.length})</label>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-2 bg-zinc-900 p-3 rounded border border-zinc-800 max-h-40 overflow-y-auto">
                 {PLAYERS.map(p => (
                   <button 
                     key={p} 
                     onClick={() => handlePlayerToggle(p)}
                     className={`text-xs p-2 rounded text-left transition-colors ${selectedPlayers.includes(p) ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
                   >
                     {p}
                   </button>
                 ))}
               </div>
             </div>

             <Button onClick={createTournament} className="w-full mt-4">Generate Bracket</Button>
           </div>
        </div>
      ) : (
        <div className="animate-fade-in overflow-x-auto">
           {/* Sticky header updated with z-index and background to ensure clickable buttons */}
           <div className="flex justify-between items-center mb-4 min-w-[600px] sticky left-0 z-10 bg-war-dark p-2 border-b border-zinc-800">
             <div>
               <h2 className="text-2xl font-bold font-orbitron text-white">{activeTournament.name}</h2>
               <div className="text-xs text-zinc-500">Status: {activeTournament.status} | Type: {activeTournament.type}</div>
             </div>
             <Button variant="danger" onClick={deleteTournament} className="text-xs py-1 px-3 bg-red-800 hover:bg-red-700 text-white border-red-900 shadow-lg">Delete Tournament</Button>
           </div>

           {/* Render Brackets Split by Type */}
           {activeTournament.type === 'single' ? (
              renderBracketSection("Bracket", activeTournament.matches)
           ) : (
              <div>
                {renderBracketSection("Winners Bracket", activeTournament.matches.filter(m => m.bracketType === 'winner'))}
                {renderBracketSection("Losers Bracket", activeTournament.matches.filter(m => m.bracketType === 'loser'))}
                {renderBracketSection("Finals", activeTournament.matches.filter(m => m.bracketType === 'final'))}
              </div>
           )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { PLAYERS } from '../constants';
import { Tournament, TournamentMatch } from '../types';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';

export const TournamentHub: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [activeTournament, setActiveTournament] = useState<Tournament | null>(null);
  const [newTourneyName, setNewTourneyName] = useState('');
  const [selectedPlayers, setSelectedPlayers] = useState<string[]>([]);
  const [tourneyType, setTourneyType] = useState<'single' | 'double'>('single');
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  // Load active tournament
  useEffect(() => {
    const saved = localStorage.getItem('battleforge_active_tournament');
    if (saved) {
      setActiveTournament(JSON.parse(saved));
    }
  }, []);

  // Handle return from MatchLogger with results
  useEffect(() => {
    if (location.state && location.state.completedMatchId && location.state.winner) {
      const { completedMatchId, winner } = location.state;

      // IMPORTANT: Clear the state immediately to prevent infinite loops on re-render
      // We use navigate with replace to scrub the state from history
      navigate(location.pathname, { replace: true, state: {} });

      if (activeTournament) {
        handleMatchCompletion(completedMatchId, winner);
      }
    }
  }, [location.state, activeTournament, navigate, location.pathname]);

  // --- Core Logic: Advance Players & Resolve Byes ---

  const advancePlayerToMatch = (matches: TournamentMatch[], targetId: string, player: string): boolean => {
    const target = matches.find(m => m.id === targetId);
    if (!target) return false;

    // Idempotency check: Don't add if already there
    // This prevents "Sven" from appearing twice in the same match
    if (target.player1 === player || target.player2 === player) return false;

    let changed = false;

    // Fill empty slot
    if (!target.player1) {
       target.player1 = player;
       changed = true;
    } else if (!target.player2) {
       target.player2 = player;
       changed = true;
    } else {
       // Both slots full, cannot advance.
       return false; 
    }

    // Update status based on fullness
    // Only set to READY if BOTH players are present
    if (changed) {
        if (target.player1 && target.player2) {
            target.status = 'ready';
        } else {
            target.status = 'pending';
        }
    }

    return changed;
  };

  const settleBracket = (matches: TournamentMatch[]) => {
    let changed = true;
    // Limit iterations to prevent infinite loops in case of bad topology
    let iterations = 0;
    while(changed && iterations < 50) {
      changed = false;
      iterations++;

      matches.forEach(m => {
         // RULE 1: Auto-resolve pending/ready matches logic
         if (m.status !== 'completed') {
             const p1 = m.player1;
             const p2 = m.player2;

             if (p1 && p2) {
                 // 1a. Handle BYE
                 if (p1 === 'BYE' || p2 === 'BYE') {
                     m.winner = p1 === 'BYE' ? p2 : p1;
                     m.status = 'completed';
                     changed = true; 
                 } 
                 // 1b. Handle Initial Pending -> Ready (for R1 matches generated as pending)
                 else if (m.status === 'pending') {
                     m.status = 'ready';
                     changed = true;
                 }
             }
         }

         // RULE 2: Propagate Completed Matches
         if (m.status === 'completed' && m.winner) {
             // Advance Winner
             if (m.nextMatchId) {
                if (advancePlayerToMatch(matches, m.nextMatchId, m.winner)) changed = true;
             }
             // Advance Loser (Double Elim)
             if (m.loserNextMatchId && m.player1 && m.player2) {
                const loser = m.winner === m.player1 ? m.player2 : m.player1;
                // Important: Even if loser is "BYE", we propagate it so the next match (Rule 1a) can auto-resolve it
                if (loser && advancePlayerToMatch(matches, m.loserNextMatchId, loser)) changed = true;
             }
         }
      });
    }
  };

  const handleMatchCompletion = (matchId: string, winner: string | null) => {
    if (!activeTournament || !winner) return;

    // Deep copy to ensure immutability during processing
    const newMatches = JSON.parse(JSON.stringify(activeTournament.matches)); 
    const match = newMatches.find((m: TournamentMatch) => m.id === matchId);

    // If match already completed with same winner, ignore to prevent reprocessing
    if (match && match.status === 'completed' && match.winner === winner) return;

    if (match) {
        match.winner = winner;
        match.status = 'completed';

        // Recursively resolve the bracket (autofill Byes, etc)
        settleBracket(newMatches);

        const updatedTourney = { ...activeTournament, matches: newMatches };
        setActiveTournament(updatedTourney);
        localStorage.setItem('battleforge_active_tournament', JSON.stringify(updatedTourney));
    }
  };

  // --- Generators ---

  const generateSingleElim = (participants: string[]): { matches: TournamentMatch[], rounds: number } => {
     const shuffled = [...participants].sort(() => 0.5 - Math.random());
     let size = 2;
     while(size < shuffled.length) size *= 2;
     // Fill with BYEs
     while(shuffled.length < size) shuffled.push("BYE");

     const matches: TournamentMatch[] = [];
     let matchIdCounter = 1;
     const getId = () => `m_${matchIdCounter++}`;

     // Round 1
     const round1Ids: string[] = [];
     const half = size / 2;

     for(let i=0; i<half; i++) {
        const id = getId();
        round1Ids.push(id);
        const p1 = shuffled[i*2];
        const p2 = shuffled[i*2+1];

        matches.push({
          id,
          roundIndex: 0,
          bracketType: 'winner',
          player1: p1,
          player2: p2,
          winner: null,
          status: 'pending' // settleBracket will handle transition to ready/completed
        });
     }

     // Subsequent Rounds
     let currentIds = round1Ids;
     let rIdx = 1;
     while(currentIds.length > 1) {
       const nextIds: string[] = [];
       for(let i=0; i<currentIds.length; i+=2) {
         const id = getId();
         nextIds.push(id);

         const m1 = matches.find(m => m.id === currentIds[i]);
         const m2 = matches.find(m => m.id === currentIds[i+1]);
         if(m1) m1.nextMatchId = id;
         if(m2) m2.nextMatchId = id;

         matches.push({
           id,
           roundIndex: rIdx,
           bracketType: 'winner',
           player1: null,
           player2: null,
           winner: null,
           status: 'pending'
         });
       }
       currentIds = nextIds;
       rIdx++;
     }

     return { matches, rounds: rIdx };
  };

  const generateDoubleElim = (participants: string[]): { matches: TournamentMatch[], rounds: number } => {
    // 1. Generate standard Winner Bracket
    const { matches: wbMatches, rounds: wbRounds } = generateSingleElim(participants);
    const matches = [...wbMatches];

    // Group WB matches by round for linking
    const wbByRound: Record<number, TournamentMatch[]> = {};
    matches.forEach(m => {
      if(!wbByRound[m.roundIndex]) wbByRound[m.roundIndex] = [];
      wbByRound[m.roundIndex].push(m);
    });

    // ID Generator for Losers Bracket
    let matchIdCounter = 2000;
    const getId = () => `m_${matchIdCounter++}`;

    const numPlayers = Math.pow(2, wbRounds); // 4, 8, 16...
    const lbMatches: TournamentMatch[] = [];

    // --- Losers Bracket Topology ---

    // N=4 (Smallest DE)
    if (numPlayers === 4) {
       // LB R0: Losers of WB R0
       const l0: TournamentMatch = { id: getId(), roundIndex: 0, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l0);
       wbByRound[0][0].loserNextMatchId = l0.id;
       wbByRound[0][1].loserNextMatchId = l0.id;

       // LB R1: Winner L0 vs Loser WB Final (WB R1)
       const l1: TournamentMatch = { id: getId(), roundIndex: 1, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l1);
       l0.nextMatchId = l1.id;
       wbByRound[1][0].loserNextMatchId = l1.id;

       // Grand Final
       const gf: TournamentMatch = { id: getId(), roundIndex: 0, bracketType: 'final', player1: null, player2: null, winner: null, status: 'pending' };
       matches.push(gf);
       wbByRound[1][0].nextMatchId = gf.id;
       l1.nextMatchId = gf.id;

    } else if (numPlayers >= 8) {
       // N=8 Standard Double Elimination

       // LB R0 (2 matches)
       const lbR0: TournamentMatch[] = [];
       const wbR0 = wbByRound[0];
       for(let i=0; i<2; i++) {
         const m: TournamentMatch = { id: getId(), roundIndex: 0, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
         lbR0.push(m);
         // Map WB losers (0,1 -> 0; 2,3 -> 1)
         wbR0[i*2].loserNextMatchId = m.id;
         wbR0[i*2+1].loserNextMatchId = m.id;
       }
       lbMatches.push(...lbR0);

       // LB R1 (Fed by LB R0 winners + WB R1 losers)
       const lbR1: TournamentMatch[] = [];
       const wbR1 = wbByRound[1]; // 2 matches
       for(let i=0; i<2; i++) {
          const m: TournamentMatch = { id: getId(), roundIndex: 1, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
          lbR1.push(m);
          lbR0[i].nextMatchId = m.id;
          wbR1[i].loserNextMatchId = m.id;
       }
       lbMatches.push(...lbR1);

       // LB R2 (Fed by LB R1 winners)
       // Usually these play each other
       const l2: TournamentMatch = { id: getId(), roundIndex: 2, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l2);
       lbR1[0].nextMatchId = l2.id;
       lbR1[1].nextMatchId = l2.id;

       // LB R3 (Fed by L2 winner + WB Final loser)
       const l3: TournamentMatch = { id: getId(), roundIndex: 3, bracketType: 'loser', player1: null, player2: null, winner: null, status: 'pending' };
       lbMatches.push(l3);
       l2.nextMatchId = l3.id;
       wbByRound[2][0].loserNextMatchId = l3.id;

       // Grand Final
       const gf: TournamentMatch = { id: getId(), roundIndex: 0, bracketType: 'final', player1: null, player2: null, winner: null, status: 'pending' };
       matches.push(gf);
       wbByRound[2][0].nextMatchId = gf.id;
       l3.nextMatchId = gf.id;
    }
    // Note: N=16 logic would follow similar patterns but expanded. For now N=8 is max supported structure.

    matches.push(...lbMatches);
    return { matches, rounds: 5 };
  };

  const createTournament = () => {
    if (!newTourneyName || selectedPlayers.length < 2) {
      alert("Enter name and select at least 2 players.");
      return;
    }

    let result;
    if (tourneyType === 'double') {
      result = generateDoubleElim(selectedPlayers);
    } else {
      result = generateSingleElim(selectedPlayers);
    }

    // Run initial settlement to resolve any initial BYEs and set R1 to ready
    settleBracket(result.matches);

    const newTourney: Tournament = {
      id: newTourneyName.replace(/\s+/g, '') + '_' + Date.now(),
      name: newTourneyName,
      type: tourneyType,
      participants: selectedPlayers,
      matches: result.matches,
      rounds: result.rounds,
      status: 'active',
      dateCreated: new Date().toISOString()
    };

    setActiveTournament(newTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(newTourney));
  };

  const handlePlayerToggle = (p: string) => {
    if (selectedPlayers.includes(p)) setSelectedPlayers(selectedPlayers.filter(x => x !== p));
    else setSelectedPlayers([...selectedPlayers, p]);
  };

  const confirmDelete = () => {
     localStorage.removeItem('battleforge_active_tournament');
     setActiveTournament(null);
     setNewTourneyName('');
     setSelectedPlayers([]);
     setShowDeleteModal(false);
     // Explicitly clear history state to prevent any weird re-mounts
     navigate('/tournament', { replace: true, state: {} });
  };

  const startMatch = (m: TournamentMatch) => {
     if (!activeTournament) return;
     if (m.status !== 'ready') return;

     navigate('/', { 
       state: {
         player1: m.player1,
         player2: m.player2,
         tournamentId: activeTournament.id,
         bracketMatchId: m.id
       }
     });
  };

  // Helper to render a bracket section
  const renderBracketSection = (title: string, matches: TournamentMatch[]) => {
      if (matches.length === 0) return null;
      // Find max round index in this set to allow scrolling
      const maxRound = Math.max(...matches.map(m => m.roundIndex), 0);

      return (
        <div className="mb-8">
           <h3 className="text-war-red font-orbitron font-bold uppercase mb-4 sticky left-0">{title}</h3>
           <div className="flex gap-8 min-w-max">
              {Array.from({ length: maxRound + 1 }).map((_, rIdx) => {
                 const roundMatches = matches.filter(m => m.roundIndex === rIdx);
                 if (roundMatches.length === 0) return null;

                 return (
                   <div key={rIdx} className="flex flex-col justify-around gap-8 w-64">
                      <div className="text-center text-zinc-500 font-orbitron text-xs font-bold uppercase mb-4 bg-black/40 p-1 rounded">
                        Round {rIdx + 1}
                      </div>
                      {roundMatches.map(m => {
                        const isReady = m.status === 'ready';
                        const isComplete = m.status === 'completed';
                        // Determine winner highlight
                        const p1Won = isComplete && m.winner === m.player1;
                        const p2Won = isComplete && m.winner === m.player2;

                        return (
                          <div 
                             key={m.id} 
                             onClick={() => isReady && startMatch(m)}
                             className={`
                               relative p-3 rounded border transition-all 
                               ${isComplete ? 'bg-green-900/10 border-green-900/30' : isReady ? 'bg-war-panel border-war-red cursor-pointer hover:bg-zinc-800 hover:scale-[1.02] shadow-[0_0_10px_rgba(255,45,45,0.2)]' : 'bg-zinc-900 border-zinc-800 opacity-60'}
                             `}
                          >
                             <div className={`text-sm font-bold flex justify-between ${p1Won ? 'text-green-400' : p2Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player1 || 'Waiting...'}</span>
                               {p1Won && <span>✓</span>}
                             </div>
                             <div className="h-px bg-zinc-700 my-2"></div>
                             <div className={`text-sm font-bold flex justify-between ${p2Won ? 'text-green-400' : p1Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player2 || 'Waiting...'}</span>
                               {p2Won && <span>✓</span>}
                             </div>
                          </div>
                        );
                      })}
                   </div>
                 );
              })}
           </div>
        </div>
      );
  };

  return (
    <div className="min-h-screen bg-war-dark pb-20 p-4">
      {/* Delete Confirmation Modal */}
      {showDeleteModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
            <div className="bg-war-panel border border-red-900/50 rounded-lg p-6 max-w-md w-full shadow-[0_0_20px_rgba(255,45,45,0.1)]">
                <h3 className="text-xl font-orbitron font-bold text-white mb-2">Delete Tournament?</h3>
                <p className="text-zinc-400 mb-6 text-sm">
                    Are you sure you want to delete <span className="text-white font-bold">{activeTournament?.name}</span>? 
                    This action cannot be undone and all bracket progress will be lost.
                </p>
                <div className="flex gap-3 justify-end">
                    <Button variant="secondary" onClick={() => setShowDeleteModal(false)} className="text-xs">Cancel</Button>
                    <Button variant="danger" onClick={confirmDelete} className="text-xs bg-red-600 hover:bg-red-700">Yes, Delete It</Button>
                </div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-orbitron font-bold text-war-red">
          TOURNAMENT<span className="text-white">HUB</span>
        </h1>
        <Button variant="secondary" onClick={() => navigate('/')} className="text-xs py-2 px-3">&larr; App</Button>
      </header>

      {!activeTournament ? (
        <div className="bg-war-panel border border-zinc-700 rounded-lg p-6 max-w-2xl mx-auto shadow-xl animate-fade-in">
           <h2 className="text-xl font-orbitron text-white mb-4">Create New Tournament</h2>

           <div className="space-y-4">
             <Input label="Tournament Name" value={newTourneyName} onChange={e => setNewTourneyName(e.target.value)} placeholder="e.g. Summer Slam 2024" />

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Format</label>
               <div className="flex gap-2">
                 <button onClick={() => setTourneyType('single')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'single' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Single Elimination</button>
                 <button onClick={() => setTourneyType('double')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'double' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Double Elimination</button>
               </div>
             </div>

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Participants ({selectedPlayers.length})</label>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-2 bg-zinc-900 p-3 rounded border border-zinc-800 max-h-40 overflow-y-auto">
                 {PLAYERS.map(p => (
                   <button 
                     key={p} 
                     onClick={() => handlePlayerToggle(p)}
                     className={`text-xs p-2 rounded text-left transition-colors ${selectedPlayers.includes(p) ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
                   >
                     {p}
                   </button>
                 ))}
               </div>
             </div>

             <Button onClick={createTournament} className="w-full mt-4">Generate Bracket</Button>
           </div>
        </div>
      ) : (
        <div className="animate-fade-in overflow-x-auto">
           {/* Sticky header updated with z-index and background to ensure clickable buttons */}
           <div className="flex justify-between items-center mb-4 min-w-[600px] sticky left-0 z-10 bg-war-dark p-2 border-b border-zinc-800">
             <div>
               <h2 className="text-2xl font-bold font-orbitron text-white">{activeTournament.name}</h2>
               <div className="text-xs text-zinc-500">Status: {activeTournament.status} | Type: {activeTournament.type}</div>
             </div>
             <Button variant="danger" onClick={() => setShowDeleteModal(true)} className="text-xs py-1 px-3 bg-red-800 hover:bg-red-700 text-white border-red-900 shadow-lg">Delete Tournament</Button>
           </div>

           {/* Render Brackets Split by Type */}
           {activeTournament.type === 'single' ? (
              renderBracketSection("Bracket", activeTournament.matches)
           ) : (
              <div>
                {renderBracketSection("Winners Bracket", activeTournament.matches.filter(m => m.bracketType === 'winner'))}
                {renderBracketSection("Losers Bracket", activeTournament.matches.filter(m => m.bracketType === 'loser'))}
                {renderBracketSection("Finals", activeTournament.matches.filter(m => m.bracketType === 'final'))}
              </div>
           )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { PLAYERS } from '../constants';
import { Tournament, TournamentMatch } from '../types';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';

export const TournamentHub: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [activeTournament, setActiveTournament] = useState<Tournament | null>(null);
  const [newTourneyName, setNewTourneyName] = useState('');
  const [selectedPlayers, setSelectedPlayers] = useState<string[]>([]);
  const [tourneyType, setTourneyType] = useState<'single' | 'double'>('single');
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  // Load active tournament
  useEffect(() => {
    const saved = localStorage.getItem('battleforge_active_tournament');
    if (saved) {
      setActiveTournament(JSON.parse(saved));
    }
  }, []);

  // Handle return from MatchLogger with results
  useEffect(() => {
    if (location.state && location.state.completedMatchId && location.state.winner) {
      const { completedMatchId, winner } = location.state;

      // IMPORTANT: Clear the state immediately to prevent infinite loops on re-render
      // We use navigate with replace to scrub the state from history
      navigate(location.pathname, { replace: true, state: {} });

      if (activeTournament) {
        handleMatchCompletion(completedMatchId, winner);
      }
    }
  }, [location.state, activeTournament, navigate, location.pathname]);

  // --- Core Logic: Advance Players & Resolve Byes ---

  const advancePlayerToMatch = (matches: TournamentMatch[], targetId: string, player: string): boolean => {
    const target = matches.find(m => m.id === targetId);
    if (!target) return false;

    // Idempotency check: Don't add if already there
    // This prevents "Sven" from appearing twice in the same match
    if (target.player1 === player || target.player2 === player) return false;

    let changed = false;

    // Fill empty slot
    if (!target.player1) {
       target.player1 = player;
       changed = true;
    } else if (!target.player2) {
       target.player2 = player;
       changed = true;
    } else {
       // Both slots full, cannot advance.
       return false; 
    }

    // Update status based on fullness
    // Only set to READY if BOTH players are present
    if (changed) {
        if (target.player1 && target.player2) {
            target.status = 'ready';
        } else {
            target.status = 'pending';
        }
    }

    return changed;
  };

  const settleBracket = (matches: TournamentMatch[]) => {
    let changed = true;
    // Limit iterations to prevent infinite loops in case of bad topology
    let iterations = 0;
    while(changed && iterations < 50) {
      changed = false;
      iterations++;

      matches.forEach(m => {
         // RULE 1: Auto-resolve pending/ready matches logic
         if (m.status !== 'completed') {
             const p1 = m.player1;
             const p2 = m.player2;

             if (p1 && p2) {
                 // 1a. Handle BYE
                 if (p1 === 'BYE' || p2 === 'BYE') {
                     m.winner = p1 === 'BYE' ? p2 : p1;
                     m.status = 'completed';
                     changed = true; 
                 } 
                 // 1b. Handle Initial Pending -> Ready (for R1 matches generated as pending)
                 else if (m.status === 'pending') {
                     m.status = 'ready';
                     changed = true;
                 }
             }
         }

         // RULE 2: Propagate Completed Matches
         if (m.status === 'completed' && m.winner) {
             // Advance Winner
             if (m.nextMatchId) {
                if (advancePlayerToMatch(matches, m.nextMatchId, m.winner)) changed = true;
             }
             // Advance Loser (Double Elim)
             if (m.loserNextMatchId && m.player1 && m.player2) {
                const loser = m.winner === m.player1 ? m.player2 : m.player1;
                // Important: Even if loser is "BYE", we propagate it so the next match (Rule 1a) can auto-resolve it
                if (loser && advancePlayerToMatch(matches, m.loserNextMatchId, loser)) changed = true;
             }
         }
      });
    }
  };

  const handleMatchCompletion = (matchId: string, winner: string | null) => {
    if (!activeTournament || !winner) return;

    // Deep copy to ensure immutability during processing
    const newMatches = JSON.parse(JSON.stringify(activeTournament.matches)); 
    const match = newMatches.find((m: TournamentMatch) => m.id === matchId);

    // If match already completed with same winner, ignore to prevent reprocessing
    if (match && match.status === 'completed' && match.winner === winner) return;

    if (match) {
        match.winner = winner;
        match.status = 'completed';

        // Recursively resolve the bracket (autofill Byes, etc)
        settleBracket(newMatches);

        const updatedTourney = { ...activeTournament, matches: newMatches };
        setActiveTournament(updatedTourney);
        localStorage.setItem('battleforge_active_tournament', JSON.stringify(updatedTourney));
    }
  };

  // --- Generators ---

  const generateSingleElim = (participants: string[]): { matches: TournamentMatch[], rounds: number } => {
     const shuffled = [...participants].sort(() => 0.5 - Math.random());
     let size = 2;
     while(size < shuffled.length) size *= 2;

     // Optimal BYE distribution:
     // Instead of filling end with BYEs, we pair BYEs with players in the first matches.
     // This reduces "BYE vs BYE" scenarios in later rounds.
     const numByes = size - shuffled.length;
     const round1MatchesCount = size / 2;

     const matches: TournamentMatch[] = [];
     let matchIdCounter = 1;
     const getId = () => `m_${matchIdCounter++}`;

     // Round 1
     const round1Ids: string[] = [];
     let pIndex = 0;

     for(let i=0; i<round1MatchesCount; i++) {
        const id = getId();
        round1Ids.push(id);

        let p1, p2;
        // Assign BYEs to the first 'numByes' matches
        if (i < numByes) {
            p1 = shuffled[pIndex++];
            p2 = "BYE";
        } else {
            p1 = shuffled[pIndex++];
            p2 = shuffled[pIndex++];
        }

        matches.push({
          id,
          roundIndex: 0,
          bracketType: 'winner',
          player1: p1,
          player2: p2,
          winner: null,
          status: 'pending' // settleBracket will handle transition to ready/completed
        });
     }

     // Subsequent Rounds
     let currentIds = round1Ids;
     let rIdx = 1;
     while(currentIds.length > 1) {
       const nextIds: string[] = [];
       for(let i=0; i<currentIds.length; i+=2) {
         const id = getId();
         nextIds.push(id);

         const m1 = matches.find(m => m.id === currentIds[i]);
         const m2 = matches.find(m => m.id === currentIds[i+1]);
         if(m1) m1.nextMatchId = id;
         if(m2) m2.nextMatchId = id;

         matches.push({
           id,
           roundIndex: rIdx,
           bracketType: 'winner',
           player1: null,
           player2: null,
           winner: null,
           status: 'pending'
         });
       }
       currentIds = nextIds;
       rIdx++;
     }

     return { matches, rounds: rIdx };
  };

  const generateDoubleElim = (participants: string[]): { matches: TournamentMatch[], rounds: number } => {
    // 1. Generate standard Winner Bracket
    const { matches: wbMatches, rounds: wbRounds } = generateSingleElim(participants);
    const matches = [...wbMatches];

    // Group WB matches by round for linking
    const wbByRound: Record<number, TournamentMatch[]> = {};
    matches.forEach(m => {
      if(!wbByRound[m.roundIndex]) wbByRound[m.roundIndex] = [];
      wbByRound[m.roundIndex].push(m);
    });

    let matchIdCounter = 2000;
    const getId = () => `m_${matchIdCounter++}`;

    const lbMatches: TournamentMatch[] = [];

    // Track the current "frontier" of LB matches to link to next layer
    let prevLBRoundMatches: TournamentMatch[] = [];

    // --- LB Round 0: Consumes WB Round 0 Losers ---
    // Standard DE: WB R0 losers drop to LB R0.
    const wbR0 = wbByRound[0];
    const lbR0Count = wbR0.length / 2;

    for (let i = 0; i < lbR0Count; i++) {
        const m: TournamentMatch = { 
            id: getId(), 
            roundIndex: 0, 
            bracketType: 'loser', 
            player1: null, 
            player2: null, 
            winner: null, 
            status: 'pending' 
        };
        lbMatches.push(m);
        prevLBRoundMatches.push(m);

        // Link WB Losers (Simple mapping: adjacent WB matches feed one LB match)
        wbR0[i*2].loserNextMatchId = m.id;
        wbR0[i*2+1].loserNextMatchId = m.id;
    }

    let lbRoundIndex = 1;

    // --- Loop through remaining WB Rounds to feed into LB ---
    // We iterate from WB R1 up to the WB Final
    for (let i = 1; i < wbRounds; i++) {
        const wbRoundMatches = wbByRound[i]; // Matches in this WB round

        // Step 1: Injection Round (Play against WB Losers)
        // Matches in this LB round = Matches in the feeding WB round
        const injectionMatches: TournamentMatch[] = [];
        for (let j = 0; j < wbRoundMatches.length; j++) {
            const m: TournamentMatch = {
                id: getId(),
                roundIndex: lbRoundIndex,
                bracketType: 'loser',
                player1: null,
                player2: null,
                winner: null,
                status: 'pending'
            };
            injectionMatches.push(m);
            lbMatches.push(m);

            // Link Sources: 
            // 1. Winner from Previous LB Round (if available)
            if (prevLBRoundMatches[j]) {
                prevLBRoundMatches[j].nextMatchId = m.id;
            }
            // 2. Loser from Current WB Round
            wbRoundMatches[j].loserNextMatchId = m.id;
        }

        prevLBRoundMatches = injectionMatches;
        lbRoundIndex++;

        // Step 2: Reduction Round (Play against each other)
        // Only if there is more than 1 match remaining (otherwise we are at LB Final)
        if (prevLBRoundMatches.length > 1) {
            const reductionMatches: TournamentMatch[] = [];
            for (let j = 0; j < prevLBRoundMatches.length; j += 2) {
                const m: TournamentMatch = {
                    id: getId(),
                    roundIndex: lbRoundIndex,
                    bracketType: 'loser',
                    player1: null,
                    player2: null,
                    winner: null,
                    status: 'pending'
                };
                reductionMatches.push(m);
                lbMatches.push(m);

                prevLBRoundMatches[j].nextMatchId = m.id;
                prevLBRoundMatches[j+1].nextMatchId = m.id;
            }
            prevLBRoundMatches = reductionMatches;
            lbRoundIndex++;
        }
    }

    // --- Grand Final ---
    const grandFinal: TournamentMatch = {
        id: getId(),
        roundIndex: 0,
        bracketType: 'final',
        player1: null,
        player2: null,
        winner: null,
        status: 'pending'
    };
    matches.push(grandFinal);

    // Winner of WB Final (last round of WB) -> GF
    const wbFinal = wbByRound[wbRounds-1][0];
    wbFinal.nextMatchId = grandFinal.id;

    // Winner of LB Final (last match in prevLBRoundMatches) -> GF
    if (prevLBRoundMatches[0]) {
        prevLBRoundMatches[0].nextMatchId = grandFinal.id;
    }

    matches.push(...lbMatches);
    return { matches, rounds: lbRoundIndex };
  };

  const createTournament = () => {
    if (!newTourneyName || selectedPlayers.length < 2) {
      alert("Enter name and select at least 2 players.");
      return;
    }

    let result;
    if (tourneyType === 'double') {
      result = generateDoubleElim(selectedPlayers);
    } else {
      result = generateSingleElim(selectedPlayers);
    }

    // Run initial settlement to resolve any initial BYEs and set R1 to ready
    settleBracket(result.matches);

    const newTourney: Tournament = {
      id: newTourneyName.replace(/\s+/g, '') + '_' + Date.now(),
      name: newTourneyName,
      type: tourneyType,
      participants: selectedPlayers,
      matches: result.matches,
      rounds: result.rounds,
      status: 'active',
      dateCreated: new Date().toISOString()
    };

    setActiveTournament(newTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(newTourney));
  };

  const handlePlayerToggle = (p: string) => {
    if (selectedPlayers.includes(p)) setSelectedPlayers(selectedPlayers.filter(x => x !== p));
    else setSelectedPlayers([...selectedPlayers, p]);
  };

  const confirmDelete = () => {
     localStorage.removeItem('battleforge_active_tournament');
     setActiveTournament(null);
     setNewTourneyName('');
     setSelectedPlayers([]);
     setShowDeleteModal(false);
     // Explicitly clear history state to prevent any weird re-mounts
     navigate('/tournament', { replace: true, state: {} });
  };

  const startMatch = (m: TournamentMatch) => {
     if (!activeTournament) return;
     if (m.status !== 'ready') return;

     navigate('/', { 
       state: {
         player1: m.player1,
         player2: m.player2,
         tournamentId: activeTournament.id,
         bracketMatchId: m.id
       }
     });
  };

  // Helper to render a bracket section
  const renderBracketSection = (title: string, matches: TournamentMatch[]) => {
      if (matches.length === 0) return null;
      // Find max round index in this set to allow scrolling
      const maxRound = Math.max(...matches.map(m => m.roundIndex), 0);

      return (
        <div className="mb-8">
           <h3 className="text-war-red font-orbitron font-bold uppercase mb-4 sticky left-0">{title}</h3>
           <div className="flex gap-8 min-w-max">
              {Array.from({ length: maxRound + 1 }).map((_, rIdx) => {
                 const roundMatches = matches.filter(m => m.roundIndex === rIdx);
                 if (roundMatches.length === 0) return null;

                 return (
                   <div key={rIdx} className="flex flex-col justify-around gap-8 w-64">
                      <div className="text-center text-zinc-500 font-orbitron text-xs font-bold uppercase mb-4 bg-black/40 p-1 rounded">
                        Round {rIdx + 1}
                      </div>
                      {roundMatches.map(m => {
                        const isReady = m.status === 'ready';
                        const isComplete = m.status === 'completed';
                        // Determine winner highlight
                        const p1Won = isComplete && m.winner === m.player1;
                        const p2Won = isComplete && m.winner === m.player2;

                        return (
                          <div 
                             key={m.id} 
                             onClick={() => isReady && startMatch(m)}
                             className={`
                               relative p-3 rounded border transition-all 
                               ${isComplete ? 'bg-green-900/10 border-green-900/30' : isReady ? 'bg-war-panel border-war-red cursor-pointer hover:bg-zinc-800 hover:scale-[1.02] shadow-[0_0_10px_rgba(255,45,45,0.2)]' : 'bg-zinc-900 border-zinc-800 opacity-60'}
                             `}
                          >
                             <div className={`text-sm font-bold flex justify-between ${p1Won ? 'text-green-400' : p2Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player1 || 'Waiting...'}</span>
                               {p1Won && <span>✓</span>}
                             </div>
                             <div className="h-px bg-zinc-700 my-2"></div>
                             <div className={`text-sm font-bold flex justify-between ${p2Won ? 'text-green-400' : p1Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player2 || 'Waiting...'}</span>
                               {p2Won && <span>✓</span>}
                             </div>
                          </div>
                        );
                      })}
                   </div>
                 );
              })}
           </div>
        </div>
      );
  };

  return (
    <div className="min-h-screen bg-war-dark pb-20 p-4">
      {/* Delete Confirmation Modal */}
      {showDeleteModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
            <div className="bg-war-panel border border-red-900/50 rounded-lg p-6 max-w-md w-full shadow-[0_0_20px_rgba(255,45,45,0.1)]">
                <h3 className="text-xl font-orbitron font-bold text-white mb-2">Delete Tournament?</h3>
                <p className="text-zinc-400 mb-6 text-sm">
                    Are you sure you want to delete <span className="text-white font-bold">{activeTournament?.name}</span>? 
                    This action cannot be undone and all bracket progress will be lost.
                </p>
                <div className="flex gap-3 justify-end">
                    <Button variant="secondary" onClick={() => setShowDeleteModal(false)} className="text-xs">Cancel</Button>
                    <Button variant="danger" onClick={confirmDelete} className="text-xs bg-red-600 hover:bg-red-700">Yes, Delete It</Button>
                </div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-orbitron font-bold text-war-red">
          TOURNAMENT<span className="text-white">HUB</span>
        </h1>
        <Button variant="secondary" onClick={() => navigate('/')} className="text-xs py-2 px-3">&larr; App</Button>
      </header>

      {!activeTournament ? (
        <div className="bg-war-panel border border-zinc-700 rounded-lg p-6 max-w-2xl mx-auto shadow-xl animate-fade-in">
           <h2 className="text-xl font-orbitron text-white mb-4">Create New Tournament</h2>

           <div className="space-y-4">
             <Input label="Tournament Name" value={newTourneyName} onChange={e => setNewTourneyName(e.target.value)} placeholder="e.g. Summer Slam 2024" />

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Format</label>
               <div className="flex gap-2">
                 <button onClick={() => setTourneyType('single')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'single' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Single Elimination</button>
                 <button onClick={() => setTourneyType('double')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'double' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Double Elimination</button>
               </div>
             </div>

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Participants ({selectedPlayers.length})</label>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-2 bg-zinc-900 p-3 rounded border border-zinc-800 max-h-40 overflow-y-auto">
                 {PLAYERS.map(p => (
                   <button 
                     key={p} 
                     onClick={() => handlePlayerToggle(p)}
                     className={`text-xs p-2 rounded text-left transition-colors ${selectedPlayers.includes(p) ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
                   >
                     {p}
                   </button>
                 ))}
               </div>
             </div>

             <Button onClick={createTournament} className="w-full mt-4">Generate Bracket</Button>
           </div>
        </div>
      ) : (
        <div className="animate-fade-in overflow-x-auto">
           {/* Sticky header updated with z-index and background to ensure clickable buttons */}
           <div className="flex justify-between items-center mb-4 min-w-[600px] sticky left-0 z-10 bg-war-dark p-2 border-b border-zinc-800">
             <div>
               <h2 className="text-2xl font-bold font-orbitron text-white">{activeTournament.name}</h2>
               <div className="text-xs text-zinc-500">Status: {activeTournament.status} | Type: {activeTournament.type}</div>
             </div>
             <Button variant="danger" onClick={() => setShowDeleteModal(true)} className="text-xs py-1 px-3 bg-red-800 hover:bg-red-700 text-white border-red-900 shadow-lg">Delete Tournament</Button>
           </div>

           {/* Render Brackets Split by Type */}
           {activeTournament.type === 'single' ? (
              renderBracketSection("Bracket", activeTournament.matches)
           ) : (
              <div>
                {renderBracketSection("Winners Bracket", activeTournament.matches.filter(m => m.bracketType === 'winner'))}
                {renderBracketSection("Losers Bracket", activeTournament.matches.filter(m => m.bracketType === 'loser'))}
                {renderBracketSection("Finals", activeTournament.matches.filter(m => m.bracketType === 'final'))}
              </div>
           )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { PLAYERS } from '../constants';
import { Tournament, TournamentMatch } from '../types';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';

export const TournamentHub: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [activeTournament, setActiveTournament] = useState<Tournament | null>(null);
  const [newTourneyName, setNewTourneyName] = useState('');
  const [selectedPlayers, setSelectedPlayers] = useState<string[]>([]);
  const [tourneyType, setTourneyType] = useState<'single' | 'double'>('single');
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  // Load active tournament
  useEffect(() => {
    const saved = localStorage.getItem('battleforge_active_tournament');
    if (saved) {
      setActiveTournament(JSON.parse(saved));
    }
  }, []);

  // Handle return from MatchLogger with results
  useEffect(() => {
    if (location.state && location.state.completedMatchId && location.state.winner) {
      const { completedMatchId, winner } = location.state;

      navigate(location.pathname, { replace: true, state: {} });

      if (activeTournament) {
        handleMatchCompletion(completedMatchId, winner);
      }
    }
  }, [location.state, activeTournament, navigate, location.pathname]);

  // --- Core Logic: Advance Players ---

  const advancePlayerToMatch = (matches: TournamentMatch[], targetId: string, player: string): boolean => {
    const target = matches.find(m => m.id === targetId);
    if (!target) return false;

    // Idempotency check
    if (target.player1 === player || target.player2 === player) return false;

    let changed = false;

    // Fill empty slot
    if (!target.player1) {
       target.player1 = player;
       changed = true;
    } else if (!target.player2) {
       target.player2 = player;
       changed = true;
    }

    if (changed) {
        if (target.player1 && target.player2) {
            target.status = 'ready';
        } else {
            target.status = 'pending';
        }
    }

    return changed;
  };

  const settleBracket = (matches: TournamentMatch[]) => {
    let changed = true;
    let iterations = 0;
    while(changed && iterations < 50) {
      changed = false;
      iterations++;

      matches.forEach(m => {
         // RULE 1: Auto-resolve pending/ready matches
         if (m.status !== 'completed') {
             const p1 = m.player1;
             const p2 = m.player2;

             if (p1 && p2) {
                 // 1a. Handle BYE (Should rarely happen post-pruning, but good safety)
                 if (p1 === 'BYE' || p2 === 'BYE') {
                     m.winner = p1 === 'BYE' ? p2 : p1;
                     m.status = 'completed';
                     changed = true; 
                 } 
                 // 1b. Handle Initial Pending -> Ready
                 else if (m.status === 'pending') {
                     m.status = 'ready';
                     changed = true;
                 }
             }
         }

         // RULE 2: Propagate Completed Matches
         if (m.status === 'completed' && m.winner) {
             // Advance Winner
             if (m.nextMatchId) {
                if (advancePlayerToMatch(matches, m.nextMatchId, m.winner)) changed = true;
             }
             // Advance Loser (Double Elim)
             if (m.loserNextMatchId && m.player1 && m.player2) {
                const loser = m.winner === m.player1 ? m.player2 : m.player1;
                if (loser && advancePlayerToMatch(matches, m.loserNextMatchId, loser)) changed = true;
             }
         }
      });
    }
  };

  const handleMatchCompletion = (matchId: string, winner: string | null) => {
    if (!activeTournament || !winner) return;

    const newMatches = JSON.parse(JSON.stringify(activeTournament.matches)); 
    const match = newMatches.find((m: TournamentMatch) => m.id === matchId);

    if (match && match.status === 'completed' && match.winner === winner) return;

    if (match) {
        match.winner = winner;
        match.status = 'completed';

        settleBracket(newMatches);

        const updatedTourney = { ...activeTournament, matches: newMatches };
        setActiveTournament(updatedTourney);
        localStorage.setItem('battleforge_active_tournament', JSON.stringify(updatedTourney));
    }
  };

  // --- Pruning Logic ---
  // This removes "BYE" matches and promotes the real players automatically
  const pruneBracket = (matches: TournamentMatch[]) => {
    let activeMatches = [...matches];
    let changed = true;

    // Safety loop to cascade byes
    while(changed) {
        changed = false;
        const toRemove: string[] = [];

        // Sort by round to process R0 first
        activeMatches.sort((a,b) => a.roundIndex - b.roundIndex);

        for(const m of activeMatches) {
            let winner: string | null = null;
            let loser: string | null = null;

            // Identify Bypass conditions
            // 1. P1 vs BYE -> P1 wins
            if (m.player1 && m.player1 !== 'BYE' && m.player2 === 'BYE') {
                winner = m.player1;
                loser = 'BYE';
            } 
            // 2. BYE vs P2 -> P2 wins
            else if (m.player1 === 'BYE' && m.player2 && m.player2 !== 'BYE') {
                winner = m.player2;
                loser = 'BYE';
            } 
            // 3. BYE vs BYE -> BYE wins
            else if (m.player1 === 'BYE' && m.player2 === 'BYE') {
                winner = 'BYE';
                loser = 'BYE';
            }

            if (winner) {
                // Mark for deletion
                toRemove.push(m.id);
                changed = true;

                // Propagate Winner Manually (since we are deleting the match, we can't rely on settleBracket)
                if (m.nextMatchId) {
                    const nextM = activeMatches.find(x => x.id === m.nextMatchId);
                    if (nextM) {
                        // Place in first available slot (or specific slot if we tracked it, but standard brackets are fluid)
                        // Note: To be precise, we should try to preserve P1->P1 flow, but simple filling works for generated brackets
                        if (!nextM.player1) nextM.player1 = winner;
                        else if (!nextM.player2) nextM.player2 = winner;
                    }
                }

                // Propagate Loser (to LB)
                if (m.loserNextMatchId) {
                     const loserM = activeMatches.find(x => x.id === m.loserNextMatchId);
                     if (loserM) {
                        if (!loserM.player1) loserM.player1 = loser;
                        else if (!loserM.player2) loserM.player2 = loser;
                     }
                }
            }
        }

        if (toRemove.length > 0) {
            activeMatches = activeMatches.filter(m => !toRemove.includes(m.id));
        }
    }
    return activeMatches;
  };

  // --- Generators ---

  // Generates a FULL power-of-2 bracket (including BYE matches)
  // Pruning happens afterwards
  const generateFullSingleElim = (participants: string[], idOffset = 0): { matches: TournamentMatch[], rounds: number, nextId: number } => {
     const shuffled = [...participants].sort(() => 0.5 - Math.random());
     let size = 2;
     while(size < shuffled.length) size *= 2;

     // Distribute BYEs interleaved to maximize pruning effectiveness
     // Pairing: [P1, BYE], [P2, BYE]... [P_x, P_y]
     // This ensures P1, P2 etc get promoted to R2 immediately
     const numByes = size - shuffled.length;

     const r1Pairs: {p1: string, p2: string}[] = [];
     let pIndex = 0;

     // Create pairs
     for (let i=0; i < size/2; i++) {
        if (i < numByes) {
            r1Pairs.push({ p1: shuffled[pIndex++] || "BYE", p2: "BYE" });
        } else {
            r1Pairs.push({ p1: shuffled[pIndex++] || "BYE", p2: shuffled[pIndex++] || "BYE" });
        }
     }

     const matches: TournamentMatch[] = [];
     let matchIdCounter = idOffset + 1;
     const getId = () => `m_${matchIdCounter++}`;

     // Round 1
     const round1Ids: string[] = [];

     r1Pairs.forEach(pair => {
        const id = getId();
        round1Ids.push(id);
        matches.push({
          id,
          roundIndex: 0,
          bracketType: 'winner',
          player1: pair.p1,
          player2: pair.p2,
          winner: null,
          status: 'pending' 
        });
     });

     // Subsequent Rounds
     let currentIds = round1Ids;
     let rIdx = 1;
     while(currentIds.length > 1) {
       const nextIds: string[] = [];
       for(let i=0; i<currentIds.length; i+=2) {
         const id = getId();
         nextIds.push(id);

         const m1 = matches.find(m => m.id === currentIds[i]);
         const m2 = matches.find(m => m.id === currentIds[i+1]);
         if(m1) m1.nextMatchId = id;
         if(m2) m2.nextMatchId = id;

         matches.push({
           id,
           roundIndex: rIdx,
           bracketType: 'winner',
           player1: null,
           player2: null,
           winner: null,
           status: 'pending'
         });
       }
       currentIds = nextIds;
       rIdx++;
     }

     return { matches, rounds: rIdx, nextId: matchIdCounter };
  };

  const generateDoubleElim = (participants: string[]): { matches: TournamentMatch[], rounds: number } => {
    // 1. Generate FULL Winner Bracket
    const { matches: wbMatches, rounds: wbRounds, nextId } = generateFullSingleElim(participants);
    const matches = [...wbMatches];

    // Group WB matches by round
    const wbByRound: Record<number, TournamentMatch[]> = {};
    matches.forEach(m => {
      if(!wbByRound[m.roundIndex]) wbByRound[m.roundIndex] = [];
      wbByRound[m.roundIndex].push(m);
    });

    let matchIdCounter = nextId + 1000;
    const getId = () => `m_${matchIdCounter++}`;

    const lbMatches: TournamentMatch[] = [];
    let prevLBRoundMatches: TournamentMatch[] = [];

    // --- LB Round 0: Consumes WB Round 0 Losers ---
    const wbR0 = wbByRound[0];
    const lbR0Count = wbR0.length / 2;

    for (let i = 0; i < lbR0Count; i++) {
        const m: TournamentMatch = { 
            id: getId(), 
            roundIndex: 0, 
            bracketType: 'loser', 
            player1: null, 
            player2: null, 
            winner: null, 
            status: 'pending' 
        };
        lbMatches.push(m);
        prevLBRoundMatches.push(m);

        wbR0[i*2].loserNextMatchId = m.id;
        wbR0[i*2+1].loserNextMatchId = m.id;
    }

    let lbRoundIndex = 1;

    // --- Feed Remaining WB Rounds ---
    for (let i = 1; i < wbRounds; i++) {
        const wbRoundMatches = wbByRound[i]; 

        // Injection Round
        const injectionMatches: TournamentMatch[] = [];
        for (let j = 0; j < wbRoundMatches.length; j++) {
            const m: TournamentMatch = {
                id: getId(),
                roundIndex: lbRoundIndex,
                bracketType: 'loser',
                player1: null,
                player2: null,
                winner: null,
                status: 'pending'
            };
            injectionMatches.push(m);
            lbMatches.push(m);

            if (prevLBRoundMatches[j]) prevLBRoundMatches[j].nextMatchId = m.id;
            wbRoundMatches[j].loserNextMatchId = m.id;
        }

        prevLBRoundMatches = injectionMatches;
        lbRoundIndex++;

        // Reduction Round
        if (prevLBRoundMatches.length > 1) {
            const reductionMatches: TournamentMatch[] = [];
            for (let j = 0; j < prevLBRoundMatches.length; j += 2) {
                const m: TournamentMatch = {
                    id: getId(),
                    roundIndex: lbRoundIndex,
                    bracketType: 'loser',
                    player1: null, 
                    player2: null,
                    winner: null, 
                    status: 'pending'
                };
                reductionMatches.push(m);
                lbMatches.push(m);

                prevLBRoundMatches[j].nextMatchId = m.id;
                prevLBRoundMatches[j+1].nextMatchId = m.id;
            }
            prevLBRoundMatches = reductionMatches;
            lbRoundIndex++;
        }
    }

    // --- Grand Final ---
    const grandFinal: TournamentMatch = {
        id: getId(),
        roundIndex: 0,
        bracketType: 'final',
        player1: null,
        player2: null,
        winner: null,
        status: 'pending'
    };
    matches.push(grandFinal);

    const wbFinal = wbByRound[wbRounds-1][0];
    wbFinal.nextMatchId = grandFinal.id;

    if (prevLBRoundMatches[0]) {
        prevLBRoundMatches[0].nextMatchId = grandFinal.id;
    }

    matches.push(...lbMatches);

    // Now Prune Everything
    const prunedMatches = pruneBracket(matches);

    return { matches: prunedMatches, rounds: lbRoundIndex };
  };

  const createTournament = () => {
    if (!newTourneyName || selectedPlayers.length < 2) {
      alert("Enter name and select at least 2 players.");
      return;
    }

    let result;
    if (tourneyType === 'double') {
      result = generateDoubleElim(selectedPlayers);
    } else {
      // Generate full tree then prune for Single Elim too
      const full = generateFullSingleElim(selectedPlayers);
      const pruned = pruneBracket(full.matches);
      result = { matches: pruned, rounds: full.rounds };
    }

    // Final settle to set ready states
    settleBracket(result.matches);

    const newTourney: Tournament = {
      id: newTourneyName.replace(/\s+/g, '') + '_' + Date.now(),
      name: newTourneyName,
      type: tourneyType,
      participants: selectedPlayers,
      matches: result.matches,
      rounds: result.rounds,
      status: 'active',
      dateCreated: new Date().toISOString()
    };

    setActiveTournament(newTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(newTourney));
  };

  const handlePlayerToggle = (p: string) => {
    if (selectedPlayers.includes(p)) setSelectedPlayers(selectedPlayers.filter(x => x !== p));
    else setSelectedPlayers([...selectedPlayers, p]);
  };

  const confirmDelete = () => {
     localStorage.removeItem('battleforge_active_tournament');
     setActiveTournament(null);
     setNewTourneyName('');
     setSelectedPlayers([]);
     setShowDeleteModal(false);
     navigate('/tournament', { replace: true, state: {} });
  };

  const startMatch = (m: TournamentMatch) => {
     if (!activeTournament) return;
     if (m.status !== 'ready') return;

     navigate('/', { 
       state: {
         player1: m.player1,
         player2: m.player2,
         tournamentId: activeTournament.id,
         bracketMatchId: m.id
       }
     });
  };

  const renderBracketSection = (title: string, matches: TournamentMatch[]) => {
      if (matches.length === 0) return null;
      // We map roundIndex to visual columns. 
      // Because of pruning, roundIndex might skip (e.g. only matches in R1).
      // We find the extent of rounds.
      const maxRound = Math.max(...matches.map(m => m.roundIndex), 0);

      return (
        <div className="mb-8">
           <h3 className="text-war-red font-orbitron font-bold uppercase mb-4 sticky left-0">{title}</h3>
           <div className="flex gap-8 min-w-max">
              {Array.from({ length: maxRound + 1 }).map((_, rIdx) => {
                 const roundMatches = matches.filter(m => m.roundIndex === rIdx);
                 // If a round is empty due to pruning, we still render the column to maintain spacing/structure 
                 // OR we can skip it. If we skip, the visual alignment breaks for DE.
                 // Better to render empty column if it's "skipped" but that looks weird.
                 // Actually, if a round has NO matches, it means everyone advanced past it. 
                 // So we should probably hide it?
                 if (roundMatches.length === 0) return null;

                 return (
                   <div key={rIdx} className="flex flex-col justify-around gap-8 w-64">
                      <div className="text-center text-zinc-500 font-orbitron text-xs font-bold uppercase mb-4 bg-black/40 p-1 rounded">
                        Round {rIdx + 1}
                      </div>
                      {roundMatches.map(m => {
                        const isReady = m.status === 'ready';
                        const isComplete = m.status === 'completed';
                        const p1Won = isComplete && m.winner === m.player1;
                        const p2Won = isComplete && m.winner === m.player2;

                        return (
                          <div 
                             key={m.id} 
                             onClick={() => isReady && startMatch(m)}
                             className={`
                               relative p-3 rounded border transition-all 
                               ${isComplete ? 'bg-green-900/10 border-green-900/30' : isReady ? 'bg-war-panel border-war-red cursor-pointer hover:bg-zinc-800 hover:scale-[1.02] shadow-[0_0_10px_rgba(255,45,45,0.2)]' : 'bg-zinc-900 border-zinc-800 opacity-60'}
                             `}
                          >
                             <div className={`text-sm font-bold flex justify-between ${p1Won ? 'text-green-400' : p2Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player1 || 'Waiting...'}</span>
                               {p1Won && <span>✓</span>}
                             </div>
                             <div className="h-px bg-zinc-700 my-2"></div>
                             <div className={`text-sm font-bold flex justify-between ${p2Won ? 'text-green-400' : p1Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player2 || 'Waiting...'}</span>
                               {p2Won && <span>✓</span>}
                             </div>
                          </div>
                        );
                      })}
                   </div>
                 );
              })}
           </div>
        </div>
      );
  };

  return (
    <div className="min-h-screen bg-war-dark pb-20 p-4">
      {/* Delete Confirmation Modal */}
      {showDeleteModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
            <div className="bg-war-panel border border-red-900/50 rounded-lg p-6 max-w-md w-full shadow-[0_0_20px_rgba(255,45,45,0.1)]">
                <h3 className="text-xl font-orbitron font-bold text-white mb-2">Delete Tournament?</h3>
                <p className="text-zinc-400 mb-6 text-sm">
                    Are you sure you want to delete <span className="text-white font-bold">{activeTournament?.name}</span>? 
                    This action cannot be undone and all bracket progress will be lost.
                </p>
                <div className="flex gap-3 justify-end">
                    <Button variant="secondary" onClick={() => setShowDeleteModal(false)} className="text-xs">Cancel</Button>
                    <Button variant="danger" onClick={confirmDelete} className="text-xs bg-red-600 hover:bg-red-700">Yes, Delete It</Button>
                </div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-orbitron font-bold text-war-red">
          TOURNAMENT<span className="text-white">HUB</span>
        </h1>
        <Button variant="secondary" onClick={() => navigate('/')} className="text-xs py-2 px-3">&larr; App</Button>
      </header>

      {!activeTournament ? (
        <div className="bg-war-panel border border-zinc-700 rounded-lg p-6 max-w-2xl mx-auto shadow-xl animate-fade-in">
           <h2 className="text-xl font-orbitron text-white mb-4">Create New Tournament</h2>

           <div className="space-y-4">
             <Input label="Tournament Name" value={newTourneyName} onChange={e => setNewTourneyName(e.target.value)} placeholder="e.g. Summer Slam 2024" />

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Format</label>
               <div className="flex gap-2">
                 <button onClick={() => setTourneyType('single')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'single' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Single Elimination</button>
                 <button onClick={() => setTourneyType('double')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'double' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Double Elimination</button>
               </div>
             </div>

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Participants ({selectedPlayers.length})</label>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-2 bg-zinc-900 p-3 rounded border border-zinc-800 max-h-40 overflow-y-auto">
                 {PLAYERS.map(p => (
                   <button 
                     key={p} 
                     onClick={() => handlePlayerToggle(p)}
                     className={`text-xs p-2 rounded text-left transition-colors ${selectedPlayers.includes(p) ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
                   >
                     {p}
                   </button>
                 ))}
               </div>
             </div>

             <Button onClick={createTournament} className="w-full mt-4">Generate Bracket</Button>
           </div>
        </div>
      ) : (
        <div className="animate-fade-in overflow-x-auto">
           {/* Sticky header updated with z-index and background to ensure clickable buttons */}
           <div className="flex justify-between items-center mb-4 min-w-[600px] sticky left-0 z-10 bg-war-dark p-2 border-b border-zinc-800">
             <div>
               <h2 className="text-2xl font-bold font-orbitron text-white">{activeTournament.name}</h2>
               <div className="text-xs text-zinc-500">Status: {activeTournament.status} | Type: {activeTournament.type}</div>
             </div>
             <Button variant="danger" onClick={() => setShowDeleteModal(true)} className="text-xs py-1 px-3 bg-red-800 hover:bg-red-700 text-white border-red-900 shadow-lg">Delete Tournament</Button>
           </div>

           {/* Render Brackets Split by Type */}
           {activeTournament.type === 'single' ? (
              renderBracketSection("Bracket", activeTournament.matches)
           ) : (
              <div>
                {renderBracketSection("Winners Bracket", activeTournament.matches.filter(m => m.bracketType === 'winner'))}
                {renderBracketSection("Losers Bracket", activeTournament.matches.filter(m => m.bracketType === 'loser'))}
                {renderBracketSection("Finals", activeTournament.matches.filter(m => m.bracketType === 'final'))}
              </div>
           )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { PLAYERS } from '../constants';
import { Tournament, TournamentMatch } from '../types';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';

export const TournamentHub: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [activeTournament, setActiveTournament] = useState<Tournament | null>(null);
  const [newTourneyName, setNewTourneyName] = useState('');
  const [selectedPlayers, setSelectedPlayers] = useState<string[]>([]);
  const [tourneyType, setTourneyType] = useState<'single' | 'double'>('single');
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  // Load active tournament
  useEffect(() => {
    const saved = localStorage.getItem('battleforge_active_tournament');
    if (saved) {
      const tourney = JSON.parse(saved);
      // Auto-prune on load to fix any existing display issues
      if (tourney.status === 'active') {
          const pruned = pruneBracket(tourney.matches);
          if (pruned.length !== tourney.matches.length) {
              tourney.matches = pruned;
              setActiveTournament(tourney); // Update state
              localStorage.setItem('battleforge_active_tournament', JSON.stringify(tourney)); // Update storage
          } else {
              setActiveTournament(tourney);
          }
      } else {
          setActiveTournament(tourney);
      }
    }
  }, []);

  // Handle return from MatchLogger with results
  useEffect(() => {
    if (location.state && location.state.completedMatchId && location.state.winner) {
      const { completedMatchId, winner } = location.state;

      navigate(location.pathname, { replace: true, state: {} });

      if (activeTournament) {
        handleMatchCompletion(completedMatchId, winner);
      }
    }
  }, [location.state, activeTournament, navigate, location.pathname]);

  // --- Core Logic: Advance Players ---

  const advancePlayerToMatch = (matches: TournamentMatch[], targetId: string, player: string): boolean => {
    const target = matches.find(m => m.id === targetId);
    if (!target) return false;

    // Idempotency check
    if (target.player1 === player || target.player2 === player) return false;

    let changed = false;

    // Fill empty slot
    if (!target.player1) {
       target.player1 = player;
       changed = true;
    } else if (!target.player2) {
       target.player2 = player;
       changed = true;
    }

    if (changed) {
        if (target.player1 && target.player2) {
            target.status = 'ready';
        } else {
            target.status = 'pending';
        }
    }

    return changed;
  };

  const settleBracket = (matches: TournamentMatch[]) => {
    let changed = true;
    let iterations = 0;
    while(changed && iterations < 50) {
      changed = false;
      iterations++;

      matches.forEach(m => {
         // RULE 1: Auto-resolve pending/ready matches
         if (m.status !== 'completed') {
             const p1 = m.player1;
             const p2 = m.player2;

             if (p1 && p2) {
                 // 1a. Handle BYE (Should rarely happen post-pruning, but good safety)
                 if (p1 === 'BYE' || p2 === 'BYE') {
                     m.winner = p1 === 'BYE' ? p2 : p1;
                     m.status = 'completed';
                     changed = true; 
                 } 
                 // 1b. Handle Initial Pending -> Ready
                 else if (m.status === 'pending') {
                     m.status = 'ready';
                     changed = true;
                 }
             }
         }

         // RULE 2: Propagate Completed Matches
         if (m.status === 'completed' && m.winner) {
             // Advance Winner
             if (m.nextMatchId) {
                if (advancePlayerToMatch(matches, m.nextMatchId, m.winner)) changed = true;
             }
             // Advance Loser (Double Elim)
             if (m.loserNextMatchId && m.player1 && m.player2) {
                const loser = m.winner === m.player1 ? m.player2 : m.player1;
                if (loser && advancePlayerToMatch(matches, m.loserNextMatchId, loser)) changed = true;
             }
         }
      });
    }
  };

  const handleMatchCompletion = (matchId: string, winner: string | null) => {
    if (!activeTournament || !winner) return;

    const newMatches = JSON.parse(JSON.stringify(activeTournament.matches)); 
    const match = newMatches.find((m: TournamentMatch) => m.id === matchId);

    if (match && match.status === 'completed' && match.winner === winner) return;

    if (match) {
        match.winner = winner;
        match.status = 'completed';

        settleBracket(newMatches);

        const updatedTourney = { ...activeTournament, matches: newMatches };
        setActiveTournament(updatedTourney);
        localStorage.setItem('battleforge_active_tournament', JSON.stringify(updatedTourney));
    }
  };

  // --- Pruning Logic ---
  // This removes "BYE" matches and promotes the real players automatically
  const pruneBracket = (matches: TournamentMatch[]) => {
    let activeMatches = [...matches];
    let changed = true;
    let iterations = 0;

    // Safety loop to cascade byes
    while(changed && iterations < 20) {
        changed = false;
        iterations++;
        const toRemove: string[] = [];

        // Sort by round to process R0 first
        activeMatches.sort((a,b) => a.roundIndex - b.roundIndex);

        for(const m of activeMatches) {
            let winner: string | null = null;
            let loser: string | null = null;

            // Identify Bypass conditions
            // 1. P1 vs BYE -> P1 wins
            if (m.player1 && m.player1 !== 'BYE' && m.player2 === 'BYE') {
                winner = m.player1;
                loser = 'BYE';
            } 
            // 2. BYE vs P2 -> P2 wins
            else if (m.player1 === 'BYE' && m.player2 && m.player2 !== 'BYE') {
                winner = m.player2;
                loser = 'BYE';
            } 
            // 3. BYE vs BYE -> BYE wins
            else if (m.player1 === 'BYE' && m.player2 === 'BYE') {
                winner = 'BYE';
                loser = 'BYE';
            }

            if (winner) {
                // Mark for deletion
                toRemove.push(m.id);
                changed = true;

                // Propagate Winner Manually
                if (m.nextMatchId) {
                    const nextM = activeMatches.find(x => x.id === m.nextMatchId);
                    if (nextM) {
                        if (!nextM.player1) nextM.player1 = winner;
                        else if (!nextM.player2) nextM.player2 = winner;
                    }
                }

                // Propagate Loser (to LB)
                if (m.loserNextMatchId) {
                     const loserM = activeMatches.find(x => x.id === m.loserNextMatchId);
                     if (loserM) {
                        if (!loserM.player1) loserM.player1 = loser;
                        else if (!loserM.player2) loserM.player2 = loser;
                     }
                }
            }
        }

        if (toRemove.length > 0) {
            activeMatches = activeMatches.filter(m => !toRemove.includes(m.id));
        }
    }
    return activeMatches;
  };

  // --- Generators ---

  // Generates a FULL power-of-2 bracket (including BYE matches)
  // Pruning happens afterwards
  const generateFullSingleElim = (participants: string[], idOffset = 0): { matches: TournamentMatch[], rounds: number, nextId: number } => {
     const shuffled = [...participants].sort(() => 0.5 - Math.random());
     let size = 2;
     while(size < shuffled.length) size *= 2;

     // Distribute BYEs interleaved
     const numByes = size - shuffled.length;

     const r1Pairs: {p1: string, p2: string}[] = [];
     let pIndex = 0;

     // Create pairs
     for (let i=0; i < size/2; i++) {
        if (i < numByes) {
            r1Pairs.push({ p1: shuffled[pIndex++] || "BYE", p2: "BYE" });
        } else {
            r1Pairs.push({ p1: shuffled[pIndex++] || "BYE", p2: shuffled[pIndex++] || "BYE" });
        }
     }

     const matches: TournamentMatch[] = [];
     let matchIdCounter = idOffset + 1;
     const getId = () => `m_${matchIdCounter++}`;

     // Round 1
     const round1Ids: string[] = [];

     r1Pairs.forEach(pair => {
        const id = getId();
        round1Ids.push(id);
        matches.push({
          id,
          roundIndex: 0,
          bracketType: 'winner',
          player1: pair.p1,
          player2: pair.p2,
          winner: null,
          status: 'pending' 
        });
     });

     // Subsequent Rounds
     let currentIds = round1Ids;
     let rIdx = 1;
     while(currentIds.length > 1) {
       const nextIds: string[] = [];
       for(let i=0; i<currentIds.length; i+=2) {
         const id = getId();
         nextIds.push(id);

         const m1 = matches.find(m => m.id === currentIds[i]);
         const m2 = matches.find(m => m.id === currentIds[i+1]);
         if(m1) m1.nextMatchId = id;
         if(m2) m2.nextMatchId = id;

         matches.push({
           id,
           roundIndex: rIdx,
           bracketType: 'winner',
           player1: null,
           player2: null,
           winner: null,
           status: 'pending'
         });
       }
       currentIds = nextIds;
       rIdx++;
     }

     return { matches, rounds: rIdx, nextId: matchIdCounter };
  };

  const generateDoubleElim = (participants: string[]): { matches: TournamentMatch[], rounds: number } => {
    // 1. Generate FULL Winner Bracket
    const { matches: wbMatches, rounds: wbRounds, nextId } = generateFullSingleElim(participants);
    const matches = [...wbMatches];

    // Group WB matches by round
    const wbByRound: Record<number, TournamentMatch[]> = {};
    matches.forEach(m => {
      if(!wbByRound[m.roundIndex]) wbByRound[m.roundIndex] = [];
      wbByRound[m.roundIndex].push(m);
    });

    let matchIdCounter = nextId + 1000;
    const getId = () => `m_${matchIdCounter++}`;

    const lbMatches: TournamentMatch[] = [];
    let prevLBRoundMatches: TournamentMatch[] = [];

    // --- LB Round 0: Consumes WB Round 0 Losers ---
    const wbR0 = wbByRound[0];
    const lbR0Count = wbR0.length / 2;

    for (let i = 0; i < lbR0Count; i++) {
        const m: TournamentMatch = { 
            id: getId(), 
            roundIndex: 0, 
            bracketType: 'loser', 
            player1: null, 
            player2: null, 
            winner: null, 
            status: 'pending' 
        };
        lbMatches.push(m);
        prevLBRoundMatches.push(m);

        wbR0[i*2].loserNextMatchId = m.id;
        wbR0[i*2+1].loserNextMatchId = m.id;
    }

    let lbRoundIndex = 1;

    // --- Feed Remaining WB Rounds ---
    for (let i = 1; i < wbRounds; i++) {
        const wbRoundMatches = wbByRound[i]; 

        // Injection Round
        const injectionMatches: TournamentMatch[] = [];
        for (let j = 0; j < wbRoundMatches.length; j++) {
            const m: TournamentMatch = {
                id: getId(),
                roundIndex: lbRoundIndex,
                bracketType: 'loser',
                player1: null,
                player2: null,
                winner: null,
                status: 'pending'
            };
            injectionMatches.push(m);
            lbMatches.push(m);

            if (prevLBRoundMatches[j]) prevLBRoundMatches[j].nextMatchId = m.id;
            wbRoundMatches[j].loserNextMatchId = m.id;
        }

        prevLBRoundMatches = injectionMatches;
        lbRoundIndex++;

        // Reduction Round
        if (prevLBRoundMatches.length > 1) {
            const reductionMatches: TournamentMatch[] = [];
            for (let j = 0; j < prevLBRoundMatches.length; j += 2) {
                const m: TournamentMatch = {
                    id: getId(),
                    roundIndex: lbRoundIndex,
                    bracketType: 'loser',
                    player1: null, 
                    player2: null,
                    winner: null, 
                    status: 'pending'
                };
                reductionMatches.push(m);
                lbMatches.push(m);

                prevLBRoundMatches[j].nextMatchId = m.id;
                prevLBRoundMatches[j+1].nextMatchId = m.id;
            }
            prevLBRoundMatches = reductionMatches;
            lbRoundIndex++;
        }
    }

    // --- Grand Final ---
    const grandFinal: TournamentMatch = {
        id: getId(),
        roundIndex: 0,
        bracketType: 'final',
        player1: null,
        player2: null,
        winner: null,
        status: 'pending'
    };
    matches.push(grandFinal);

    const wbFinal = wbByRound[wbRounds-1][0];
    wbFinal.nextMatchId = grandFinal.id;

    if (prevLBRoundMatches[0]) {
        prevLBRoundMatches[0].nextMatchId = grandFinal.id;
    }

    matches.push(...lbMatches);

    // Now Prune Everything
    const prunedMatches = pruneBracket(matches);

    return { matches: prunedMatches, rounds: lbRoundIndex };
  };

  const createTournament = () => {
    if (!newTourneyName || selectedPlayers.length < 2) {
      alert("Enter name and select at least 2 players.");
      return;
    }

    let result;
    if (tourneyType === 'double') {
      result = generateDoubleElim(selectedPlayers);
    } else {
      // Generate full tree then prune for Single Elim too
      const full = generateFullSingleElim(selectedPlayers);
      const pruned = pruneBracket(full.matches);
      result = { matches: pruned, rounds: full.rounds };
    }

    // Final settle to set ready states
    settleBracket(result.matches);

    const newTourney: Tournament = {
      id: newTourneyName.replace(/\s+/g, '') + '_' + Date.now(),
      name: newTourneyName,
      type: tourneyType,
      participants: selectedPlayers,
      matches: result.matches,
      rounds: result.rounds,
      status: 'active',
      dateCreated: new Date().toISOString()
    };

    setActiveTournament(newTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(newTourney));
  };

  const handlePlayerToggle = (p: string) => {
    if (selectedPlayers.includes(p)) setSelectedPlayers(selectedPlayers.filter(x => x !== p));
    else setSelectedPlayers([...selectedPlayers, p]);
  };

  const confirmDelete = () => {
     localStorage.removeItem('battleforge_active_tournament');
     setActiveTournament(null);
     setNewTourneyName('');
     setSelectedPlayers([]);
     setShowDeleteModal(false);
     navigate('/tournament', { replace: true, state: {} });
  };

  const startMatch = (m: TournamentMatch) => {
     if (!activeTournament) return;
     if (m.status !== 'ready') return;

     navigate('/', { 
       state: {
         player1: m.player1,
         player2: m.player2,
         tournamentId: activeTournament.id,
         bracketMatchId: m.id
       }
     });
  };

  const renderBracketSection = (title: string, matches: TournamentMatch[]) => {
      // VISUAL FILTER: Hide any match that is a "Bye" match (player2 is BYE) or completed with a BYE winner
      // This serves as a secondary visual layer to ensure clean UI even if pruning missed a spot
      const visibleMatches = matches.filter(m => {
          if (m.player2 === 'BYE') return false;
          if (m.player1 === 'BYE' && m.player2 === null) return false; // Hide waiting bye matches
          if (m.winner === 'BYE') return false;
          return true;
      });

      if (visibleMatches.length === 0) return null;

      const maxRound = Math.max(...visibleMatches.map(m => m.roundIndex), 0);

      return (
        <div className="mb-8">
           <h3 className="text-war-red font-orbitron font-bold uppercase mb-4 sticky left-0">{title}</h3>
           <div className="flex gap-8 min-w-max">
              {Array.from({ length: maxRound + 1 }).map((_, rIdx) => {
                 const roundMatches = visibleMatches.filter(m => m.roundIndex === rIdx);
                 if (roundMatches.length === 0) return null;

                 return (
                   <div key={rIdx} className="flex flex-col justify-around gap-8 w-64">
                      <div className="text-center text-zinc-500 font-orbitron text-xs font-bold uppercase mb-4 bg-black/40 p-1 rounded">
                        Round {rIdx + 1}
                      </div>
                      {roundMatches.map(m => {
                        const isReady = m.status === 'ready';
                        const isComplete = m.status === 'completed';
                        const p1Won = isComplete && m.winner === m.player1;
                        const p2Won = isComplete && m.winner === m.player2;

                        return (
                          <div 
                             key={m.id} 
                             onClick={() => isReady && startMatch(m)}
                             className={`
                               relative p-3 rounded border transition-all 
                               ${isComplete ? 'bg-green-900/10 border-green-900/30' : isReady ? 'bg-war-panel border-war-red cursor-pointer hover:bg-zinc-800 hover:scale-[1.02] shadow-[0_0_10px_rgba(255,45,45,0.2)]' : 'bg-zinc-900 border-zinc-800 opacity-60'}
                             `}
                          >
                             <div className={`text-sm font-bold flex justify-between ${p1Won ? 'text-green-400' : p2Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player1 || 'Waiting...'}</span>
                               {p1Won && <span>✓</span>}
                             </div>
                             <div className="h-px bg-zinc-700 my-2"></div>
                             <div className={`text-sm font-bold flex justify-between ${p2Won ? 'text-green-400' : p1Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player2 || 'Waiting...'}</span>
                               {p2Won && <span>✓</span>}
                             </div>
                          </div>
                        );
                      })}
                   </div>
                 );
              })}
           </div>
        </div>
      );
  };

  return (
    <div className="min-h-screen bg-war-dark pb-20 p-4">
      {/* Delete Confirmation Modal */}
      {showDeleteModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
            <div className="bg-war-panel border border-red-900/50 rounded-lg p-6 max-w-md w-full shadow-[0_0_20px_rgba(255,45,45,0.1)]">
                <h3 className="text-xl font-orbitron font-bold text-white mb-2">Delete Tournament?</h3>
                <p className="text-zinc-400 mb-6 text-sm">
                    Are you sure you want to delete <span className="text-white font-bold">{activeTournament?.name}</span>? 
                    This action cannot be undone and all bracket progress will be lost.
                </p>
                <div className="flex gap-3 justify-end">
                    <Button variant="secondary" onClick={() => setShowDeleteModal(false)} className="text-xs">Cancel</Button>
                    <Button variant="danger" onClick={confirmDelete} className="text-xs bg-red-600 hover:bg-red-700">Yes, Delete It</Button>
                </div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-orbitron font-bold text-war-red">
          TOURNAMENT<span className="text-white">HUB</span>
        </h1>
        <Button variant="secondary" onClick={() => navigate('/')} className="text-xs py-2 px-3">&larr; App</Button>
      </header>

      {!activeTournament ? (
        <div className="bg-war-panel border border-zinc-700 rounded-lg p-6 max-w-2xl mx-auto shadow-xl animate-fade-in">
           <h2 className="text-xl font-orbitron text-white mb-4">Create New Tournament</h2>

           <div className="space-y-4">
             <Input label="Tournament Name" value={newTourneyName} onChange={e => setNewTourneyName(e.target.value)} placeholder="e.g. Summer Slam 2024" />

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Format</label>
               <div className="flex gap-2">
                 <button onClick={() => setTourneyType('single')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'single' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Single Elimination</button>
                 <button onClick={() => setTourneyType('double')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'double' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Double Elimination</button>
               </div>
             </div>

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Participants ({selectedPlayers.length})</label>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-2 bg-zinc-900 p-3 rounded border border-zinc-800 max-h-40 overflow-y-auto">
                 {PLAYERS.map(p => (
                   <button 
                     key={p} 
                     onClick={() => handlePlayerToggle(p)}
                     className={`text-xs p-2 rounded text-left transition-colors ${selectedPlayers.includes(p) ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
                   >
                     {p}
                   </button>
                 ))}
               </div>
             </div>

             <Button onClick={createTournament} className="w-full mt-4">Generate Bracket</Button>
           </div>
        </div>
      ) : (
        <div className="animate-fade-in overflow-x-auto">
           {/* Sticky header updated with z-index and background to ensure clickable buttons */}
           <div className="flex justify-between items-center mb-4 min-w-[600px] sticky left-0 z-10 bg-war-dark p-2 border-b border-zinc-800">
             <div>
               <h2 className="text-2xl font-bold font-orbitron text-white">{activeTournament.name}</h2>
               <div className="text-xs text-zinc-500">Status: {activeTournament.status} | Type: {activeTournament.type}</div>
             </div>
             <Button variant="danger" onClick={() => setShowDeleteModal(true)} className="text-xs py-1 px-3 bg-red-800 hover:bg-red-700 text-white border-red-900 shadow-lg">Delete Tournament</Button>
           </div>

           {/* Render Brackets Split by Type */}
           {activeTournament.type === 'single' ? (
              renderBracketSection("Bracket", activeTournament.matches)
           ) : (
              <div>
                {renderBracketSection("Winners Bracket", activeTournament.matches.filter(m => m.bracketType === 'winner'))}
                {renderBracketSection("Losers Bracket", activeTournament.matches.filter(m => m.bracketType === 'loser'))}
                {renderBracketSection("Finals", activeTournament.matches.filter(m => m.bracketType === 'final'))}
              </div>
           )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { PLAYERS } from '../constants';
import { Tournament, TournamentMatch } from '../types';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';

export const TournamentHub: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [activeTournament, setActiveTournament] = useState<Tournament | null>(null);
  const [newTourneyName, setNewTourneyName] = useState('');
  const [selectedPlayers, setSelectedPlayers] = useState<string[]>([]);
  const [tourneyType, setTourneyType] = useState<'single' | 'double'>('single');
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  // Load active tournament
  useEffect(() => {
    const saved = localStorage.getItem('battleforge_active_tournament');
    if (saved) {
      const tourney = JSON.parse(saved);
      // We don't auto-prune on load anymore to prevent shifting state unexpectedly, 
      // relying on correct generation instead.
      setActiveTournament(tourney);
    }
  }, []);

  // Handle return from MatchLogger with results
  useEffect(() => {
    if (location.state && location.state.completedMatchId && location.state.winner) {
      const { completedMatchId, winner } = location.state;

      navigate(location.pathname, { replace: true, state: {} });

      if (activeTournament) {
        handleMatchCompletion(completedMatchId, winner);
      }
    }
  }, [location.state, activeTournament, navigate, location.pathname]);

  // --- Core Logic: Advance Players ---

  const advancePlayerToMatch = (matches: TournamentMatch[], targetId: string, player: string): boolean => {
    const target = matches.find(m => m.id === targetId);
    if (!target) return false;

    // Idempotency check
    if (target.player1 === player || target.player2 === player) return false;

    let changed = false;

    // Fill empty slot
    if (!target.player1) {
       target.player1 = player;
       changed = true;
    } else if (!target.player2) {
       target.player2 = player;
       changed = true;
    }

    if (changed) {
        if (target.player1 && target.player2) {
            target.status = 'ready';
        } else {
            target.status = 'pending';
        }
    }

    return changed;
  };

  const settleBracket = (matches: TournamentMatch[]) => {
    let changed = true;
    let iterations = 0;
    while(changed && iterations < 50) {
      changed = false;
      iterations++;

      matches.forEach(m => {
         // RULE 1: Auto-resolve pending/ready matches
         if (m.status !== 'completed') {
             const p1 = m.player1;
             const p2 = m.player2;

             if (p1 && p2) {
                 // 1a. Handle BYE (Auto-Win)
                 if (p1 === 'BYE' || p2 === 'BYE') {
                     // If both are BYE, technically it's a BYE win, but pruning should handle removal.
                     // If one is player, player wins.
                     m.winner = p1 === 'BYE' ? p2 : p1;
                     m.status = 'completed';
                     changed = true; 
                 } 
                 // 1b. Handle Initial Pending -> Ready
                 else if (m.status === 'pending') {
                     m.status = 'ready';
                     changed = true;
                 }
             }
         }

         // RULE 2: Propagate Completed Matches
         if (m.status === 'completed' && m.winner) {
             // Advance Winner
             if (m.nextMatchId) {
                if (advancePlayerToMatch(matches, m.nextMatchId, m.winner)) changed = true;
             }
             // Advance Loser (Double Elim)
             if (m.loserNextMatchId && m.player1 && m.player2) {
                const loser = m.winner === m.player1 ? m.player2 : m.player1;
                if (loser && advancePlayerToMatch(matches, m.loserNextMatchId, loser)) changed = true;
             }
         }
      });
    }
  };

  const handleMatchCompletion = (matchId: string, winner: string | null) => {
    if (!activeTournament || !winner) return;

    const newMatches = JSON.parse(JSON.stringify(activeTournament.matches)); 
    const match = newMatches.find((m: TournamentMatch) => m.id === matchId);

    if (match && match.status === 'completed' && match.winner === winner) return;

    if (match) {
        match.winner = winner;
        match.status = 'completed';

        settleBracket(newMatches);

        const updatedTourney = { ...activeTournament, matches: newMatches };
        setActiveTournament(updatedTourney);
        localStorage.setItem('battleforge_active_tournament', JSON.stringify(updatedTourney));
    }
  };

  // --- Pruning Logic ---
  const pruneBracket = (matches: TournamentMatch[]) => {
    let activeMatches = [...matches];
    let changed = true;
    let iterations = 0;

    // Safety loop to cascade byes
    while(changed && iterations < 20) {
        changed = false;
        iterations++;
        const toRemove: string[] = [];

        // Sort by round to process R0 first
        activeMatches.sort((a,b) => a.roundIndex - b.roundIndex);

        for(const m of activeMatches) {
            // ONLY remove matches if BOTH are BYE.
            // We want to KEEP matches where a Player fights a BYE, so they show in the bracket as a free win.
            if (m.player1 === 'BYE' && m.player2 === 'BYE') {
                toRemove.push(m.id);
                changed = true;

                // Propagate "BYE" as the winner to the next bracket
                // This ensures the next match receives a BYE opponent and can auto-resolve or prune
                if (m.nextMatchId) {
                    const nextM = activeMatches.find(x => x.id === m.nextMatchId);
                    if (nextM) {
                        if (!nextM.player1) nextM.player1 = 'BYE';
                        else if (!nextM.player2) nextM.player2 = 'BYE';
                    }
                }

                // Propagate "BYE" as loser
                if (m.loserNextMatchId) {
                     const loserM = activeMatches.find(x => x.id === m.loserNextMatchId);
                     if (loserM) {
                        if (!loserM.player1) loserM.player1 = 'BYE';
                        else if (!loserM.player2) loserM.player2 = 'BYE';
                     }
                }
            }
            // For Player vs BYE, settleBracket will handle the auto-win/completion logic. 
            // We do NOT remove them here.
        }

        if (toRemove.length > 0) {
            activeMatches = activeMatches.filter(m => !toRemove.includes(m.id));
        }
    }
    return activeMatches;
  };

  // --- Generators ---

  // Generates a FULL power-of-2 bracket (including BYE matches)
  const generateFullSingleElim = (participants: string[], idOffset = 0): { matches: TournamentMatch[], rounds: number, nextId: number } => {
     const shuffled = [...participants].sort(() => 0.5 - Math.random());
     let size = 2;
     while(size < shuffled.length) size *= 2;

     // Fill with BYEs
     const seeded = [...shuffled];
     while(seeded.length < size) seeded.push("BYE");

     // Pair adjacent (Standard pairing: 0v1, 2v3...)
     // This concentrates players in early matches and BYEs in later matches
     const r1Pairs: {p1: string, p2: string}[] = [];
     for(let i=0; i<size; i+=2) {
         r1Pairs.push({ p1: seeded[i], p2: seeded[i+1] });
     }

     const matches: TournamentMatch[] = [];
     let matchIdCounter = idOffset + 1;
     const getId = () => `m_${matchIdCounter++}`;

     // Round 1
     const round1Ids: string[] = [];

     r1Pairs.forEach(pair => {
        const id = getId();
        round1Ids.push(id);
        matches.push({
          id,
          roundIndex: 0,
          bracketType: 'winner',
          player1: pair.p1,
          player2: pair.p2,
          winner: null,
          status: 'pending' 
        });
     });

     // Subsequent Rounds
     let currentIds = round1Ids;
     let rIdx = 1;
     while(currentIds.length > 1) {
       const nextIds: string[] = [];
       for(let i=0; i<currentIds.length; i+=2) {
         const id = getId();
         nextIds.push(id);

         const m1 = matches.find(m => m.id === currentIds[i]);
         const m2 = matches.find(m => m.id === currentIds[i+1]);
         if(m1) m1.nextMatchId = id;
         if(m2) m2.nextMatchId = id;

         matches.push({
           id,
           roundIndex: rIdx,
           bracketType: 'winner',
           player1: null,
           player2: null,
           winner: null,
           status: 'pending'
         });
       }
       currentIds = nextIds;
       rIdx++;
     }

     return { matches, rounds: rIdx, nextId: matchIdCounter };
  };

  const generateDoubleElim = (participants: string[]): { matches: TournamentMatch[], rounds: number } => {
    // 1. Generate FULL Winner Bracket
    const { matches: wbMatches, rounds: wbRounds, nextId } = generateFullSingleElim(participants);
    const matches = [...wbMatches];

    // Group WB matches by round
    const wbByRound: Record<number, TournamentMatch[]> = {};
    matches.forEach(m => {
      if(!wbByRound[m.roundIndex]) wbByRound[m.roundIndex] = [];
      wbByRound[m.roundIndex].push(m);
    });

    let matchIdCounter = nextId + 1000;
    const getId = () => `m_${matchIdCounter++}`;

    const lbMatches: TournamentMatch[] = [];
    let prevLBRoundMatches: TournamentMatch[] = [];

    // --- LB Round 0: Consumes WB Round 0 Losers ---
    const wbR0 = wbByRound[0];
    const lbR0Count = wbR0.length / 2;

    for (let i = 0; i < lbR0Count; i++) {
        const m: TournamentMatch = { 
            id: getId(), 
            roundIndex: 0, 
            bracketType: 'loser', 
            player1: null, 
            player2: null, 
            winner: null, 
            status: 'pending' 
        };
        lbMatches.push(m);
        prevLBRoundMatches.push(m);

        wbR0[i*2].loserNextMatchId = m.id;
        wbR0[i*2+1].loserNextMatchId = m.id;
    }

    let lbRoundIndex = 1;

    // --- Feed Remaining WB Rounds ---
    for (let i = 1; i < wbRounds; i++) {
        const wbRoundMatches = wbByRound[i]; 

        // Injection Round
        const injectionMatches: TournamentMatch[] = [];
        for (let j = 0; j < wbRoundMatches.length; j++) {
            const m: TournamentMatch = {
                id: getId(),
                roundIndex: lbRoundIndex,
                bracketType: 'loser',
                player1: null,
                player2: null,
                winner: null,
                status: 'pending'
            };
            injectionMatches.push(m);
            lbMatches.push(m);

            if (prevLBRoundMatches[j]) prevLBRoundMatches[j].nextMatchId = m.id;
            wbRoundMatches[j].loserNextMatchId = m.id;
        }

        prevLBRoundMatches = injectionMatches;
        lbRoundIndex++;

        // Reduction Round
        if (prevLBRoundMatches.length > 1) {
            const reductionMatches: TournamentMatch[] = [];
            for (let j = 0; j < prevLBRoundMatches.length; j += 2) {
                const m: TournamentMatch = {
                    id: getId(),
                    roundIndex: lbRoundIndex,
                    bracketType: 'loser',
                    player1: null, 
                    player2: null,
                    winner: null, 
                    status: 'pending'
                };
                reductionMatches.push(m);
                lbMatches.push(m);

                prevLBRoundMatches[j].nextMatchId = m.id;
                prevLBRoundMatches[j+1].nextMatchId = m.id;
            }
            prevLBRoundMatches = reductionMatches;
            lbRoundIndex++;
        }
    }

    // --- Grand Final ---
    const grandFinal: TournamentMatch = {
        id: getId(),
        roundIndex: 0,
        bracketType: 'final',
        player1: null,
        player2: null,
        winner: null,
        status: 'pending'
    };
    matches.push(grandFinal);

    const wbFinal = wbByRound[wbRounds-1][0];
    wbFinal.nextMatchId = grandFinal.id;

    if (prevLBRoundMatches[0]) {
        prevLBRoundMatches[0].nextMatchId = grandFinal.id;
    }

    matches.push(...lbMatches);

    // Now Prune ONLY the Ghost Matches (Bye vs Bye)
    const prunedMatches = pruneBracket(matches);

    return { matches: prunedMatches, rounds: lbRoundIndex };
  };

  const createTournament = () => {
    if (!newTourneyName || selectedPlayers.length < 2) {
      alert("Enter name and select at least 2 players.");
      return;
    }

    let result;
    if (tourneyType === 'double') {
      result = generateDoubleElim(selectedPlayers);
    } else {
      // Generate full tree then prune for Single Elim too
      const full = generateFullSingleElim(selectedPlayers);
      const pruned = pruneBracket(full.matches);
      result = { matches: pruned, rounds: full.rounds };
    }

    // Final settle to set ready states
    settleBracket(result.matches);

    const newTourney: Tournament = {
      id: newTourneyName.replace(/\s+/g, '') + '_' + Date.now(),
      name: newTourneyName,
      type: tourneyType,
      participants: selectedPlayers,
      matches: result.matches,
      rounds: result.rounds,
      status: 'active',
      dateCreated: new Date().toISOString()
    };

    setActiveTournament(newTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(newTourney));
  };

  const handlePlayerToggle = (p: string) => {
    if (selectedPlayers.includes(p)) setSelectedPlayers(selectedPlayers.filter(x => x !== p));
    else setSelectedPlayers([...selectedPlayers, p]);
  };

  const confirmDelete = () => {
     localStorage.removeItem('battleforge_active_tournament');
     setActiveTournament(null);
     setNewTourneyName('');
     setSelectedPlayers([]);
     setShowDeleteModal(false);
     navigate('/tournament', { replace: true, state: {} });
  };

  const startMatch = (m: TournamentMatch) => {
     if (!activeTournament) return;
     if (m.status !== 'ready') return;

     navigate('/', { 
       state: {
         player1: m.player1,
         player2: m.player2,
         tournamentId: activeTournament.id,
         bracketMatchId: m.id
       }
     });
  };

  const renderBracketSection = (title: string, matches: TournamentMatch[]) => {
      // VISUAL FILTER: Only hide matches that are purely Ghost Matches (Bye vs Bye)
      // Matches where a player fights a BYE should be SHOWN so the user sees the free win.
      const visibleMatches = matches.filter(m => {
          if (m.player1 === 'BYE' && m.player2 === 'BYE') return false;
          // Hide waiting matches that are ghost-candidates (e.g. Bye vs null) - though prune should handle most
          if (m.player1 === 'BYE' && m.player2 === null) return false;
          return true;
      });

      if (visibleMatches.length === 0) return null;

      const maxRound = Math.max(...visibleMatches.map(m => m.roundIndex), 0);

      return (
        <div className="mb-8">
           <h3 className="text-war-red font-orbitron font-bold uppercase mb-4 sticky left-0">{title}</h3>
           <div className="flex gap-8 min-w-max">
              {Array.from({ length: maxRound + 1 }).map((_, rIdx) => {
                 const roundMatches = visibleMatches.filter(m => m.roundIndex === rIdx);
                 if (roundMatches.length === 0) return null;

                 return (
                   <div key={rIdx} className="flex flex-col justify-around gap-8 w-64">
                      <div className="text-center text-zinc-500 font-orbitron text-xs font-bold uppercase mb-4 bg-black/40 p-1 rounded">
                        Round {rIdx + 1}
                      </div>
                      {roundMatches.map(m => {
                        const isReady = m.status === 'ready';
                        const isComplete = m.status === 'completed';
                        const p1Won = isComplete && m.winner === m.player1;
                        const p2Won = isComplete && m.winner === m.player2;

                        return (
                          <div 
                             key={m.id} 
                             onClick={() => isReady && startMatch(m)}
                             className={`
                               relative p-3 rounded border transition-all 
                               ${isComplete ? 'bg-green-900/10 border-green-900/30' : isReady ? 'bg-war-panel border-war-red cursor-pointer hover:bg-zinc-800 hover:scale-[1.02] shadow-[0_0_10px_rgba(255,45,45,0.2)]' : 'bg-zinc-900 border-zinc-800 opacity-60'}
                             `}
                          >
                             <div className={`text-sm font-bold flex justify-between ${p1Won ? 'text-green-400' : p2Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player1 || 'Waiting...'}</span>
                               {p1Won && <span>✓</span>}
                             </div>
                             <div className="h-px bg-zinc-700 my-2"></div>
                             <div className={`text-sm font-bold flex justify-between ${p2Won ? 'text-green-400' : p1Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player2 || 'Waiting...'}</span>
                               {p2Won && <span>✓</span>}
                             </div>
                          </div>
                        );
                      })}
                   </div>
                 );
              })}
           </div>
        </div>
      );
  };

  return (
    <div className="min-h-screen bg-war-dark pb-20 p-4">
      {/* Delete Confirmation Modal */}
      {showDeleteModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
            <div className="bg-war-panel border border-red-900/50 rounded-lg p-6 max-w-md w-full shadow-[0_0_20px_rgba(255,45,45,0.1)]">
                <h3 className="text-xl font-orbitron font-bold text-white mb-2">Delete Tournament?</h3>
                <p className="text-zinc-400 mb-6 text-sm">
                    Are you sure you want to delete <span className="text-white font-bold">{activeTournament?.name}</span>? 
                    This action cannot be undone and all bracket progress will be lost.
                </p>
                <div className="flex gap-3 justify-end">
                    <Button variant="secondary" onClick={() => setShowDeleteModal(false)} className="text-xs">Cancel</Button>
                    <Button variant="danger" onClick={confirmDelete} className="text-xs bg-red-600 hover:bg-red-700">Yes, Delete It</Button>
                </div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-orbitron font-bold text-war-red">
          TOURNAMENT<span className="text-white">HUB</span>
        </h1>
        <Button variant="secondary" onClick={() => navigate('/')} className="text-xs py-2 px-3">&larr; App</Button>
      </header>

      {!activeTournament ? (
        <div className="bg-war-panel border border-zinc-700 rounded-lg p-6 max-w-2xl mx-auto shadow-xl animate-fade-in">
           <h2 className="text-xl font-orbitron text-white mb-4">Create New Tournament</h2>

           <div className="space-y-4">
             <Input label="Tournament Name" value={newTourneyName} onChange={e => setNewTourneyName(e.target.value)} placeholder="e.g. Summer Slam 2024" />

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Format</label>
               <div className="flex gap-2">
                 <button onClick={() => setTourneyType('single')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'single' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Single Elimination</button>
                 <button onClick={() => setTourneyType('double')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'double' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Double Elimination</button>
               </div>
             </div>

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Participants ({selectedPlayers.length})</label>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-2 bg-zinc-900 p-3 rounded border border-zinc-800 max-h-40 overflow-y-auto">
                 {PLAYERS.map(p => (
                   <button 
                     key={p} 
                     onClick={() => handlePlayerToggle(p)}
                     className={`text-xs p-2 rounded text-left transition-colors ${selectedPlayers.includes(p) ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
                   >
                     {p}
                   </button>
                 ))}
               </div>
             </div>

             <Button onClick={createTournament} className="w-full mt-4">Generate Bracket</Button>
           </div>
        </div>
      ) : (
        <div className="animate-fade-in overflow-x-auto">
           {/* Sticky header updated with z-index and background to ensure clickable buttons */}
           <div className="flex justify-between items-center mb-4 min-w-[600px] sticky left-0 z-10 bg-war-dark p-2 border-b border-zinc-800">
             <div>
               <h2 className="text-2xl font-bold font-orbitron text-white">{activeTournament.name}</h2>
               <div className="text-xs text-zinc-500">Status: {activeTournament.status} | Type: {activeTournament.type}</div>
             </div>
             <Button variant="danger" onClick={() => setShowDeleteModal(true)} className="text-xs py-1 px-3 bg-red-800 hover:bg-red-700 text-white border-red-900 shadow-lg">Delete Tournament</Button>
           </div>

           {/* Render Brackets Split by Type */}
           {activeTournament.type === 'single' ? (
              renderBracketSection("Bracket", activeTournament.matches)
           ) : (
              <div>
                {renderBracketSection("Winners Bracket", activeTournament.matches.filter(m => m.bracketType === 'winner'))}
                {renderBracketSection("Losers Bracket", activeTournament.matches.filter(m => m.bracketType === 'loser'))}
                {renderBracketSection("Finals", activeTournament.matches.filter(m => m.bracketType === 'final'))}
              </div>
           )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { PLAYERS } from '../constants';
import { Tournament, TournamentMatch } from '../types';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';

export const TournamentHub: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [activeTournament, setActiveTournament] = useState<Tournament | null>(null);
  const [newTourneyName, setNewTourneyName] = useState('');
  const [selectedPlayers, setSelectedPlayers] = useState<string[]>([]);
  const [tourneyType, setTourneyType] = useState<'single' | 'double'>('single');
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  // Load active tournament
  useEffect(() => {
    const saved = localStorage.getItem('battleforge_active_tournament');
    if (saved) {
      const tourney = JSON.parse(saved);
      setActiveTournament(tourney);
    }
  }, []);

  // Handle return from MatchLogger with results
  useEffect(() => {
    if (location.state && location.state.completedMatchId && location.state.winner) {
      const { completedMatchId, winner } = location.state;

      navigate(location.pathname, { replace: true, state: {} });

      if (activeTournament) {
        handleMatchCompletion(completedMatchId, winner);
      }
    }
  }, [location.state, activeTournament, navigate, location.pathname]);

  // --- Core Logic: Advance Players ---

  const advancePlayerToMatch = (matches: TournamentMatch[], targetId: string, player: string): boolean => {
    const target = matches.find(m => m.id === targetId);
    if (!target) return false;

    // Idempotency check
    if (target.player1 === player || target.player2 === player) return false;

    let changed = false;

    // Fill empty slot
    if (!target.player1) {
       target.player1 = player;
       changed = true;
    } else if (!target.player2) {
       target.player2 = player;
       changed = true;
    }

    if (changed) {
        if (target.player1 && target.player2) {
            target.status = 'ready';
        } else {
            target.status = 'pending';
        }
    }

    return changed;
  };

  const settleBracket = (matches: TournamentMatch[]) => {
    let changed = true;
    let iterations = 0;
    while(changed && iterations < 50) {
      changed = false;
      iterations++;

      matches.forEach(m => {
         // RULE 1: Auto-resolve pending/ready matches
         if (m.status !== 'completed') {
             const p1 = m.player1;
             const p2 = m.player2;

             if (p1 && p2) {
                 // 1a. Handle BYE (Auto-Win)
                 if (p1 === 'BYE' || p2 === 'BYE') {
                     // If both are BYE, technically it's a BYE win.
                     m.winner = p1 === 'BYE' ? p2 : p1;
                     m.status = 'completed';
                     changed = true; 
                 } 
                 // 1b. Handle Initial Pending -> Ready
                 else if (m.status === 'pending') {
                     m.status = 'ready';
                     changed = true;
                 }
             }
         }

         // RULE 2: Propagate Completed Matches
         if (m.status === 'completed' && m.winner) {
             // Advance Winner
             if (m.nextMatchId) {
                if (advancePlayerToMatch(matches, m.nextMatchId, m.winner)) changed = true;
             }
             // Advance Loser (Double Elim)
             if (m.loserNextMatchId && m.player1 && m.player2) {
                const loser = m.winner === m.player1 ? m.player2 : m.player1;
                if (loser && advancePlayerToMatch(matches, m.loserNextMatchId, loser)) changed = true;
             }
         }
      });
    }
  };

  const handleMatchCompletion = (matchId: string, winner: string | null) => {
    if (!activeTournament || !winner) return;

    const newMatches = JSON.parse(JSON.stringify(activeTournament.matches)); 
    const match = newMatches.find((m: TournamentMatch) => m.id === matchId);

    if (match && match.status === 'completed' && match.winner === winner) return;

    if (match) {
        match.winner = winner;
        match.status = 'completed';

        // Run settle to propagate winner
        settleBracket(newMatches);

        // Run prune to clean up any new "Player vs BYE" situations (e.g. in Loser Bracket)
        const pruned = pruneBracket(newMatches);

        // Run settle again to ensure new structure is ready
        settleBracket(pruned);

        const updatedTourney = { ...activeTournament, matches: pruned };
        setActiveTournament(updatedTourney);
        localStorage.setItem('battleforge_active_tournament', JSON.stringify(updatedTourney));
    }
  };

  // --- Pruning Logic ---
  const pruneBracket = (matches: TournamentMatch[]) => {
    let activeMatches = [...matches];
    let changed = true;
    let iterations = 0;

    // Safety loop to cascade byes
    while(changed && iterations < 20) {
        changed = false;
        iterations++;
        const toRemove: string[] = [];

        // Sort by round to process R0 first
        activeMatches.sort((a,b) => a.roundIndex - b.roundIndex);

        for(const m of activeMatches) {
            let winner: string | null = null;
            let loser: string | null = null;

            // Bypass logic: Keep "Player vs BYE" ONLY in Winner Bracket Round 0
            const isWbR0 = m.bracketType === 'winner' && m.roundIndex === 0;

            // 1. P1 vs BYE
            if (m.player1 && m.player1 !== 'BYE' && m.player2 === 'BYE') {
                if (!isWbR0) {
                   winner = m.player1;
                   loser = 'BYE';
                }
            } 
            // 2. BYE vs P2
            else if (m.player1 === 'BYE' && m.player2 && m.player2 !== 'BYE') {
                 if (!isWbR0) {
                    winner = m.player2;
                    loser = 'BYE';
                 }
            } 
            // 3. BYE vs BYE (Always remove)
            else if (m.player1 === 'BYE' && m.player2 === 'BYE') {
                winner = 'BYE';
                loser = 'BYE';
            }

            if (winner) {
                toRemove.push(m.id);
                changed = true;

                // Propagate Winner
                if (m.nextMatchId) {
                    const nextM = activeMatches.find(x => x.id === m.nextMatchId);
                    if (nextM) {
                        if (!nextM.player1) nextM.player1 = winner;
                        else if (!nextM.player2) nextM.player2 = winner;
                    }
                }

                // Propagate Loser
                if (m.loserNextMatchId) {
                     const loserM = activeMatches.find(x => x.id === m.loserNextMatchId);
                     if (loserM) {
                        if (!loserM.player1) loserM.player1 = loser;
                        else if (!loserM.player2) loserM.player2 = loser;
                     }
                }
            }
        }

        if (toRemove.length > 0) {
            activeMatches = activeMatches.filter(m => !toRemove.includes(m.id));
        }
    }
    return activeMatches;
  };

  // --- Generators ---

  // Generates a FULL power-of-2 bracket (including BYE matches)
  const generateFullSingleElim = (participants: string[], idOffset = 0): { matches: TournamentMatch[], rounds: number, nextId: number } => {
     const shuffled = [...participants].sort(() => 0.5 - Math.random());
     let size = 2;
     while(size < shuffled.length) size *= 2;

     // Fill with BYEs
     const seeded = [...shuffled];
     while(seeded.length < size) seeded.push("BYE");

     // Pair adjacent
     const r1Pairs: {p1: string, p2: string}[] = [];
     for(let i=0; i<size; i+=2) {
         r1Pairs.push({ p1: seeded[i], p2: seeded[i+1] });
     }

     const matches: TournamentMatch[] = [];
     let matchIdCounter = idOffset + 1;
     const getId = () => `m_${matchIdCounter++}`;

     // Round 1
     const round1Ids: string[] = [];

     r1Pairs.forEach(pair => {
        const id = getId();
        round1Ids.push(id);
        matches.push({
          id,
          roundIndex: 0,
          bracketType: 'winner',
          player1: pair.p1,
          player2: pair.p2,
          winner: null,
          status: 'pending' 
        });
     });

     // Subsequent Rounds
     let currentIds = round1Ids;
     let rIdx = 1;
     while(currentIds.length > 1) {
       const nextIds: string[] = [];
       for(let i=0; i<currentIds.length; i+=2) {
         const id = getId();
         nextIds.push(id);

         const m1 = matches.find(m => m.id === currentIds[i]);
         const m2 = matches.find(m => m.id === currentIds[i+1]);
         if(m1) m1.nextMatchId = id;
         if(m2) m2.nextMatchId = id;

         matches.push({
           id,
           roundIndex: rIdx,
           bracketType: 'winner',
           player1: null,
           player2: null,
           winner: null,
           status: 'pending'
         });
       }
       currentIds = nextIds;
       rIdx++;
     }

     return { matches, rounds: rIdx, nextId: matchIdCounter };
  };

  const generateDoubleElim = (participants: string[]): { matches: TournamentMatch[], rounds: number } => {
    // 1. Generate FULL Winner Bracket
    const { matches: wbMatches, rounds: wbRounds, nextId } = generateFullSingleElim(participants);
    const matches = [...wbMatches];

    // Group WB matches by round
    const wbByRound: Record<number, TournamentMatch[]> = {};
    matches.forEach(m => {
      if(!wbByRound[m.roundIndex]) wbByRound[m.roundIndex] = [];
      wbByRound[m.roundIndex].push(m);
    });

    let matchIdCounter = nextId + 1000;
    const getId = () => `m_${matchIdCounter++}`;

    const lbMatches: TournamentMatch[] = [];
    let prevLBRoundMatches: TournamentMatch[] = [];

    // --- LB Round 0: Consumes WB Round 0 Losers ---
    const wbR0 = wbByRound[0];
    const lbR0Count = wbR0.length / 2;

    for (let i = 0; i < lbR0Count; i++) {
        const m: TournamentMatch = { 
            id: getId(), 
            roundIndex: 0, 
            bracketType: 'loser', 
            player1: null, 
            player2: null, 
            winner: null, 
            status: 'pending' 
        };
        lbMatches.push(m);
        prevLBRoundMatches.push(m);

        wbR0[i*2].loserNextMatchId = m.id;
        wbR0[i*2+1].loserNextMatchId = m.id;
    }

    let lbRoundIndex = 1;

    // --- Feed Remaining WB Rounds ---
    for (let i = 1; i < wbRounds; i++) {
        const wbRoundMatches = wbByRound[i]; 

        // Injection Round
        const injectionMatches: TournamentMatch[] = [];
        for (let j = 0; j < wbRoundMatches.length; j++) {
            const m: TournamentMatch = {
                id: getId(),
                roundIndex: lbRoundIndex,
                bracketType: 'loser',
                player1: null,
                player2: null,
                winner: null,
                status: 'pending'
            };
            injectionMatches.push(m);
            lbMatches.push(m);

            if (prevLBRoundMatches[j]) prevLBRoundMatches[j].nextMatchId = m.id;
            wbRoundMatches[j].loserNextMatchId = m.id;
        }

        prevLBRoundMatches = injectionMatches;
        lbRoundIndex++;

        // Reduction Round
        if (prevLBRoundMatches.length > 1) {
            const reductionMatches: TournamentMatch[] = [];
            for (let j = 0; j < prevLBRoundMatches.length; j += 2) {
                const m: TournamentMatch = {
                    id: getId(),
                    roundIndex: lbRoundIndex,
                    bracketType: 'loser',
                    player1: null, 
                    player2: null,
                    winner: null, 
                    status: 'pending'
                };
                reductionMatches.push(m);
                lbMatches.push(m);

                prevLBRoundMatches[j].nextMatchId = m.id;
                prevLBRoundMatches[j+1].nextMatchId = m.id;
            }
            prevLBRoundMatches = reductionMatches;
            lbRoundIndex++;
        }
    }

    // --- Grand Final ---
    const grandFinal: TournamentMatch = {
        id: getId(),
        roundIndex: 0,
        bracketType: 'final',
        player1: null,
        player2: null,
        winner: null,
        status: 'pending'
    };
    matches.push(grandFinal);

    const wbFinal = wbByRound[wbRounds-1][0];
    wbFinal.nextMatchId = grandFinal.id;

    if (prevLBRoundMatches[0]) {
        prevLBRoundMatches[0].nextMatchId = grandFinal.id;
    }

    matches.push(...lbMatches);

    return { matches, rounds: lbRoundIndex };
  };

  const createTournament = () => {
    if (!newTourneyName || selectedPlayers.length < 2) {
      alert("Enter name and select at least 2 players.");
      return;
    }

    let result;
    if (tourneyType === 'double') {
      result = generateDoubleElim(selectedPlayers);
    } else {
      const full = generateFullSingleElim(selectedPlayers);
      result = { matches: full.matches, rounds: full.rounds };
    }

    let matches = result.matches;

    // PASS 1: Prune initial ghosts (Bye vs Bye)
    matches = pruneBracket(matches);

    // PASS 2: Settle initial BYE results (WB Player vs Bye auto-wins)
    // This propagates BYE losers to LB
    settleBracket(matches);

    // PASS 3: Prune again (Clean up LB matches that became Player vs Bye)
    matches = pruneBracket(matches);

    // PASS 4: Final settle
    settleBracket(matches);

    const newTourney: Tournament = {
      id: newTourneyName.replace(/\s+/g, '') + '_' + Date.now(),
      name: newTourneyName,
      type: tourneyType,
      participants: selectedPlayers,
      matches: matches,
      rounds: result.rounds,
      status: 'active',
      dateCreated: new Date().toISOString()
    };

    setActiveTournament(newTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(newTourney));
  };

  const handlePlayerToggle = (p: string) => {
    if (selectedPlayers.includes(p)) setSelectedPlayers(selectedPlayers.filter(x => x !== p));
    else setSelectedPlayers([...selectedPlayers, p]);
  };

  const confirmDelete = () => {
     localStorage.removeItem('battleforge_active_tournament');
     setActiveTournament(null);
     setNewTourneyName('');
     setSelectedPlayers([]);
     setShowDeleteModal(false);
     navigate('/tournament', { replace: true, state: {} });
  };

  const startMatch = (m: TournamentMatch) => {
     if (!activeTournament) return;
     if (m.status !== 'ready') return;

     navigate('/', { 
       state: {
         player1: m.player1,
         player2: m.player2,
         tournamentId: activeTournament.id,
         bracketMatchId: m.id
       }
     });
  };

  const renderBracketSection = (title: string, matches: TournamentMatch[]) => {
      // VISUAL FILTER: Only hide matches that are purely Ghost Matches (Bye vs Bye)
      // or "Waiting" matches that are destined to be Byes (optional, but pruning handles most)
      const visibleMatches = matches.filter(m => {
          if (m.player1 === 'BYE' && m.player2 === 'BYE') return false;
          return true;
      });

      if (visibleMatches.length === 0) return null;

      // Dynamic Rounds: Find which rounds actually have matches left after pruning
      const activeRounds = Array.from(new Set(visibleMatches.map(m => m.roundIndex))).sort((a,b) => a-b);

      return (
        <div className="mb-8">
           <h3 className="text-war-red font-orbitron font-bold uppercase mb-4 sticky left-0">{title}</h3>
           <div className="flex gap-8 min-w-max">
              {activeRounds.map((roundIdx, displayIdx) => {
                 const roundMatches = visibleMatches.filter(m => m.roundIndex === roundIdx);

                 return (
                   <div key={roundIdx} className="flex flex-col justify-around gap-8 w-64">
                      <div className="text-center text-zinc-500 font-orbitron text-xs font-bold uppercase mb-4 bg-black/40 p-1 rounded">
                        Round {displayIdx + 1}
                      </div>
                      {roundMatches.map(m => {
                        const isReady = m.status === 'ready';
                        const isComplete = m.status === 'completed';
                        const p1Won = isComplete && m.winner === m.player1;
                        const p2Won = isComplete && m.winner === m.player2;

                        return (
                          <div 
                             key={m.id} 
                             onClick={() => isReady && startMatch(m)}
                             className={`
                               relative p-3 rounded border transition-all 
                               ${isComplete ? 'bg-green-900/10 border-green-900/30' : isReady ? 'bg-war-panel border-war-red cursor-pointer hover:bg-zinc-800 hover:scale-[1.02] shadow-[0_0_10px_rgba(255,45,45,0.2)]' : 'bg-zinc-900 border-zinc-800 opacity-60'}
                             `}
                          >
                             <div className={`text-sm font-bold flex justify-between ${p1Won ? 'text-green-400' : p2Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player1 || 'Waiting...'}</span>
                               {p1Won && <span>✓</span>}
                             </div>
                             <div className="h-px bg-zinc-700 my-2"></div>
                             <div className={`text-sm font-bold flex justify-between ${p2Won ? 'text-green-400' : p1Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player2 || 'Waiting...'}</span>
                               {p2Won && <span>✓</span>}
                             </div>
                          </div>
                        );
                      })}
                   </div>
                 );
              })}
           </div>
        </div>
      );
  };

  return (
    <div className="min-h-screen bg-war-dark pb-20 p-4">
      {/* Delete Confirmation Modal */}
      {showDeleteModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
            <div className="bg-war-panel border border-red-900/50 rounded-lg p-6 max-w-md w-full shadow-[0_0_20px_rgba(255,45,45,0.1)]">
                <h3 className="text-xl font-orbitron font-bold text-white mb-2">Delete Tournament?</h3>
                <p className="text-zinc-400 mb-6 text-sm">
                    Are you sure you want to delete <span className="text-white font-bold">{activeTournament?.name}</span>? 
                    This action cannot be undone and all bracket progress will be lost.
                </p>
                <div className="flex gap-3 justify-end">
                    <Button variant="secondary" onClick={() => setShowDeleteModal(false)} className="text-xs">Cancel</Button>
                    <Button variant="danger" onClick={confirmDelete} className="text-xs bg-red-600 hover:bg-red-700">Yes, Delete It</Button>
                </div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-orbitron font-bold text-war-red">
          TOURNAMENT<span className="text-white">HUB</span>
        </h1>
        <Button variant="secondary" onClick={() => navigate('/')} className="text-xs py-2 px-3">&larr; App</Button>
      </header>

      {!activeTournament ? (
        <div className="bg-war-panel border border-zinc-700 rounded-lg p-6 max-w-2xl mx-auto shadow-xl animate-fade-in">
           <h2 className="text-xl font-orbitron text-white mb-4">Create New Tournament</h2>

           <div className="space-y-4">
             <Input label="Tournament Name" value={newTourneyName} onChange={e => setNewTourneyName(e.target.value)} placeholder="e.g. Summer Slam 2024" />

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Format</label>
               <div className="flex gap-2">
                 <button onClick={() => setTourneyType('single')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'single' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Single Elimination</button>
                 <button onClick={() => setTourneyType('double')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'double' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Double Elimination</button>
               </div>
             </div>

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Participants ({selectedPlayers.length})</label>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-2 bg-zinc-900 p-3 rounded border border-zinc-800 max-h-40 overflow-y-auto">
                 {PLAYERS.map(p => (
                   <button 
                     key={p} 
                     onClick={() => handlePlayerToggle(p)}
                     className={`text-xs p-2 rounded text-left transition-colors ${selectedPlayers.includes(p) ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
                   >
                     {p}
                   </button>
                 ))}
               </div>
             </div>

             <Button onClick={createTournament} className="w-full mt-4">Generate Bracket</Button>
           </div>
        </div>
      ) : (
        <div className="animate-fade-in overflow-x-auto">
           {/* Sticky header updated with z-index and background to ensure clickable buttons */}
           <div className="flex justify-between items-center mb-4 min-w-[600px] sticky left-0 z-10 bg-war-dark p-2 border-b border-zinc-800">
             <div>
               <h2 className="text-2xl font-bold font-orbitron text-white">{activeTournament.name}</h2>
               <div className="text-xs text-zinc-500">Status: {activeTournament.status} | Type: {activeTournament.type}</div>
             </div>
             <Button variant="danger" onClick={() => setShowDeleteModal(true)} className="text-xs py-1 px-3 bg-red-800 hover:bg-red-700 text-white border-red-900 shadow-lg">Delete Tournament</Button>
           </div>

           {/* Render Brackets Split by Type */}
           {activeTournament.type === 'single' ? (
              renderBracketSection("Bracket", activeTournament.matches)
           ) : (
              <div>
                {renderBracketSection("Winners Bracket", activeTournament.matches.filter(m => m.bracketType === 'winner'))}
                {renderBracketSection("Losers Bracket", activeTournament.matches.filter(m => m.bracketType === 'loser'))}
                {renderBracketSection("Finals", activeTournament.matches.filter(m => m.bracketType === 'final'))}
              </div>
           )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { PLAYERS } from '../constants';
import { Tournament, TournamentMatch } from '../types';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';

export const TournamentHub: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [activeTournament, setActiveTournament] = useState<Tournament | null>(null);
  const [newTourneyName, setNewTourneyName] = useState('');
  const [selectedPlayers, setSelectedPlayers] = useState<string[]>([]);
  const [tourneyType, setTourneyType] = useState<'single' | 'double'>('single');
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  // Load active tournament
  useEffect(() => {
    const saved = localStorage.getItem('battleforge_active_tournament');
    if (saved) {
      const tourney = JSON.parse(saved);
      setActiveTournament(tourney);
    }
  }, []);

  // Handle return from MatchLogger with results
  useEffect(() => {
    if (location.state && location.state.completedMatchId && location.state.winner) {
      const { completedMatchId, winner } = location.state;

      navigate(location.pathname, { replace: true, state: {} });

      if (activeTournament) {
        handleMatchCompletion(completedMatchId, winner);
      }
    }
  }, [location.state, activeTournament, navigate, location.pathname]);

  // --- Core Logic: Advance Players ---

  const advancePlayerToMatch = (matches: TournamentMatch[], targetId: string, player: string): boolean => {
    const target = matches.find(m => m.id === targetId);
    if (!target) return false;

    // Idempotency check
    if (target.player1 === player || target.player2 === player) return false;

    let changed = false;

    // Fill empty slot
    if (!target.player1) {
       target.player1 = player;
       changed = true;
    } else if (!target.player2) {
       target.player2 = player;
       changed = true;
    }

    if (changed) {
        if (target.player1 && target.player2) {
            target.status = 'ready';
        } else {
            target.status = 'pending';
        }
    }

    return changed;
  };

  const settleBracket = (matches: TournamentMatch[]) => {
    let changed = true;
    let iterations = 0;
    while(changed && iterations < 50) {
      changed = false;
      iterations++;

      matches.forEach(m => {
         // RULE 1: Auto-resolve pending/ready matches
         if (m.status !== 'completed') {
             const p1 = m.player1;
             const p2 = m.player2;

             if (p1 && p2) {
                 // 1a. Handle BYE (Auto-Win)
                 if (p1 === 'BYE' || p2 === 'BYE') {
                     m.winner = p1 === 'BYE' ? p2 : p1;
                     m.status = 'completed';
                     changed = true; 
                 } 
                 // 1b. Handle Initial Pending -> Ready
                 else if (m.status === 'pending') {
                     m.status = 'ready';
                     changed = true;
                 }
             }
         }

         // RULE 2: Propagate Completed Matches
         if (m.status === 'completed' && m.winner) {
             // Advance Winner
             if (m.nextMatchId) {
                if (advancePlayerToMatch(matches, m.nextMatchId, m.winner)) changed = true;
             }
             // Advance Loser (Double Elim)
             if (m.loserNextMatchId && m.player1 && m.player2) {
                const loser = m.winner === m.player1 ? m.player2 : m.player1;
                if (loser && advancePlayerToMatch(matches, m.loserNextMatchId, loser)) changed = true;
             }
         }
      });
    }
  };

  const handleMatchCompletion = (matchId: string, winner: string | null) => {
    if (!activeTournament || !winner) return;

    const newMatches = JSON.parse(JSON.stringify(activeTournament.matches)); 
    const match = newMatches.find((m: TournamentMatch) => m.id === matchId);

    if (match && match.status === 'completed' && match.winner === winner) return;

    if (match) {
        match.winner = winner;
        match.status = 'completed';

        // Run settle to propagate winner
        settleBracket(newMatches);

        // Check if new "Player vs BYE" scenarios arose and prune them if needed (though usually settle handles auto-wins)
        // Topological pruning is destructive, so we generally rely on settleBracket for live updates.
        // However, if we want to collapse the view live, we would need to run prune.
        // For safety/simplicity in live mode, we stick to settleBracket which marks them "Completed" (green check).
        // The user specifically asked for correct INITIAL GENERATION. Live updates can show the "Bye" win.

        const updatedTourney = { ...activeTournament, matches: newMatches };
        setActiveTournament(updatedTourney);
        localStorage.setItem('battleforge_active_tournament', JSON.stringify(updatedTourney));
    }
  };

  // --- Pruning Logic (Topological Rewire) ---
  const pruneBracket = (matches: TournamentMatch[]) => {
    let activeMatches = [...matches];
    let changed = true;
    let iterations = 0;

    // We loop because removing one bypass might create another bypass downstream
    while(changed && iterations < 20) {
        changed = false;
        iterations++;
        const toRemoveIds: string[] = [];

        // Sort by round to process early rounds first
        activeMatches.sort((a,b) => a.roundIndex - b.roundIndex);

        for(const m of activeMatches) {
            // Check if this match is a "Pass Through" (Player vs Bye) or "Dead" (Bye vs Bye)

            const isWbR0 = m.bracketType === 'winner' && m.roundIndex === 0;
            // We NEVER prune WB Round 0 Player vs Bye matches (we want to show the seed bye)
            if (isWbR0 && m.player1 !== 'BYE' && m.player2 !== 'BYE') continue;
            if (isWbR0 && (m.player1 === 'BYE' || m.player2 === 'BYE') && !(m.player1 === 'BYE' && m.player2 === 'BYE')) continue;

            let shouldPrune = false;

            // 1. BYE vs BYE (Always remove)
            if (m.player1 === 'BYE' && m.player2 === 'BYE') {
                shouldPrune = true;
            }
            // 2. Player vs BYE (Remove in LB or later rounds, effectively advancing player)
            else if ((m.player1 === 'BYE' || m.player2 === 'BYE') && !isWbR0) {
                shouldPrune = true;
            }

            if (shouldPrune) {
                toRemoveIds.push(m.id);
                changed = true;

                // REWIRE: Connect input matches to output match
                const nextId = m.nextMatchId;
                const loserNextId = m.loserNextMatchId; // Usually null for LB matches, but exists for WB

                // Rewire feeds to 'nextMatchId'
                if (nextId) {
                    // Find all matches that feed THIS match
                    const feeders = activeMatches.filter(f => f.nextMatchId === m.id || f.loserNextMatchId === m.id);
                    feeders.forEach(f => {
                         if (f.nextMatchId === m.id) f.nextMatchId = nextId;
                         if (f.loserNextMatchId === m.id) f.loserNextMatchId = nextId;
                    });
                }

                // If this match produced a loser that goes somewhere (unlikely for Bye matches, but possible in WB)
                if (loserNextId) {
                     // Since "BYE" matches generally mean the BYE loses...
                     // If P vs BYE -> P wins (goes to nextId), BYE loses (goes to loserNextId)
                     // If we prune this, the "BYE" effectively propagates to loserNextId.
                     // But we don't have a "Source of Bye" usually.
                     // We just assume the destination receives a BYE.
                     // We can manually inject 'BYE' into the destination?
                     // Or, more robustly, we let the destination sit empty. 
                     // When settleBracket runs, if it sees empty vs Player, it waits. 
                     // If it sees empty vs empty? 

                     // For correct LB generation, we rely on the fact that if a WB match sends a BYE to LB,
                     // the LB match will eventually become [Player vs BYE] or [BYE vs BYE] and get pruned in the next loop.
                }
            }
        }

        if (toRemoveIds.length > 0) {
            activeMatches = activeMatches.filter(m => !toRemoveIds.includes(m.id));
        }
    }
    return activeMatches;
  };

  // --- Generators ---

  const generateFullSingleElim = (participants: string[], idOffset = 0): { matches: TournamentMatch[], rounds: number, nextId: number } => {
     const shuffled = [...participants].sort(() => 0.5 - Math.random());
     let size = 2;
     while(size < shuffled.length) size *= 2;

     // Fill with BYEs
     const seeded = [...shuffled];
     while(seeded.length < size) seeded.push("BYE");

     // Standard pairing (0v1, 2v3...)
     const r1Pairs: {p1: string, p2: string}[] = [];
     for(let i=0; i<size; i+=2) {
         r1Pairs.push({ p1: seeded[i], p2: seeded[i+1] });
     }

     const matches: TournamentMatch[] = [];
     let matchIdCounter = idOffset + 1;
     const getId = () => `m_${matchIdCounter++}`;

     // Round 1
     const round1Ids: string[] = [];
     r1Pairs.forEach(pair => {
        const id = getId();
        round1Ids.push(id);
        matches.push({
          id,
          roundIndex: 0,
          bracketType: 'winner',
          player1: pair.p1,
          player2: pair.p2,
          winner: null,
          status: 'pending' 
        });
     });

     // Subsequent Rounds
     let currentIds = round1Ids;
     let rIdx = 1;
     while(currentIds.length > 1) {
       const nextIds: string[] = [];
       for(let i=0; i<currentIds.length; i+=2) {
         const id = getId();
         nextIds.push(id);

         const m1 = matches.find(m => m.id === currentIds[i]);
         const m2 = matches.find(m => m.id === currentIds[i+1]);
         if(m1) m1.nextMatchId = id;
         if(m2) m2.nextMatchId = id;

         matches.push({
           id,
           roundIndex: rIdx,
           bracketType: 'winner',
           player1: null,
           player2: null,
           winner: null,
           status: 'pending'
         });
       }
       currentIds = nextIds;
       rIdx++;
     }

     return { matches, rounds: rIdx, nextId: matchIdCounter };
  };

  const generateDoubleElim = (participants: string[]): { matches: TournamentMatch[], rounds: number } => {
    // 1. Generate FULL Winner Bracket
    const { matches: wbMatches, rounds: wbRounds, nextId } = generateFullSingleElim(participants);
    const matches = [...wbMatches];

    const wbByRound: Record<number, TournamentMatch[]> = {};
    matches.forEach(m => {
      if(!wbByRound[m.roundIndex]) wbByRound[m.roundIndex] = [];
      wbByRound[m.roundIndex].push(m);
    });

    let matchIdCounter = nextId + 1000;
    const getId = () => `m_${matchIdCounter++}`;

    const lbMatches: TournamentMatch[] = [];
    let prevLBRoundMatches: TournamentMatch[] = [];

    // --- LB Round 0: Consumes WB Round 0 Losers ---
    const wbR0 = wbByRound[0];
    const lbR0Count = wbR0.length / 2;

    for (let i = 0; i < lbR0Count; i++) {
        const m: TournamentMatch = { 
            id: getId(), 
            roundIndex: 0, 
            bracketType: 'loser', 
            player1: null, 
            player2: null, 
            winner: null, 
            status: 'pending' 
        };
        lbMatches.push(m);
        prevLBRoundMatches.push(m);

        wbR0[i*2].loserNextMatchId = m.id;
        wbR0[i*2+1].loserNextMatchId = m.id;
    }

    let lbRoundIndex = 1;

    // --- Feed Remaining WB Rounds ---
    for (let i = 1; i < wbRounds; i++) {
        const wbRoundMatches = wbByRound[i]; 

        // Injection Round (Winner of previous LB vs Loser of current WB)
        const injectionMatches: TournamentMatch[] = [];
        for (let j = 0; j < wbRoundMatches.length; j++) {
            const m: TournamentMatch = {
                id: getId(),
                roundIndex: lbRoundIndex,
                bracketType: 'loser',
                player1: null,
                player2: null,
                winner: null,
                status: 'pending'
            };
            injectionMatches.push(m);
            lbMatches.push(m);

            if (prevLBRoundMatches[j]) prevLBRoundMatches[j].nextMatchId = m.id;
            wbRoundMatches[j].loserNextMatchId = m.id;
        }
        prevLBRoundMatches = injectionMatches;
        lbRoundIndex++;

        // Reduction Round (Winner of LB vs Winner of LB) - Only if not the last WB round
        if (prevLBRoundMatches.length > 1) {
            const reductionMatches: TournamentMatch[] = [];
            for (let j = 0; j < prevLBRoundMatches.length; j += 2) {
                const m: TournamentMatch = {
                    id: getId(),
                    roundIndex: lbRoundIndex,
                    bracketType: 'loser',
                    player1: null, 
                    player2: null,
                    winner: null, 
                    status: 'pending'
                };
                reductionMatches.push(m);
                lbMatches.push(m);

                prevLBRoundMatches[j].nextMatchId = m.id;
                prevLBRoundMatches[j+1].nextMatchId = m.id;
            }
            prevLBRoundMatches = reductionMatches;
            lbRoundIndex++;
        }
    }

    // --- Grand Final ---
    const grandFinal: TournamentMatch = {
        id: getId(),
        roundIndex: 0,
        bracketType: 'final',
        player1: null,
        player2: null,
        winner: null,
        status: 'pending'
    };
    matches.push(grandFinal);

    // Winner of WB Final -> Final
    const wbFinal = wbByRound[wbRounds-1][0];
    wbFinal.nextMatchId = grandFinal.id;

    // Winner of LB Final -> Final
    if (prevLBRoundMatches[0]) {
        prevLBRoundMatches[0].nextMatchId = grandFinal.id;
    }

    matches.push(...lbMatches);

    return { matches, rounds: lbRoundIndex };
  };

  const createTournament = () => {
    if (!newTourneyName || selectedPlayers.length < 2) {
      alert("Enter name and select at least 2 players.");
      return;
    }

    let result;
    if (tourneyType === 'double') {
      result = generateDoubleElim(selectedPlayers);
    } else {
      const full = generateFullSingleElim(selectedPlayers);
      result = { matches: full.matches, rounds: full.rounds };
    }

    let matches = result.matches;

    // 1. Initial Settle: Push Names to initial matches
    // This fills the "Player vs Bye" slots with actual names
    settleBracket(matches);

    // 2. Structural Prune: Collapse any "Player vs Bye" or "Bye vs Bye" sections
    // This rewires the graph to skip empty rounds
    matches = pruneBracket(matches);

    // 3. Final Settle: Propagate names through the new rewired connections
    settleBracket(matches);

    const newTourney: Tournament = {
      id: newTourneyName.replace(/\s+/g, '') + '_' + Date.now(),
      name: newTourneyName,
      type: tourneyType,
      participants: selectedPlayers,
      matches: matches,
      rounds: result.rounds,
      status: 'active',
      dateCreated: new Date().toISOString()
    };

    setActiveTournament(newTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(newTourney));
  };

  const handlePlayerToggle = (p: string) => {
    if (selectedPlayers.includes(p)) setSelectedPlayers(selectedPlayers.filter(x => x !== p));
    else setSelectedPlayers([...selectedPlayers, p]);
  };

  const confirmDelete = () => {
     localStorage.removeItem('battleforge_active_tournament');
     setActiveTournament(null);
     setNewTourneyName('');
     setSelectedPlayers([]);
     setShowDeleteModal(false);
     navigate('/tournament', { replace: true, state: {} });
  };

  const startMatch = (m: TournamentMatch) => {
     if (!activeTournament) return;
     if (m.status !== 'ready') return;

     navigate('/', { 
       state: {
         player1: m.player1,
         player2: m.player2,
         tournamentId: activeTournament.id,
         bracketMatchId: m.id
       }
     });
  };

  const renderBracketSection = (title: string, matches: TournamentMatch[]) => {
      // Visual Filter: Even after pruning, hide any stubborn Bye matches
      const visibleMatches = matches.filter(m => {
          if (m.player1 === 'BYE' && m.player2 === 'BYE') return false;
          return true;
      });

      if (visibleMatches.length === 0) return null;

      // Dynamic Column Mapping:
      // Map the distinct 'roundIndex' values to 1, 2, 3...
      // This ensures if Round 2 is pruned entirely, Round 3 becomes the 2nd visual column.
      const activeRoundIndices = Array.from(new Set(visibleMatches.map(m => m.roundIndex))).sort((a,b) => a-b);

      return (
        <div className="mb-8">
           <h3 className="text-war-red font-orbitron font-bold uppercase mb-4 sticky left-0">{title}</h3>
           <div className="flex gap-8 min-w-max">
              {activeRoundIndices.map((roundIdx, displayIdx) => {
                 const roundMatches = visibleMatches.filter(m => m.roundIndex === roundIdx);

                 return (
                   <div key={roundIdx} className="flex flex-col justify-around gap-8 w-64">
                      <div className="text-center text-zinc-500 font-orbitron text-xs font-bold uppercase mb-4 bg-black/40 p-1 rounded">
                        Round {displayIdx + 1}
                      </div>
                      {roundMatches.map(m => {
                        const isReady = m.status === 'ready';
                        const isComplete = m.status === 'completed';
                        const p1Won = isComplete && m.winner === m.player1;
                        const p2Won = isComplete && m.winner === m.player2;

                        return (
                          <div 
                             key={m.id} 
                             onClick={() => isReady && startMatch(m)}
                             className={`
                               relative p-3 rounded border transition-all 
                               ${isComplete ? 'bg-green-900/10 border-green-900/30' : isReady ? 'bg-war-panel border-war-red cursor-pointer hover:bg-zinc-800 hover:scale-[1.02] shadow-[0_0_10px_rgba(255,45,45,0.2)]' : 'bg-zinc-900 border-zinc-800 opacity-60'}
                             `}
                          >
                             <div className={`text-sm font-bold flex justify-between ${p1Won ? 'text-green-400' : p2Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player1 || 'Waiting...'}</span>
                               {p1Won && <span>✓</span>}
                             </div>
                             <div className="h-px bg-zinc-700 my-2"></div>
                             <div className={`text-sm font-bold flex justify-between ${p2Won ? 'text-green-400' : p1Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player2 || 'Waiting...'}</span>
                               {p2Won && <span>✓</span>}
                             </div>
                          </div>
                        );
                      })}
                   </div>
                 );
              })}
           </div>
        </div>
      );
  };

  return (
    <div className="min-h-screen bg-war-dark pb-20 p-4">
      {/* Delete Confirmation Modal */}
      {showDeleteModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
            <div className="bg-war-panel border border-red-900/50 rounded-lg p-6 max-w-md w-full shadow-[0_0_20px_rgba(255,45,45,0.1)]">
                <h3 className="text-xl font-orbitron font-bold text-white mb-2">Delete Tournament?</h3>
                <p className="text-zinc-400 mb-6 text-sm">
                    Are you sure you want to delete <span className="text-white font-bold">{activeTournament?.name}</span>? 
                    This action cannot be undone and all bracket progress will be lost.
                </p>
                <div className="flex gap-3 justify-end">
                    <Button variant="secondary" onClick={() => setShowDeleteModal(false)} className="text-xs">Cancel</Button>
                    <Button variant="danger" onClick={confirmDelete} className="text-xs bg-red-600 hover:bg-red-700">Yes, Delete It</Button>
                </div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-orbitron font-bold text-war-red">
          TOURNAMENT<span className="text-white">HUB</span>
        </h1>
        <Button variant="secondary" onClick={() => navigate('/')} className="text-xs py-2 px-3">&larr; App</Button>
      </header>

      {!activeTournament ? (
        <div className="bg-war-panel border border-zinc-700 rounded-lg p-6 max-w-2xl mx-auto shadow-xl animate-fade-in">
           <h2 className="text-xl font-orbitron text-white mb-4">Create New Tournament</h2>

           <div className="space-y-4">
             <Input label="Tournament Name" value={newTourneyName} onChange={e => setNewTourneyName(e.target.value)} placeholder="e.g. Summer Slam 2024" />

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Format</label>
               <div className="flex gap-2">
                 <button onClick={() => setTourneyType('single')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'single' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Single Elimination</button>
                 <button onClick={() => setTourneyType('double')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'double' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Double Elimination</button>
               </div>
             </div>

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Participants ({selectedPlayers.length})</label>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-2 bg-zinc-900 p-3 rounded border border-zinc-800 max-h-40 overflow-y-auto">
                 {PLAYERS.map(p => (
                   <button 
                     key={p} 
                     onClick={() => handlePlayerToggle(p)}
                     className={`text-xs p-2 rounded text-left transition-colors ${selectedPlayers.includes(p) ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
                   >
                     {p}
                   </button>
                 ))}
               </div>
             </div>

             <Button onClick={createTournament} className="w-full mt-4">Generate Bracket</Button>
           </div>
        </div>
      ) : (
        <div className="animate-fade-in overflow-x-auto">
           {/* Sticky header updated with z-index and background to ensure clickable buttons */}
           <div className="flex justify-between items-center mb-4 min-w-[600px] sticky left-0 z-10 bg-war-dark p-2 border-b border-zinc-800">
             <div>
               <h2 className="text-2xl font-bold font-orbitron text-white">{activeTournament.name}</h2>
               <div className="text-xs text-zinc-500">Status: {activeTournament.status} | Type: {activeTournament.type}</div>
             </div>
             <Button variant="danger" onClick={() => setShowDeleteModal(true)} className="text-xs py-1 px-3 bg-red-800 hover:bg-red-700 text-white border-red-900 shadow-lg">Delete Tournament</Button>
           </div>

           {/* Render Brackets Split by Type */}
           {activeTournament.type === 'single' ? (
              renderBracketSection("Bracket", activeTournament.matches)
           ) : (
              <div>
                {renderBracketSection("Winners Bracket", activeTournament.matches.filter(m => m.bracketType === 'winner'))}
                {renderBracketSection("Losers Bracket", activeTournament.matches.filter(m => m.bracketType === 'loser'))}
                {renderBracketSection("Finals", activeTournament.matches.filter(m => m.bracketType === 'final'))}
              </div>
           )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { PLAYERS } from '../constants';
import { Tournament, TournamentMatch } from '../types';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';

export const TournamentHub: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [activeTournament, setActiveTournament] = useState<Tournament | null>(null);
  const [newTourneyName, setNewTourneyName] = useState('');
  const [selectedPlayers, setSelectedPlayers] = useState<string[]>([]);
  const [tourneyType, setTourneyType] = useState<'single' | 'double'>('single');
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  // Load active tournament
  useEffect(() => {
    const saved = localStorage.getItem('battleforge_active_tournament');
    if (saved) {
      const tourney = JSON.parse(saved);
      setActiveTournament(tourney);
    }
  }, []);

  // Handle return from MatchLogger with results
  useEffect(() => {
    if (location.state && location.state.completedMatchId && location.state.winner) {
      const { completedMatchId, winner } = location.state;

      navigate(location.pathname, { replace: true, state: {} });

      if (activeTournament) {
        handleMatchCompletion(completedMatchId, winner);
      }
    }
  }, [location.state, activeTournament, navigate, location.pathname]);

  // --- Core Logic: Advance Players ---

  const advancePlayerToMatch = (matches: TournamentMatch[], targetId: string, player: string): boolean => {
    const target = matches.find(m => m.id === targetId);
    if (!target) return false;

    // Idempotency check
    if (target.player1 === player || target.player2 === player) return false;

    let changed = false;

    // Fill empty slot
    if (!target.player1) {
       target.player1 = player;
       changed = true;
    } else if (!target.player2) {
       target.player2 = player;
       changed = true;
    }

    if (changed) {
        if (target.player1 && target.player2) {
            target.status = 'ready';
        } else {
            target.status = 'pending';
        }
    }

    return changed;
  };

  const settleBracket = (matches: TournamentMatch[]) => {
    let changed = true;
    let iterations = 0;
    while(changed && iterations < 50) {
      changed = false;
      iterations++;

      matches.forEach(m => {
         // RULE 1: Auto-resolve pending/ready matches
         if (m.status !== 'completed') {
             const p1 = m.player1;
             const p2 = m.player2;

             if (p1 && p2) {
                 // 1a. Handle BYE (Auto-Win)
                 if (p1 === 'BYE' || p2 === 'BYE') {
                     m.winner = p1 === 'BYE' ? p2 : p1;
                     m.status = 'completed';
                     changed = true; 
                 } 
                 // 1b. Handle Initial Pending -> Ready
                 else if (m.status === 'pending') {
                     m.status = 'ready';
                     changed = true;
                 }
             }
         }

         // RULE 2: Propagate Completed Matches
         if (m.status === 'completed' && m.winner) {
             // Advance Winner
             if (m.nextMatchId) {
                if (advancePlayerToMatch(matches, m.nextMatchId, m.winner)) changed = true;
             }
             // Advance Loser (Double Elim)
             if (m.loserNextMatchId && m.player1 && m.player2) {
                const loser = m.winner === m.player1 ? m.player2 : m.player1;
                if (loser && advancePlayerToMatch(matches, m.loserNextMatchId, loser)) changed = true;
             }
         }
      });
    }
  };

  const handleMatchCompletion = (matchId: string, winner: string | null) => {
    if (!activeTournament || !winner) return;

    const newMatches = JSON.parse(JSON.stringify(activeTournament.matches)); 
    const match = newMatches.find((m: TournamentMatch) => m.id === matchId);

    if (match && match.status === 'completed' && match.winner === winner) return;

    if (match) {
        match.winner = winner;
        match.status = 'completed';

        // 1. Settle the immediate match result
        settleBracket(newMatches);

        // 2. Prune any new Bye scenarios (e.g. if a Bye dropped to Loser Bracket)
        const pruned = pruneBracket(newMatches);

        // 3. Final settle to ensure everything propagated
        settleBracket(pruned);

        const updatedTourney = { ...activeTournament, matches: pruned };
        setActiveTournament(updatedTourney);
        localStorage.setItem('battleforge_active_tournament', JSON.stringify(updatedTourney));
    }
  };

  // --- Pruning Logic (Injection Method) ---
  const pruneBracket = (matches: TournamentMatch[]) => {
    let activeMatches = [...matches];
    let changed = true;
    let iterations = 0;

    while(changed && iterations < 20) {
        changed = false;
        iterations++;
        const toRemoveIds: string[] = [];

        // Sort by round to process upstream matches first
        activeMatches.sort((a,b) => a.roundIndex - b.roundIndex);

        for(const m of activeMatches) {
            const isWbR0 = m.bracketType === 'winner' && m.roundIndex === 0;

            let p1 = m.player1;
            let p2 = m.player2;

            const isByeBye = p1 === 'BYE' && p2 === 'BYE';
            const isPlayerBye = (p1 === 'BYE' || p2 === 'BYE') && !isByeBye; 

            let shouldPrune = false;
            let projectedWinner: string | null = null;
            let projectedLoser: string | null = null;

            // 1. BYE vs BYE -> Winner is BYE, Loser is BYE. Always Remove.
            if (isByeBye) {
                shouldPrune = true;
                projectedWinner = 'BYE';
                projectedLoser = 'BYE';
            } 
            // 2. Player vs BYE -> Winner is Player, Loser is BYE. Remove unless WB Round 0.
            else if (isPlayerBye && !isWbR0) {
                shouldPrune = true;
                projectedWinner = p1 === 'BYE' ? p2 : p1;
                projectedLoser = 'BYE';
            }

            if (shouldPrune && projectedWinner) {
                // INJECT RESULTS DOWNSTREAM
                // This simulates the match happening instantly and auto-forwarding the result
                if (m.nextMatchId) {
                    if (advancePlayerToMatch(activeMatches, m.nextMatchId, projectedWinner)) {
                        // If we successfully advanced, we might have created a new pruning opportunity downstream
                        // The loop will catch it in the next iteration
                    }
                }
                if (m.loserNextMatchId) {
                    if (advancePlayerToMatch(activeMatches, m.loserNextMatchId, projectedLoser!)) {
                        // same here
                    }
                }

                toRemoveIds.push(m.id);
                changed = true;
            }
        }

        if (toRemoveIds.length > 0) {
            activeMatches = activeMatches.filter(m => !toRemoveIds.includes(m.id));
        }
    }
    return activeMatches;
  };

  // --- Generators ---

  const generateFullSingleElim = (participants: string[], idOffset = 0): { matches: TournamentMatch[], rounds: number, nextId: number } => {
     const shuffled = [...participants].sort(() => 0.5 - Math.random());
     let size = 2;
     while(size < shuffled.length) size *= 2;

     // Fill with BYEs
     const seeded = [...shuffled];
     while(seeded.length < size) seeded.push("BYE");

     // Standard pairing (0v1, 2v3...)
     const r1Pairs: {p1: string, p2: string}[] = [];
     for(let i=0; i<size; i+=2) {
         r1Pairs.push({ p1: seeded[i], p2: seeded[i+1] });
     }

     const matches: TournamentMatch[] = [];
     let matchIdCounter = idOffset + 1;
     const getId = () => `m_${matchIdCounter++}`;

     // Round 1
     const round1Ids: string[] = [];
     r1Pairs.forEach(pair => {
        const id = getId();
        round1Ids.push(id);
        matches.push({
          id,
          roundIndex: 0,
          bracketType: 'winner',
          player1: pair.p1,
          player2: pair.p2,
          winner: null,
          status: 'pending' 
        });
     });

     // Subsequent Rounds
     let currentIds = round1Ids;
     let rIdx = 1;
     while(currentIds.length > 1) {
       const nextIds: string[] = [];
       for(let i=0; i<currentIds.length; i+=2) {
         const id = getId();
         nextIds.push(id);

         const m1 = matches.find(m => m.id === currentIds[i]);
         const m2 = matches.find(m => m.id === currentIds[i+1]);
         if(m1) m1.nextMatchId = id;
         if(m2) m2.nextMatchId = id;

         matches.push({
           id,
           roundIndex: rIdx,
           bracketType: 'winner',
           player1: null,
           player2: null,
           winner: null,
           status: 'pending'
         });
       }
       currentIds = nextIds;
       rIdx++;
     }

     return { matches, rounds: rIdx, nextId: matchIdCounter };
  };

  const generateDoubleElim = (participants: string[]): { matches: TournamentMatch[], rounds: number } => {
    // 1. Generate FULL Winner Bracket
    const { matches: wbMatches, rounds: wbRounds, nextId } = generateFullSingleElim(participants);
    const matches = [...wbMatches];

    const wbByRound: Record<number, TournamentMatch[]> = {};
    matches.forEach(m => {
      if(!wbByRound[m.roundIndex]) wbByRound[m.roundIndex] = [];
      wbByRound[m.roundIndex].push(m);
    });

    let matchIdCounter = nextId + 1000;
    const getId = () => `m_${matchIdCounter++}`;

    const lbMatches: TournamentMatch[] = [];
    let prevLBRoundMatches: TournamentMatch[] = [];

    // --- LB Round 0: Consumes WB Round 0 Losers ---
    const wbR0 = wbByRound[0];
    const lbR0Count = wbR0.length / 2;

    for (let i = 0; i < lbR0Count; i++) {
        const m: TournamentMatch = { 
            id: getId(), 
            roundIndex: 0, 
            bracketType: 'loser', 
            player1: null, 
            player2: null, 
            winner: null, 
            status: 'pending' 
        };
        lbMatches.push(m);
        prevLBRoundMatches.push(m);

        wbR0[i*2].loserNextMatchId = m.id;
        wbR0[i*2+1].loserNextMatchId = m.id;
    }

    let lbRoundIndex = 1;

    // --- Feed Remaining WB Rounds ---
    for (let i = 1; i < wbRounds; i++) {
        const wbRoundMatches = wbByRound[i]; 

        // Injection Round (Winner of previous LB vs Loser of current WB)
        const injectionMatches: TournamentMatch[] = [];
        for (let j = 0; j < wbRoundMatches.length; j++) {
            const m: TournamentMatch = {
                id: getId(),
                roundIndex: lbRoundIndex,
                bracketType: 'loser',
                player1: null,
                player2: null,
                winner: null,
                status: 'pending'
            };
            injectionMatches.push(m);
            lbMatches.push(m);

            if (prevLBRoundMatches[j]) prevLBRoundMatches[j].nextMatchId = m.id;
            wbRoundMatches[j].loserNextMatchId = m.id;
        }
        prevLBRoundMatches = injectionMatches;
        lbRoundIndex++;

        // Reduction Round (Winner of LB vs Winner of LB) - Only if not the last WB round
        if (prevLBRoundMatches.length > 1) {
            const reductionMatches: TournamentMatch[] = [];
            for (let j = 0; j < prevLBRoundMatches.length; j += 2) {
                const m: TournamentMatch = {
                    id: getId(),
                    roundIndex: lbRoundIndex,
                    bracketType: 'loser',
                    player1: null, 
                    player2: null,
                    winner: null, 
                    status: 'pending'
                };
                reductionMatches.push(m);
                lbMatches.push(m);

                prevLBRoundMatches[j].nextMatchId = m.id;
                prevLBRoundMatches[j+1].nextMatchId = m.id;
            }
            prevLBRoundMatches = reductionMatches;
            lbRoundIndex++;
        }
    }

    // --- Grand Final ---
    const grandFinal: TournamentMatch = {
        id: getId(),
        roundIndex: 0,
        bracketType: 'final',
        player1: null,
        player2: null,
        winner: null,
        status: 'pending'
    };
    matches.push(grandFinal);

    // Winner of WB Final -> Final
    const wbFinal = wbByRound[wbRounds-1][0];
    wbFinal.nextMatchId = grandFinal.id;

    // Winner of LB Final -> Final
    if (prevLBRoundMatches[0]) {
        prevLBRoundMatches[0].nextMatchId = grandFinal.id;
    }

    matches.push(...lbMatches);

    return { matches, rounds: lbRoundIndex };
  };

  const createTournament = () => {
    if (!newTourneyName || selectedPlayers.length < 2) {
      alert("Enter name and select at least 2 players.");
      return;
    }

    let result;
    if (tourneyType === 'double') {
      result = generateDoubleElim(selectedPlayers);
    } else {
      const full = generateFullSingleElim(selectedPlayers);
      result = { matches: full.matches, rounds: full.rounds };
    }

    let matches = result.matches;

    // 1. Initial Settle: Push Names to initial matches
    // This fills the "Player vs Bye" slots with actual names in WB R0
    settleBracket(matches);

    // 2. Structural Prune with Injection: 
    // This collapses the bracket by auto-resolving Bye matches and pushing results downstream
    matches = pruneBracket(matches);

    // 3. Final Settle: Propagate any remaining states
    settleBracket(matches);

    const newTourney: Tournament = {
      id: newTourneyName.replace(/\s+/g, '') + '_' + Date.now(),
      name: newTourneyName,
      type: tourneyType,
      participants: selectedPlayers,
      matches: matches,
      rounds: result.rounds,
      status: 'active',
      dateCreated: new Date().toISOString()
    };

    setActiveTournament(newTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(newTourney));
  };

  const handlePlayerToggle = (p: string) => {
    if (selectedPlayers.includes(p)) setSelectedPlayers(selectedPlayers.filter(x => x !== p));
    else setSelectedPlayers([...selectedPlayers, p]);
  };

  const confirmDelete = () => {
     localStorage.removeItem('battleforge_active_tournament');
     setActiveTournament(null);
     setNewTourneyName('');
     setSelectedPlayers([]);
     setShowDeleteModal(false);
     navigate('/tournament', { replace: true, state: {} });
  };

  const startMatch = (m: TournamentMatch) => {
     if (!activeTournament) return;
     if (m.status !== 'ready') return;

     navigate('/', { 
       state: {
         player1: m.player1,
         player2: m.player2,
         tournamentId: activeTournament.id,
         bracketMatchId: m.id
       }
     });
  };

  const renderBracketSection = (title: string, matches: TournamentMatch[]) => {
      // Visual Filter: Even after pruning, hide any stubborn Bye matches
      const visibleMatches = matches.filter(m => {
          if (m.player1 === 'BYE' && m.player2 === 'BYE') return false;
          return true;
      });

      if (visibleMatches.length === 0) return null;

      // Dynamic Column Mapping:
      // Map the distinct 'roundIndex' values to 1, 2, 3...
      // This ensures if Round 2 is pruned entirely, Round 3 becomes the 2nd visual column.
      const activeRoundIndices = Array.from(new Set(visibleMatches.map(m => m.roundIndex))).sort((a,b) => a-b);

      return (
        <div className="mb-8">
           <h3 className="text-war-red font-orbitron font-bold uppercase mb-4 sticky left-0">{title}</h3>
           <div className="flex gap-8 min-w-max">
              {activeRoundIndices.map((roundIdx, displayIdx) => {
                 const roundMatches = visibleMatches.filter(m => m.roundIndex === roundIdx);

                 return (
                   <div key={roundIdx} className="flex flex-col justify-around gap-8 w-64">
                      <div className="text-center text-zinc-500 font-orbitron text-xs font-bold uppercase mb-4 bg-black/40 p-1 rounded">
                        Round {displayIdx + 1}
                      </div>
                      {roundMatches.map(m => {
                        const isReady = m.status === 'ready';
                        const isComplete = m.status === 'completed';
                        const p1Won = isComplete && m.winner === m.player1;
                        const p2Won = isComplete && m.winner === m.player2;

                        return (
                          <div 
                             key={m.id} 
                             onClick={() => isReady && startMatch(m)}
                             className={`
                               relative p-3 rounded border transition-all 
                               ${isComplete ? 'bg-green-900/10 border-green-900/30' : isReady ? 'bg-war-panel border-war-red cursor-pointer hover:bg-zinc-800 hover:scale-[1.02] shadow-[0_0_10px_rgba(255,45,45,0.2)]' : 'bg-zinc-900 border-zinc-800 opacity-60'}
                             `}
                          >
                             <div className={`text-sm font-bold flex justify-between ${p1Won ? 'text-green-400' : p2Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player1 || 'Waiting...'}</span>
                               {p1Won && <span>✓</span>}
                             </div>
                             <div className="h-px bg-zinc-700 my-2"></div>
                             <div className={`text-sm font-bold flex justify-between ${p2Won ? 'text-green-400' : p1Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player2 || 'Waiting...'}</span>
                               {p2Won && <span>✓</span>}
                             </div>
                          </div>
                        );
                      })}
                   </div>
                 );
              })}
           </div>
        </div>
      );
  };

  return (
    <div className="min-h-screen bg-war-dark pb-20 p-4">
      {/* Delete Confirmation Modal */}
      {showDeleteModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
            <div className="bg-war-panel border border-red-900/50 rounded-lg p-6 max-w-md w-full shadow-[0_0_20px_rgba(255,45,45,0.1)]">
                <h3 className="text-xl font-orbitron font-bold text-white mb-2">Delete Tournament?</h3>
                <p className="text-zinc-400 mb-6 text-sm">
                    Are you sure you want to delete <span className="text-white font-bold">{activeTournament?.name}</span>? 
                    This action cannot be undone and all bracket progress will be lost.
                </p>
                <div className="flex gap-3 justify-end">
                    <Button variant="secondary" onClick={() => setShowDeleteModal(false)} className="text-xs">Cancel</Button>
                    <Button variant="danger" onClick={confirmDelete} className="text-xs bg-red-600 hover:bg-red-700">Yes, Delete It</Button>
                </div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-orbitron font-bold text-war-red">
          TOURNAMENT<span className="text-white">HUB</span>
        </h1>
        <Button variant="secondary" onClick={() => navigate('/')} className="text-xs py-2 px-3">&larr; App</Button>
      </header>

      {!activeTournament ? (
        <div className="bg-war-panel border border-zinc-700 rounded-lg p-6 max-w-2xl mx-auto shadow-xl animate-fade-in">
           <h2 className="text-xl font-orbitron text-white mb-4">Create New Tournament</h2>

           <div className="space-y-4">
             <Input label="Tournament Name" value={newTourneyName} onChange={e => setNewTourneyName(e.target.value)} placeholder="e.g. Summer Slam 2024" />

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Format</label>
               <div className="flex gap-2">
                 <button onClick={() => setTourneyType('single')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'single' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Single Elimination</button>
                 <button onClick={() => setTourneyType('double')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'double' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Double Elimination</button>
               </div>
             </div>

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Participants ({selectedPlayers.length})</label>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-2 bg-zinc-900 p-3 rounded border border-zinc-800 max-h-40 overflow-y-auto">
                 {PLAYERS.map(p => (
                   <button 
                     key={p} 
                     onClick={() => handlePlayerToggle(p)}
                     className={`text-xs p-2 rounded text-left transition-colors ${selectedPlayers.includes(p) ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
                   >
                     {p}
                   </button>
                 ))}
               </div>
             </div>

             <Button onClick={createTournament} className="w-full mt-4">Generate Bracket</Button>
           </div>
        </div>
      ) : (
        <div className="animate-fade-in overflow-x-auto">
           {/* Sticky header updated with z-index and background to ensure clickable buttons */}
           <div className="flex justify-between items-center mb-4 min-w-[600px] sticky left-0 z-10 bg-war-dark p-2 border-b border-zinc-800">
             <div>
               <h2 className="text-2xl font-bold font-orbitron text-white">{activeTournament.name}</h2>
               <div className="text-xs text-zinc-500">Status: {activeTournament.status} | Type: {activeTournament.type}</div>
             </div>
             <Button variant="danger" onClick={() => setShowDeleteModal(true)} className="text-xs py-1 px-3 bg-red-800 hover:bg-red-700 text-white border-red-900 shadow-lg">Delete Tournament</Button>
           </div>

           {/* Render Brackets Split by Type */}
           {activeTournament.type === 'single' ? (
              renderBracketSection("Bracket", activeTournament.matches)
           ) : (
              <div>
                {renderBracketSection("Winners Bracket", activeTournament.matches.filter(m => m.bracketType === 'winner'))}
                {renderBracketSection("Losers Bracket", activeTournament.matches.filter(m => m.bracketType === 'loser'))}
                {renderBracketSection("Finals", activeTournament.matches.filter(m => m.bracketType === 'final'))}
              </div>
           )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { PLAYERS } from '../constants';
import { Tournament, TournamentMatch } from '../types';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';

export const TournamentHub: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [activeTournament, setActiveTournament] = useState<Tournament | null>(null);
  const [newTourneyName, setNewTourneyName] = useState('');
  const [selectedPlayers, setSelectedPlayers] = useState<string[]>([]);
  const [tourneyType, setTourneyType] = useState<'single' | 'double'>('single');
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  // Load active tournament
  useEffect(() => {
    const saved = localStorage.getItem('battleforge_active_tournament');
    if (saved) {
      const tourney = JSON.parse(saved);
      setActiveTournament(tourney);
    }
  }, []);

  // Handle return from MatchLogger with results
  useEffect(() => {
    if (location.state && location.state.completedMatchId && location.state.winner) {
      // CRITICAL FIX: Wait for activeTournament to be loaded from localStorage
      // If we navigate/clear state before 'activeTournament' is set, the update is lost.
      if (!activeTournament) return;

      const { completedMatchId, winner } = location.state;

      handleMatchCompletion(completedMatchId, winner);

      // Only clear the state AFTER we have successfully processed it
      navigate(location.pathname, { replace: true, state: {} });
    }
  }, [location.state, activeTournament, navigate, location.pathname]);

  // --- Core Logic: Advance Players ---

  const advancePlayerToMatch = (matches: TournamentMatch[], targetId: string, player: string): boolean => {
    const target = matches.find(m => m.id === targetId);
    if (!target) return false;

    // Idempotency check
    if (target.player1 === player || target.player2 === player) return false;

    let changed = false;

    // Fill empty slot
    if (!target.player1) {
       target.player1 = player;
       changed = true;
    } else if (!target.player2) {
       target.player2 = player;
       changed = true;
    }

    if (changed) {
        if (target.player1 && target.player2) {
            target.status = 'ready';
        } else {
            target.status = 'pending';
        }
    }

    return changed;
  };

  const settleBracket = (matches: TournamentMatch[]) => {
    let changed = true;
    let iterations = 0;
    while(changed && iterations < 50) {
      changed = false;
      iterations++;

      matches.forEach(m => {
         // RULE 1: Auto-resolve pending/ready matches
         if (m.status !== 'completed') {
             const p1 = m.player1;
             const p2 = m.player2;

             if (p1 && p2) {
                 // 1a. Handle BYE (Auto-Win)
                 if (p1 === 'BYE' || p2 === 'BYE') {
                     m.winner = p1 === 'BYE' ? p2 : p1;
                     m.status = 'completed';
                     changed = true; 
                 } 
                 // 1b. Handle Initial Pending -> Ready
                 else if (m.status === 'pending') {
                     m.status = 'ready';
                     changed = true;
                 }
             }
         }

         // RULE 2: Propagate Completed Matches
         if (m.status === 'completed' && m.winner) {
             // Advance Winner
             if (m.nextMatchId) {
                if (advancePlayerToMatch(matches, m.nextMatchId, m.winner)) changed = true;
             }
             // Advance Loser (Double Elim)
             if (m.loserNextMatchId && m.player1 && m.player2) {
                const loser = m.winner === m.player1 ? m.player2 : m.player1;
                if (loser && advancePlayerToMatch(matches, m.loserNextMatchId, loser)) changed = true;
             }
         }
      });
    }
  };

  const handleMatchCompletion = (matchId: string, winner: string | null) => {
    if (!activeTournament || !winner) return;

    const newMatches = JSON.parse(JSON.stringify(activeTournament.matches)); 
    const match = newMatches.find((m: TournamentMatch) => m.id === matchId);

    // If match is already completed with same winner, ignore
    if (match && match.status === 'completed' && match.winner === winner) return;

    if (match) {
        match.winner = winner;
        match.status = 'completed';

        // 1. Settle the immediate match result
        settleBracket(newMatches);

        // 2. Prune any new Bye scenarios (e.g. if a Bye dropped to Loser Bracket)
        const pruned = pruneBracket(newMatches);

        // 3. Final settle to ensure everything propagated
        settleBracket(pruned);

        const updatedTourney = { ...activeTournament, matches: pruned };
        setActiveTournament(updatedTourney);
        localStorage.setItem('battleforge_active_tournament', JSON.stringify(updatedTourney));
    }
  };

  // --- Pruning Logic (Injection Method) ---
  const pruneBracket = (matches: TournamentMatch[]) => {
    let activeMatches = [...matches];
    let changed = true;
    let iterations = 0;

    while(changed && iterations < 20) {
        changed = false;
        iterations++;
        const toRemoveIds: string[] = [];

        // Sort by round to process upstream matches first
        activeMatches.sort((a,b) => a.roundIndex - b.roundIndex);

        for(const m of activeMatches) {
            const isWbR0 = m.bracketType === 'winner' && m.roundIndex === 0;

            let p1 = m.player1;
            let p2 = m.player2;

            const isByeBye = p1 === 'BYE' && p2 === 'BYE';
            const isPlayerBye = (p1 === 'BYE' || p2 === 'BYE') && !isByeBye; 

            let shouldPrune = false;
            let projectedWinner: string | null = null;
            let projectedLoser: string | null = null;

            // 1. BYE vs BYE -> Winner is BYE, Loser is BYE. Always Remove.
            if (isByeBye) {
                shouldPrune = true;
                projectedWinner = 'BYE';
                projectedLoser = 'BYE';
            } 
            // 2. Player vs BYE -> Winner is Player, Loser is BYE. Remove unless WB Round 0.
            else if (isPlayerBye && !isWbR0) {
                shouldPrune = true;
                projectedWinner = p1 === 'BYE' ? p2 : p1;
                projectedLoser = 'BYE';
            }

            if (shouldPrune && projectedWinner) {
                // INJECT RESULTS DOWNSTREAM
                // This simulates the match happening instantly and auto-forwarding the result
                if (m.nextMatchId) {
                    if (advancePlayerToMatch(activeMatches, m.nextMatchId, projectedWinner)) {
                        // If we successfully advanced, we might have created a new pruning opportunity downstream
                        // The loop will catch it in the next iteration
                    }
                }
                if (m.loserNextMatchId) {
                    if (advancePlayerToMatch(activeMatches, m.loserNextMatchId, projectedLoser!)) {
                        // same here
                    }
                }

                toRemoveIds.push(m.id);
                changed = true;
            }
        }

        if (toRemoveIds.length > 0) {
            activeMatches = activeMatches.filter(m => !toRemoveIds.includes(m.id));
        }
    }
    return activeMatches;
  };

  // --- Generators ---

  const generateFullSingleElim = (participants: string[], idOffset = 0): { matches: TournamentMatch[], rounds: number, nextId: number } => {
     const shuffled = [...participants].sort(() => 0.5 - Math.random());
     let size = 2;
     while(size < shuffled.length) size *= 2;

     // Fill with BYEs
     const seeded = [...shuffled];
     while(seeded.length < size) seeded.push("BYE");

     // Standard pairing (0v1, 2v3...)
     const r1Pairs: {p1: string, p2: string}[] = [];
     for(let i=0; i<size; i+=2) {
         r1Pairs.push({ p1: seeded[i], p2: seeded[i+1] });
     }

     const matches: TournamentMatch[] = [];
     let matchIdCounter = idOffset + 1;
     const getId = () => `m_${matchIdCounter++}`;

     // Round 1
     const round1Ids: string[] = [];
     r1Pairs.forEach(pair => {
        const id = getId();
        round1Ids.push(id);
        matches.push({
          id,
          roundIndex: 0,
          bracketType: 'winner',
          player1: pair.p1,
          player2: pair.p2,
          winner: null,
          status: 'pending' 
        });
     });

     // Subsequent Rounds
     let currentIds = round1Ids;
     let rIdx = 1;
     while(currentIds.length > 1) {
       const nextIds: string[] = [];
       for(let i=0; i<currentIds.length; i+=2) {
         const id = getId();
         nextIds.push(id);

         const m1 = matches.find(m => m.id === currentIds[i]);
         const m2 = matches.find(m => m.id === currentIds[i+1]);
         if(m1) m1.nextMatchId = id;
         if(m2) m2.nextMatchId = id;

         matches.push({
           id,
           roundIndex: rIdx,
           bracketType: 'winner',
           player1: null,
           player2: null,
           winner: null,
           status: 'pending'
         });
       }
       currentIds = nextIds;
       rIdx++;
     }

     return { matches, rounds: rIdx, nextId: matchIdCounter };
  };

  const generateDoubleElim = (participants: string[]): { matches: TournamentMatch[], rounds: number } => {
    // 1. Generate FULL Winner Bracket
    const { matches: wbMatches, rounds: wbRounds, nextId } = generateFullSingleElim(participants);
    const matches = [...wbMatches];

    const wbByRound: Record<number, TournamentMatch[]> = {};
    matches.forEach(m => {
      if(!wbByRound[m.roundIndex]) wbByRound[m.roundIndex] = [];
      wbByRound[m.roundIndex].push(m);
    });

    let matchIdCounter = nextId + 1000;
    const getId = () => `m_${matchIdCounter++}`;

    const lbMatches: TournamentMatch[] = [];
    let prevLBRoundMatches: TournamentMatch[] = [];

    // --- LB Round 0: Consumes WB Round 0 Losers ---
    const wbR0 = wbByRound[0];
    const lbR0Count = wbR0.length / 2;

    for (let i = 0; i < lbR0Count; i++) {
        const m: TournamentMatch = { 
            id: getId(), 
            roundIndex: 0, 
            bracketType: 'loser', 
            player1: null, 
            player2: null, 
            winner: null, 
            status: 'pending' 
        };
        lbMatches.push(m);
        prevLBRoundMatches.push(m);

        wbR0[i*2].loserNextMatchId = m.id;
        wbR0[i*2+1].loserNextMatchId = m.id;
    }

    let lbRoundIndex = 1;

    // --- Feed Remaining WB Rounds ---
    for (let i = 1; i < wbRounds; i++) {
        const wbRoundMatches = wbByRound[i]; 

        // Injection Round (Winner of previous LB vs Loser of current WB)
        const injectionMatches: TournamentMatch[] = [];
        for (let j = 0; j < wbRoundMatches.length; j++) {
            const m: TournamentMatch = {
                id: getId(),
                roundIndex: lbRoundIndex,
                bracketType: 'loser',
                player1: null,
                player2: null,
                winner: null,
                status: 'pending'
            };
            injectionMatches.push(m);
            lbMatches.push(m);

            if (prevLBRoundMatches[j]) prevLBRoundMatches[j].nextMatchId = m.id;
            wbRoundMatches[j].loserNextMatchId = m.id;
        }
        prevLBRoundMatches = injectionMatches;
        lbRoundIndex++;

        // Reduction Round (Winner of LB vs Winner of LB) - Only if not the last WB round
        if (prevLBRoundMatches.length > 1) {
            const reductionMatches: TournamentMatch[] = [];
            for (let j = 0; j < prevLBRoundMatches.length; j += 2) {
                const m: TournamentMatch = {
                    id: getId(),
                    roundIndex: lbRoundIndex,
                    bracketType: 'loser',
                    player1: null, 
                    player2: null,
                    winner: null, 
                    status: 'pending'
                };
                reductionMatches.push(m);
                lbMatches.push(m);

                prevLBRoundMatches[j].nextMatchId = m.id;
                prevLBRoundMatches[j+1].nextMatchId = m.id;
            }
            prevLBRoundMatches = reductionMatches;
            lbRoundIndex++;
        }
    }

    // --- Grand Final ---
    const grandFinal: TournamentMatch = {
        id: getId(),
        roundIndex: 0,
        bracketType: 'final',
        player1: null,
        player2: null,
        winner: null,
        status: 'pending'
    };
    matches.push(grandFinal);

    // Winner of WB Final -> Final
    const wbFinal = wbByRound[wbRounds-1][0];
    wbFinal.nextMatchId = grandFinal.id;

    // Winner of LB Final -> Final
    if (prevLBRoundMatches[0]) {
        prevLBRoundMatches[0].nextMatchId = grandFinal.id;
    }

    matches.push(...lbMatches);

    return { matches, rounds: lbRoundIndex };
  };

  const createTournament = () => {
    if (!newTourneyName || selectedPlayers.length < 2) {
      alert("Enter name and select at least 2 players.");
      return;
    }

    let result;
    if (tourneyType === 'double') {
      result = generateDoubleElim(selectedPlayers);
    } else {
      const full = generateFullSingleElim(selectedPlayers);
      result = { matches: full.matches, rounds: full.rounds };
    }

    let matches = result.matches;

    // 1. Initial Settle: Push Names to initial matches
    // This fills the "Player vs Bye" slots with actual names in WB R0
    settleBracket(matches);

    // 2. Structural Prune with Injection: 
    // This collapses the bracket by auto-resolving Bye matches and pushing results downstream
    matches = pruneBracket(matches);

    // 3. Final Settle: Propagate any remaining states
    settleBracket(matches);

    const newTourney: Tournament = {
      id: newTourneyName.replace(/\s+/g, '') + '_' + Date.now(),
      name: newTourneyName,
      type: tourneyType,
      participants: selectedPlayers,
      matches: matches,
      rounds: result.rounds,
      status: 'active',
      dateCreated: new Date().toISOString()
    };

    setActiveTournament(newTourney);
    localStorage.setItem('battleforge_active_tournament', JSON.stringify(newTourney));
  };

  const handlePlayerToggle = (p: string) => {
    if (selectedPlayers.includes(p)) setSelectedPlayers(selectedPlayers.filter(x => x !== p));
    else setSelectedPlayers([...selectedPlayers, p]);
  };

  const confirmDelete = () => {
     localStorage.removeItem('battleforge_active_tournament');
     setActiveTournament(null);
     setNewTourneyName('');
     setSelectedPlayers([]);
     setShowDeleteModal(false);
     navigate('/tournament', { replace: true, state: {} });
  };

  const startMatch = (m: TournamentMatch) => {
     if (!activeTournament) return;
     if (m.status !== 'ready') return;

     navigate('/', { 
       state: {
         player1: m.player1,
         player2: m.player2,
         tournamentId: activeTournament.id,
         bracketMatchId: m.id
       }
     });
  };

  const renderBracketSection = (title: string, matches: TournamentMatch[]) => {
      // Visual Filter: Even after pruning, hide any stubborn Bye matches
      const visibleMatches = matches.filter(m => {
          if (m.player1 === 'BYE' && m.player2 === 'BYE') return false;
          return true;
      });

      if (visibleMatches.length === 0) return null;

      // Dynamic Column Mapping:
      // Map the distinct 'roundIndex' values to 1, 2, 3...
      // This ensures if Round 2 is pruned entirely, Round 3 becomes the 2nd visual column.
      const activeRoundIndices = Array.from(new Set(visibleMatches.map(m => m.roundIndex))).sort((a,b) => a-b);

      return (
        <div className="mb-8">
           <h3 className="text-war-red font-orbitron font-bold uppercase mb-4 sticky left-0">{title}</h3>
           <div className="flex gap-8 min-w-max">
              {activeRoundIndices.map((roundIdx, displayIdx) => {
                 const roundMatches = visibleMatches.filter(m => m.roundIndex === roundIdx);

                 return (
                   <div key={roundIdx} className="flex flex-col justify-around gap-8 w-64">
                      <div className="text-center text-zinc-500 font-orbitron text-xs font-bold uppercase mb-4 bg-black/40 p-1 rounded">
                        Round {displayIdx + 1}
                      </div>
                      {roundMatches.map(m => {
                        const isReady = m.status === 'ready';
                        const isComplete = m.status === 'completed';
                        const p1Won = isComplete && m.winner === m.player1;
                        const p2Won = isComplete && m.winner === m.player2;

                        return (
                          <div 
                             key={m.id} 
                             onClick={() => isReady && startMatch(m)}
                             className={`
                               relative p-3 rounded border transition-all 
                               ${isComplete ? 'bg-green-900/10 border-green-900/30' : isReady ? 'bg-war-panel border-war-red cursor-pointer hover:bg-zinc-800 hover:scale-[1.02] shadow-[0_0_10px_rgba(255,45,45,0.2)]' : 'bg-zinc-900 border-zinc-800 opacity-60'}
                             `}
                          >
                             <div className={`text-sm font-bold flex justify-between ${p1Won ? 'text-green-400' : p2Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player1 || 'Waiting...'}</span>
                               {p1Won && <span>✓</span>}
                             </div>
                             <div className="h-px bg-zinc-700 my-2"></div>
                             <div className={`text-sm font-bold flex justify-between ${p2Won ? 'text-green-400' : p1Won ? 'text-red-900 line-through opacity-50' : 'text-zinc-300'}`}>
                               <span>{m.player2 || 'Waiting...'}</span>
                               {p2Won && <span>✓</span>}
                             </div>
                          </div>
                        );
                      })}
                   </div>
                 );
              })}
           </div>
        </div>
      );
  };

  return (
    <div className="min-h-screen bg-war-dark pb-20 p-4">
      {/* Delete Confirmation Modal */}
      {showDeleteModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
            <div className="bg-war-panel border border-red-900/50 rounded-lg p-6 max-w-md w-full shadow-[0_0_20px_rgba(255,45,45,0.1)]">
                <h3 className="text-xl font-orbitron font-bold text-white mb-2">Delete Tournament?</h3>
                <p className="text-zinc-400 mb-6 text-sm">
                    Are you sure you want to delete <span className="text-white font-bold">{activeTournament?.name}</span>? 
                    This action cannot be undone and all bracket progress will be lost.
                </p>
                <div className="flex gap-3 justify-end">
                    <Button variant="secondary" onClick={() => setShowDeleteModal(false)} className="text-xs">Cancel</Button>
                    <Button variant="danger" onClick={confirmDelete} className="text-xs bg-red-600 hover:bg-red-700">Yes, Delete It</Button>
                </div>
            </div>
        </div>
      )}

      <header className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-orbitron font-bold text-war-red">
          TOURNAMENT<span className="text-white">HUB</span>
        </h1>
        <Button variant="secondary" onClick={() => navigate('/')} className="text-xs py-2 px-3">&larr; App</Button>
      </header>

      {!activeTournament ? (
        <div className="bg-war-panel border border-zinc-700 rounded-lg p-6 max-w-2xl mx-auto shadow-xl animate-fade-in">
           <h2 className="text-xl font-orbitron text-white mb-4">Create New Tournament</h2>

           <div className="space-y-4">
             <Input label="Tournament Name" value={newTourneyName} onChange={e => setNewTourneyName(e.target.value)} placeholder="e.g. Summer Slam 2024" />

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Format</label>
               <div className="flex gap-2">
                 <button onClick={() => setTourneyType('single')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'single' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Single Elimination</button>
                 <button onClick={() => setTourneyType('double')} className={`flex-1 py-2 rounded border transition-all ${tourneyType === 'double' ? 'bg-war-red border-war-red text-white' : 'bg-zinc-800 border-zinc-700 text-gray-400'}`}>Double Elimination</button>
               </div>
             </div>

             <div className="flex flex-col gap-1">
               <label className="text-war-gray text-xs font-orbitron uppercase">Participants ({selectedPlayers.length})</label>
               <div className="grid grid-cols-2 md:grid-cols-4 gap-2 bg-zinc-900 p-3 rounded border border-zinc-800 max-h-40 overflow-y-auto">
                 {PLAYERS.map(p => (
                   <button 
                     key={p} 
                     onClick={() => handlePlayerToggle(p)}
                     className={`text-xs p-2 rounded text-left transition-colors ${selectedPlayers.includes(p) ? 'bg-green-900/50 text-green-200 border border-green-700' : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'}`}
                   >
                     {p}
                   </button>
                 ))}
               </div>
             </div>

             <Button onClick={createTournament} className="w-full mt-4">Generate Bracket</Button>
           </div>
        </div>
      ) : (
        <div className="animate-fade-in overflow-x-auto">
           {/* Sticky header updated with z-index and background to ensure clickable buttons */}
           <div className="flex justify-between items-center mb-4 min-w-[600px] sticky left-0 z-10 bg-war-dark p-2 border-b border-zinc-800">
             <div>
               <h2 className="text-2xl font-bold font-orbitron text-white">{activeTournament.name}</h2>
               <div className="text-xs text-zinc-500">Status: {activeTournament.status} | Type: {activeTournament.type}</div>
             </div>
             <Button variant="danger" onClick={() => setShowDeleteModal(true)} className="text-xs py-1 px-3 bg-red-800 hover:bg-red-700 text-white border-red-900 shadow-lg">Delete Tournament</Button>
           </div>

           {/* Render Brackets Split by Type */}
           {activeTournament.type === 'single' ? (
              renderBracketSection("Bracket", activeTournament.matches)
           ) : (
              <div>
                {renderBracketSection("Winners Bracket", activeTournament.matches.filter(m => m.bracketType === 'winner'))}
                {renderBracketSection("Losers Bracket", activeTournament.matches.filter(m => m.bracketType === 'loser'))}
                {renderBracketSection("Finals", activeTournament.matches.filter(m => m.bracketType === 'final'))}
              </div>
           )}
        </div>
      )}
    </div>
  );
};
